window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q05"]=window.__LIBQ["pham-nhan-tu-tien"]["q05"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q05"]["cotTruyen"]=[{"chuong":593,"tieuDe":"Ủy Thân Chi Cử","tomTat":"Hàn Lập chém chết Hinh Nha Thú, xác nhận ba người đang ở Vô Biên Hải — vùng biển phía bắc Thiên Nam, không còn ở Loạn Tinh Hải. Ba người quyết định bay về hướng nam tìm lục địa, dọc đường Hàn Lập hồi tưởng về Nam Cung Uyển với tình cảm phức tạp. Sau ba bốn tháng phi hành, họ đáp xuống Mẫn Châu thuộc Khê Quốc ở đông bắc Thiên Nam. Hàn Lập tiết lộ mình xuất thân Thiên Nam, trước đây bị đuổi giết mới đến Loạn Tinh Hải, đã mất liên lạc sư môn hơn trăm năm, đồng thời chế tạo hai khối ngọc giản phiên dịch ngôn ngữ trao cho hai nàng. Hàn Lập cho biết tu vi đã đến Kết Đan Hậu Kỳ đỉnh, tựa hồ chuẩn bị ngưng kết Nguyên Anh, định tìm động phủ bế quan. Mai Ngưng bộc bạch mình chỉ ở Trúc Cơ Trung Kỳ, tư chất kém, tính tìm cao giai tu sĩ làm thiếp thân để song tu có hy vọng kết đan, vì huynh trưởng đã gặp nạn và nàng cô độc. Tử Linh chủ động gợi ý Mai Ngưng nên chọn Hàn Lập, Mai Ngưng đỏ mặt không phản đối, không khí trở nên ám muội."},{"chuong":594,"tieuDe":"Lạc Vân Tông","tomTat":"Tử Linh tiếp tục đề nghị Hàn Lập thu nhận Mai Ngưng làm thiếp, nhưng Hàn Lập bình tĩnh cự tuyệt, tuyên bố lập chí theo đuổi thành tiên chi đạo, chưa vào Nguyên Anh kỳ sẽ không tính chuyện nam nữ. Mai Ngưng hỏi liệu sau khi vào Nguyên Anh kỳ có nguyện thu nhận không, nhưng tự nhận ra bản thân tuy có hảo cảm mà chưa đến mức ái mộ thật lòng, không thể chờ đợi kết quả không xác định. Hàn Lập tặng Mai Ngưng hai bình đan dược đỉnh cấp Trúc Cơ kỳ luyện từ yêu đan để trả ân tình Thông Linh Khí. Sau khi chia tay nhị nữ, Hàn Lập tới Khê Quốc — quốc gia vùng tây bộ xa xôi, nơi có Vân Mộng Sơn là linh khí thánh mạch nổi danh. Sâu trong Vân Mộng Sơn có Linh Nhãn Chi Thụ, một trong ba đại thần mộc cuối cùng, mỗi hai trăm năm chảy ra Thuần dịch — thuốc dẫn cho Định Linh Đan giúp ngưng kết Nguyên Anh. Hàn Lập quyết định giả thân phận Luyện Khí kỳ dùng liễm tức thuật trà trộn vào Lạc Vân Tông — đại phái nổi tiếng luyện đan thuật đang thu nhận đệ tử. Tuy nhiên, hắn phát hiện mọi đan dược tịnh tiến tu vi hoàn toàn mất hiệu lực dù luyện từ yêu đan cấp sáu hay cấp bảy, kế hoạch đưa tu vi lên Kết Đan hậu kỳ đại viên mãn phá sản hoàn toàn."},{"chuong":595,"tieuDe":"Bốn Thế Lực Lớn","tomTat":"Hàn Lập phát hiện đan dược hoàn toàn mất tác dụng ở Kết Đan Kỳ hậu kỳ, sớm hơn bình thường, nghi do di chứng Bích Diễm Tửu và Thông Linh khí. Có yêu đan cấp tám Độc Giao nhưng không nỡ luyện chế vì tỷ lệ thất bại lớn, đành chấp nhận khổ tu ước tính khoảng mười năm. Sau khi cân nhắc, hắn loại bỏ phương án đánh chiếm linh mạch và gia nhập gia tộc tu sĩ, quyết định trà trộn vào môn phái lớn ở thánh mạch Vân Mộng Sơn — nơi linh khí nổi tiếng nhất Thiên Nam. Cùng hai chị em Tử Linh thu thập tình báo, hắn nắm được cục diện Thiên Nam đã biến đổi lớn: bốn thế lực chính đạo, ma đạo, Thiên Đạo Minh và Cửu Quốc Minh cùng thống trị. Cửu Quốc Minh bị Mạc Lan bộ lạc (có tiếp viện từ đệ nhị, đệ tứ) áp đảo, phải uy hiếp ba thế lực kia tăng viện, sau đại chiến hơn ngàn tu sĩ tử trận mới chặn được. Bốn thế lực đạt hiệp nghị: Cửu Quốc Minh làm chủ chống Mạc Lan, ba nhà thay phiên trợ giúp, duy trì hòa bình hơn trăm năm. Cổ Kiếm Môn, Lạc Vân Tông, Bách Xảo là trung tâm Thiên Đạo Minh, Khê quốc thuộc phạm vi liên minh này."},{"chuong":596,"tieuDe":"Nhập Môn (Thượng)","tomTat":"Hàn Lập phân tích ba môn phái lớn chiếm cứ Vân Mộng Sơn tại Khê Quốc: Bách Xảo Viện chuyên luyện pháp khí nhưng chỉ thu đệ tử gia tộc, Cổ Kiếm Môn mạnh nhất nhưng yêu cầu linh căn cực cao, Lạc Vân Tông công pháp hỗn tạp nhưng dễ nhập môn và có Định Linh Đan. Hắn chọn Lạc Vân Tông vì dễ gia nhập nhất, chia tay Tử Linh nhị nữ rồi phi độn tới chân núi chờ ngày thu đệ tử. Leo núi theo sơn đạo lát đá xanh, trên đường bị thi triển huyễn thuật thô sơ thử luyện tâm cảnh. Lên tới sân rộng, đám tán tu chỉ thấy tiểu đình nhưng thần thức Hàn Lập nhìn thấu ảo trận, thấy rõ tòa bạch ngọc lâu Huyễn Vân Đường và ba tu sĩ Lạc Vân Tông đang bình phẩm tán tu. Hàn Lập thu liễm khí tức giả tu vi Luyện Khí Kỳ mười tầng. Ba tu sĩ Thu sư huynh, Lưu sư huynh và một thanh niên thảo luận tiêu chuẩn thu đệ tử, nhắc tấm gương Tôn Hỏa — tán tu chỉ năm sáu năm Trúc Cơ thành công. Hoàng hôn gần trăm tán tu tập trung, ảo trận giải trừ lộ ra Huyễn Vân Đường, Thu sư huynh tuyên bố bắt đầu thủ tục tuyển chọn."},{"chuong":597,"tieuDe":"Nhập Môn (Trung)","tomTat":"Thu sư huynh công bố quy định tuyển chọn đệ tử Lạc Vân Tông: mỗi lần chỉ thu sáu người, phân nhóm theo linh căn đặc thù và tu vi công pháp. Nhóm có hai ba linh căn hoặc linh thể đặc thù (bốn người) được Lưu sư đệ mang đi kiểm tra tư chất. Hàn Lập cùng sáu tu sĩ có công pháp trên mười tầng lên pháp khí đồng bát do Du sư đệ điều khiển bay tới Vân Mộng Sơn. Trên đường, Hàn Lập phát hiện đại hán râu quai nón trên người ẩn dật hàn khí âm trầm dị thường, dùng thần thức dò xét nhưng suýt bị lộ. Hàn Lập cảm thán rằng nếu không có bình nhỏ thần bí thì với ngụy linh căn không thể đột phá quá tầng năm sáu. Đoàn người gặp đại trận hộ phái Lạc Vân Tông — sương mù mịt mờ ẩn chứa âm phong sấm sét, thần thức chỉ xuyên được mười trượng. Du sư đệ dùng trận kỳ màu xanh mở thông đạo hai ba trượng đưa mọi người xuyên qua. Tới sơn môn Lục Kỳ Phong linh khí nồng đậm, điện phủ lầu các san sát, Du sư đệ dẫn nhóm tới Thiên Tuyền Phong để khai báo lai lịch và kiểm tra công pháp."},{"chuong":598,"tieuDe":"Nhập Môn (Hạ)","tomTat":"Du sư đệ khu cự bát đưa bảy tán tu gồm Hàn Lập bay tới Thiên Tuyền Phong. Trên đường gặp Ngôn sư huynh — tu sĩ Trúc Cơ Kỳ mặc hoàng bào tai khỉ — đòi xin hai đệ tử mới phục vụ luyện phù, bị Du sư đệ khéo léo từ chối bằng cách viện cớ Chưởng môn quyết định và Miêu sư huynh đang chờ. Tại Nghênh Tùng Cư dưới chân núi, Miêu sư huynh — kỳ tài Trúc Cơ Hậu Kỳ mới 34-35 tuổi nhưng sắc mặt bệnh hoạn — đánh giá bảy tán tu, ánh mắt dừng lại theo bản năng ở đại hán râu quai nón khiến Hàn Lập lặng lẽ ghi nhận. Miêu sư huynh giao bảy Vấn Tâm Phù cho Du sư đệ phát, rồi lên lầu hai thi triển Vấn Tâm Thuật hỏi mười câu mỗi người. Hàn Lập là người đầu tiên bị gọi, bề ngoài thành thật nhưng trong lòng cười lạnh, tự tin thuật phán đoán không thể hỏi ra thật lòng hắn. Cả bảy người đều qua kiểm tra, sau đó bay tới gặp Chưởng môn Lạc Vân Tông đăng ký tên, chính thức trở thành đệ tử."},{"chuong":599,"tieuDe":"Đoán Kim Chi Thể","tomTat":"Bảy ngoại sự đệ tử gồm Hàn Lập đến Lục Kỳ Phong — ngọn núi chính của Lạc Vân Tông, chân núi náo nhiệt với cửa hàng và đền đài. Thanh niên họ Du dẫn đoàn vào thạch điện bằng đá xanh gặp Chưởng môn Ngụy Nhất Minh cùng bảy tám tu sĩ trưởng bối để phân phối đệ tử mới. Hàn Lập lén thả thần thức dò xét, xác nhận chưởng môn ở Trúc Cơ hậu kỳ, hai tu sĩ trung kỳ, còn lại sơ kỳ. Tranh chấp nổ ra khi Ẩn Kiếm Phong và Hỏa Vân Phong cùng muốn nhận thanh niên khôi ngô có linh thể đặc thù Đoán kim chi thể — trời sinh hợp công pháp kim thuộc tính. Thu sư huynh đề nghị để chưởng môn quyết định, Ngụy Nhất Minh phân thanh niên đó về Huyễn Thạch Phong. Hàn Lập cùng gã râu quai nón được phân về Thiên Tuyền Phong làm ngoại sự đệ tử, đổi phục sức màu lam cấp thấp. Trên đường về, thanh niên họ Du giảng giải quy chế: ngoại sự đệ tử chủ yếu học chế phù và luyện đan, sư tổ đối đãi nhân hậu, nếu lập công lớn có thể được ban thưởng Trúc Cơ Đan."},{"chuong":600,"tieuDe":"Quy Chúc","tomTat":"Hàn Lập cùng đại hán Đỗ Đông được Du Quân dẫn đến Tuyền Phong Sơn bái kiến sư tổ Thiên Tuyền Phong, một tu sĩ Kết Đan trung kỳ tướng mạo nho sinh. Dọc đường Hàn Lập vẫn canh cánh chuyện dị trạng trên người Đỗ Đông mà ngay cả Miêu sư huynh Trúc Cơ hậu kỳ cũng nhìn ra, khẳng định bên trong có gian trá. Tại nơi hạ cánh, hai người gặp Mã sư muội và Tân sư đệ là hậu bối tục giới của sư tổ, được Du Quân cảnh báo tuyệt đối không được đắc tội. Sư tổ không phát hiện tu vi thật của Hàn Lập lẫn dị trạng trên người Đỗ Đông, phân phó tam sư huynh chuyên chế phù nhận Đỗ Đông, còn Mộ Phái Linh chuyên luyện đan nhận Hàn Lập. Khi bị đuổi ra ngoài chờ, Hàn Lập lặng lẽ dùng thần thức cường đại nghe lén toàn bộ cuộc thương lượng bí mật bên trong. Sau đó Mộ Phái Linh dùng vải lụa hồng đưa Hàn Lập đến động phủ, cho chọn giữa trông coi dược viên hoặc học luyện đan thuật. Hàn Lập không chút do dự chọn trông coi dược viên vì công việc này cho phép hắn có nhiều thời gian tự do tu luyện, nhận ngọc giản công pháp thủy thuộc tính Huyền Băng Quyết rồi chính thức tiếp quản khu dược viên rộng hơn trăm trượng làm địa bàn riêng."},{"chuong":601,"tieuDe":"Giải Trừ Hậu Hoạn","tomTat":"Sau khi Mộ Phái Linh rời đi, Hàn Lập xem xét ba vật nhận được gồm ngọc giản bồi dưỡng dược viên, công pháp Huyền Băng Quyết và lệnh bài khống chế trận pháp, đều đánh giá thấp. Hắn bí mật dùng phi kiếm khai phá động phủ trong tiểu thạch sơn phía sau dược viên, tạo nhiều thạch thất và bố trí trận pháp ẩn nặc cao cấp che được tu sĩ Kết Đan Kỳ. Hắn sắp xếp Cửu Khúc Linh Sâm vào dược viên nội bộ có cấm chế, Phệ Kim Trùng vào trùng thất, Đề Hồn Thú đang hôn mê tiến cấp vào linh thú thất. Quyết định nhân lúc Đề Hồn Thú hôn mê để luyện hóa hoàn toàn Minh Hồn Châu trong bụng nó vì lo sợ mất kiểm soát khi thú tỉnh. Hắn ưu tiên khu trừ tà khí Phong Linh Kính bằng Ích Tà Thần Lôi, quá trình vô cùng đau đớn nhưng có hiệu quả, ước tính nửa năm sạch hoàn toàn. Bắt đầu nghiên cứu Câu Linh Trận từ ngọc giản đen, dự định bố trí tầng phòng hộ thứ hai che được cả Nguyên Anh Kỳ. Thiết lập lịch trình tu luyện ổn định, mấy tháng trôi qua bình yên, Mộ Phái Linh đến kiểm tra hai lần thấy ổn nên không hỏi nhiều."},{"chuong":602,"tieuDe":"Huyết Ảnh Độn","tomTat":"Hàn Lập hoàn tất Câu Linh Trận sau một tháng, bày trận che giấu hoàn toàn động phủ tiểu thạch sơn. Hai ba tháng sau, hắn luyện hóa Minh Hồn Châu thành công không phản ứng phụ, đồng thời trục xuất hoàn toàn tà khí Phong Linh Kính khỏi cơ thể. Hắn lên kế hoạch đồng thời tu luyện Đại Diễn Quyết tầng thứ tư và Thanh Nguyên Kiếm Quyết, nhưng chưa vội luyện đan Cửu Khúc Linh Sâm vì ba nguyên liệu then chốt tại Thiên Nam không thể tìm được. Học cổ văn yêu tộc, hắn giải mã sách da thú phát hiện công pháp Tật Phong Cửu Biến gồm pháp quyết, thân pháp dành riêng yêu cầm và hai mật thuật. Mật thuật Huyết Ảnh Độn khiến hắn hứng thú — độn thuật mượn máu huyết bắn xa trăm dặm, và Phong Lôi Sí đáp ứng điều kiện cánh. Đồng phiến Phạm Thánh Chân Phiến thì nội dung không đầy đủ, không thể giải mã. Sau nửa năm kiêm tu, Hàn Lập tự cảm nắm được Huyết Ảnh Độn nhưng chưa dám thực hành. Khuê Hoán — nam tử trẻ ngoại hình kỳ quặc, tu vi chỉ Luyện Khí kỳ tám chín tầng — từ Ẩn Kiếm Phong đến dược viên tìm Viên sư tỷ, khiến Hàn Lập ngạc nhiên không hiểu hắn hỗn nhập Lạc Vân Tông bằng cách nào."},{"chuong":603,"tieuDe":"Tuyết Vân Hồ","tomTat":"Khuê Hoán, đệ tử ngoại môn Ẩn Kiếm Phong tu vi Luyện Khí tầng mười hai, đến dược viên tìm Hàn Lập. Hắn kể nhóm mình phát hiện dị chủng Tuyết Vân Hồ có linh khí tại đầm lầy Lục Tung chiểu trạch, bắt được có thể bán trên một trăm linh thạch, nhưng cần Địa Hoàng Tinh trên năm mươi năm làm mồi nhử. Hàn Lập kiên quyết từ chối cho mượn linh dược trong vườn vì không có tư cách tự ý dùng, nhưng chủ động cho Khuê Hoán mượn hơn hai mươi khối linh thạch để tự mua, tính toán giữ quan hệ vì Khuê Hoán linh thông tin tức. Khuê Hoán quay lại mời Hàn Lập tham gia bắt thú vì thiếu người vận hành Mê Tung trận. Hàn Lập vốn không muốn đi nhưng mấy ngày trước khi bế quan tu luyện tầng thứ tư Đại Diễn Quyết đã gặp bình cảnh, tâm tư phiền não không thể bình tâm tĩnh khí, nhận ra đột phá cần cơ duyên nên đồng ý ra ngoài thay đổi tâm trạng."},{"chuong":604,"tieuDe":"Lục Tung Chiểu Trạch","tomTat":"Hàn Lập đáp ứng yêu cầu của Khuê Hoán, sáng sớm rời dược viên, chân đạp phi kiếm thượng giai pháp khí lâu không dùng từ khi Kết Đan, đến điểm hẹn trên tiểu sơn chờ đợi. Khuê Hoán cùng ba sư huynh — Vương sư huynh (Luyện Khí tầng 11, thủ lĩnh nhóm), Mã sư huynh và Tập sư huynh (đều Luyện Khí tầng 10) — bay đến bằng pháp khí cấp thấp thống nhất của nội môn. Vương sư huynh chân thành cảm ơn Hàn Lập cho mượn linh thạch, coi hắn là bằng hữu đáng kết giao. Hàn Lập tiết lộ biết luyện chế phù bảo sơ cấp hạ bậc cùng hai loại trung giai Lôi Hỏa phù và Kim Cương phù nhưng cố tình nói tỷ lệ thành công thấp. Vương sư huynh cho biết Tuyết Vân Hồ ở Lục Tung chiểu trạch đã bị bắt gần hết, sau chuyến này không thể đi nữa, lại không phải yêu thú chính thức nên khó bán. Năm người bay ra khỏi phạm vi cấm chế Lạc Vân Tông, vào giữa Vân Mộng Sơn, Vương sư huynh ném cho Hàn Lập bình đan dược khu chướng khí. Cuối cùng nhóm vượt qua ngọn núi lớn, thung lũng xanh tươi với vụ khí phấn đỏ nhạt hiện ra — Lục Tung chiểu trạch nằm nơi giao nhau thế lực Lạc Vân Tông và Cổ Kiếm Môn, Vương sư huynh dẫn đầu lao xuống."},{"chuong":605,"tieuDe":"Hồ Hiện","tomTat":"Nhóm năm người gồm Hàn Lập, Vương sư huynh, Khuê Hoán, thanh niên họ Mã và tu sĩ họ Tập hạ xuống vùng đầm lầy để bắt Tuyết Vân Hồ. Khuê Hoán chôn cây Hoàng Tinh hơn năm mươi năm tuổi làm mồi nhử, phân phối trận kỳ cho mọi người. Năm người ẩn hình trên không phục kích, Hàn Lập nhờ thần thức bao trùm vài trăm trượng phát hiện bạch hồ trốn ở bụi cây hướng tây trước tất cả, truyền âm cảnh báo. Khi bạch hồ trắng như tuyết tiến gần Hoàng Tinh, Vương sư huynh ra lệnh kích hoạt Ngũ Hành Mê Tung trận. Tuyết Vân Hồ bị huyễn cảnh khốn trụ, hóa bạch quang cố thoát thất bại, cuối cùng run rẩy ngã vật xuống đất. Thanh niên họ Mã kiểm tra báo thân lạnh tim không đập, Vương sư huynh nghi giả chết nhưng cuối cùng đồng ý thu trận. Hàn Lập im lặng suốt quá trình, nhìn bạch hồ lộ vẻ cổ quái — dường như nhận ra điều bất thường mà người khác không thấy."},{"chuong":606,"tieuDe":"Truy Nặc","tomTat":"Tuyết Vân Hồ giả chết lừa Mã sư đệ, dùng lông đuôi cứng nhọn đâm thủng bàn tay hắn rồi thoát ra, sử dụng Chướng Nhãn pháp độn thổ trốn đi. Bốn đệ tử Ẩn Kiếm Phong bao vây bụi cây nhưng không phát hiện. Hàn Lập dùng thần thức nhận ra thủ đoạn của yêu hồ, cố ý để nó thoát khỏi nhóm Khuê Hoán để tự mình truy đuổi. Hắn phát hiện trên thân Tuyết Vân Hồ có thanh linh chi khí tương tự hóa thân bạch thỏ của Cửu Khúc Linh Sâm nhưng lượng rất ít, suy đoán việc tiến hóa thành yêu thú liên quan loại linh khí này. Hàn Lập dùng Ngọc Như Ý thi triển Thổ Độn Thuật xuyên núi đá bám theo bạch hồ. Khi yêu hồ chui vào thạch thất phong bế trong núi, thần thức Hàn Lập bị lực lượng cổ quái bắn ngược. Một nhân vật bí ẩn xưng lão thân phát thanh âm mời hắn vào, dùng vô số đạo ánh sáng vàng và cự lực kéo hắn vào thạch thất. Hàn Lập lập tức kích hoạt Ngọc Như Ý tạo vòng bảo hộ phòng thủ."},{"chuong":607,"tieuDe":"Hắc Y Thiếu Phụ","tomTat":"Hàn Lập bước vào thạch thất và phát hiện người nói chuyện là một thiếu phụ áo đen bí ẩn, khuôn mặt xinh đẹp nhưng sắc mặt trắng nhợt, cụt một cánh tay, trên đùi nuôi một con Tuyết Vân Hồ. Khi Hàn Lập thả pháp bảo lộ tu vi Kết Đan hậu kỳ, thiếu phụ khen ẩn nặc thuật của hắn cao minh. Hàn Lập dùng thần thức dò xét nhưng thần thức xuyên thẳng qua thân thể đối phương như không tồn tại, nhận ra bà là tu sĩ Nguyên Anh kỳ, tuy nhiên hắn không quá sợ hãi nhờ vừa học được Huyết Ảnh Độn có thể dùng để đào thoát. Thiếu phụ gợi ý Hàn Lập thử công kích vách đá, kiếm mang và phi kiếm đều không để lại vết, lỗ nhỏ tự liền lại, bà giải thích đây là Hấp Linh thạch hay còn gọi Thanh Kim thạch, tài liệu luyện khí cực hiếm gần như thất truyền. Thiếu phụ thẳng thắn nhận xét tư chất Hàn Lập kém, đạt Kết Đan hậu kỳ hoàn toàn nhờ cơ duyên, rồi đề nghị cho mượn Linh Nhãn Chi Ngọc, loại linh nhãn chi thạch cao cấp nhất, có thể giúp giai đoạn giả anh ổn định thêm ba phần và ngưng kết Nguyên Anh dễ dàng hơn. Điều kiện đổi lại là dùng xong trả nguyên vẹn và giúp bà chuyển một tín hàm cho một người nào đó, bởi vì nguyên nhân bí ẩn khiến bà không thể rời khỏi nơi này dù chỉ một bước."},{"chuong":608,"tieuDe":"Biến Hóa","tomTat":"Thiếu phụ áo đen trao Linh nhãn chi ngọc sắp hóa hình cho Hàn Lập — viên ngọc phẩm chất cực cao, bên trong có hình con trâu xanh sống động, giúp hắn chỉ cần vài năm tiến vào cảnh giới Giả Anh thay vì mười năm. Hàn Lập cũng tỉnh ngộ rằng Tuyết Vân Hồ tiến hóa thành yêu hồ nhờ nhiễm linh khí viên ngọc này. Thiếu phụ tự bạch lai lịch: tu luyện U Sát quyết đạt Nguyên Anh trung kỳ nhưng sát tính bùng phát không kiểm soát, bị nhiều tu sĩ Nguyên Anh kỳ vây đánh trọng thương phế một cánh tay, tự chế Thiên Hỏa Thần Liên và thạch thất Thanh kim thạch giam mình, giao chìa khóa cho bạn thân nhưng bạn biến mất. Bà nhờ Hàn Lập lấy hộp ngọc thứ hai từ sau đài đá và gỡ phù ấn. Khi Hàn Lập chuẩn bị xé phù, hắn phát hiện mắt thiếu phụ biến thành màu bích lục dị thường, khuôn mặt vặn vẹo hung ác, nhận ra có vấn đề và rụt tay. Hắn cầm hộp có phù ấn tiến lại gần thiếu phụ, bà hoảng sợ thực sự quát bảo dừng lại — chứng tỏ đạo phù trên hộp chính là vật trấn áp bà, câu chuyện nhờ chuyển tín vật thực chất là mưu kế để được giải phóng."},{"chuong":609,"tieuDe":"Thi Tiêu","tomTat":"Hàn Lập dùng lá phù trong hộp ngọc ố vàng tấn công thiếu phụ áo đen, phù văn vàng khiến đối phương kêu thảm thiết với thanh âm lúc nam lúc nữ phi nhân và bốc khói xanh độc. Thiếu phụ cố bay lên tránh nhưng bị cấm chế trên đài đá kéo lại, duỗi quỷ trảo bạc từ trong khói chụp Hàn Lập nhưng ngân liên tự co lại thiêu đốt khiến quỷ trảo phải rút về. Hàn Lập phòng thủ bằng Ngọc Như Ý và túi linh thú Phệ Kim Trùng, rồi dùng hỏa thuật tạo quang đoàn đỏ phá tan khói xanh độc. Trên đài đá lộ ra quái vật phủ đầy lông xanh, da bọc xương mặt xám, răng nanh dài hơn một tấc, mất một cánh tay, bị ngân liên buộc chân và xuyên ngực. Hàn Lập thử phi kiếm chém liên tục nhưng quái vật bình yên vô sự, thể xác cực kỳ cứng rắn. Nhớ lại kiến thức từ sách, Hàn Lập nhận ra đây là Thi Tiêu — loại cương thi đặc biệt hình thành từ thi thể tu sĩ tối thiểu Nguyên Anh kỳ có thiên linh căn mộc hoặc thổ thuộc tính, chết mang oán khí lớn khiến hồn phách 981 ngày dung hợp trở lại, bán nhân bán quỷ không sợ mặt trời, giữ trí nhớ và công pháp khi sống, hung ác thành tính thích hút hồn phách tra tấn."},{"chuong":610,"tieuDe":"Hồ Biến","tomTat":"Sau khi chế trụ thi tiêu, Hàn Lập phân tích hộp ngọc dán linh phù bên cạnh là vật chứa tinh hồn thi tiêu bị Trừu Hồn thuật phong ấn, thu vào túi trữ vật và hẹn đại thành Nguyên Anh mới mở. Chuẩn bị rời đi bằng Thổ độn thuật thì phát hiện Tuyết Vân Hồ ẩn nấp trong hố nhỏ dưới thân thi tiêu. Bắt được bạch hồ nhưng nhận ra điều bất thường — con thú sống cùng thi tiêu mà không hề tổn hao — liền ném nó đi. Bạch hồ lộ bản chất, chân trước hóa lợi trảo khổng lồ trắng như tuyết chộp vào ngực Hàn Lập, nhờ nội giáp xanh di vật Ôn Thiên Nhân mà không bị thương. Hàn Lập triệu Ngọc Như Ý hộ thân nhưng nó hoàn toàn không phản ứng lần đầu tiên, phải chuyển dùng phi kiếm phòng ngự. Bạch hồ biến hình thành thiếu phụ xích lõa có đuôi dài kiều mị, dung mạo giống hệt thiếu phụ áo đen từng giao chiến, cất giọng giễu cợt. Hàn Lập nhận định đây là yêu hồ — linh hồ cấp cao có thiên phú ảo thuật và ẩn nặc đứng hàng đầu trong yêu thú, mơ hồ cảm thấy nó không phải hóa thân đơn giản của thi tiêu, trong mắt lộ sát khí."},{"chuong":611,"tieuDe":"Lang Hiện","tomTat":"Hàn Lập tuyên bố chỉ một trong hai được sống rồi dùng phi kiếm tấn công yêu hồ, nhưng đánh trượt do ẩn hình thuật vượt ngoài dự liệu. Hắn lấy Kinh Long chung phát âm ba trong thạch thất phong bế, uy lực tăng nửa phần, phá ẩn hình thành công — thiếu phụ trần trụi hiện hình. Hàn Lập búng năm đạo kiếm khí xuyên thủng phân thân giả do huyễn thuật, suýt trúng ngân ti ám kích từ chỗ trống nhưng Ngọc Như Ý tự phát hào quang hỏa hộ thể chặn đòn mà không cần Hàn Lập thúc dục. Hồng quang từ Ngọc Như Ý bay ra hội tụ với tiểu lang hoàng sắc, hiện hình Ngân sắc cự lang cao hơn trượng. Ngân lang chủ động phun ngân đoàn lao vào phấn vụ, đoạt xá bạch hồ thành công — ngân quang nuốt hết phấn quang, tu vi kinh người biến mất, yêu hồ trở về yêu thú cấp thấp. Hàn Lập cân nhắc rồi quyết không xuống tay vì Ngân lang từng cứu hắn. Bạch hồ đứng dậy nhưng quỵ ngã, rồi truyền âm bằng giọng nữ tử — Hàn Lập sửng sốt phát hiện Ngân lang là nữ giới có ý thức độc lập."},{"chuong":612,"tieuDe":"Ngân Nguyệt Lang Tộc","tomTat":"Hàn Lập thu phi kiếm và yêu cầu Bạch hồ (khí linh Ngọc Như Ý đã đoạt xá thân yêu hồ) khai rõ lai lịch, dùng Ngọc Như Ý đe doạ đập nát để thăm dò — xác nhận nếu phá huỷ pháp bảo thì khí linh cũng tan biến vì đã hợp nhất. Bạch hồ phóng ngân quang hoá hình thành thiếu phụ có dung nhan giống hệt yêu hồ nhưng đôi mắt đổi thành con ngươi trong suốt, tự xưng tên Ngân Nguyệt, nhận mình là thành viên Ngân Nguyệt lang tộc với ký ức kiếp trước tàn khuyết. Ngân Nguyệt giải thích thiên phú thôn phệ linh hồn của tộc mình — dùng nguyên thần xuất khiếu công kích nguyên thần đối phương để đoạt xá, nhưng có nhiều hạn chế. Cô cho biết đoạt xá thành công vì Tứ đồng linh hồ bị Ngân Nguyệt lang tộc thiên sinh khắc chế và thân xác đã bị Thi Tiêu đoạt xá trước. Tu vi chân chính của yêu hồ chỉ là cấp thấp, Thi Tiêu đã tiếp thêm tu vi tạm thời. Ngân Nguyệt tiết lộ có mật thuật tạm đề thăng tu vi lên thất-bát cấp nhưng sau đó hạ xuống, cần ít nhất một tháng hồi phục. Chương kết thúc khi Ngân Nguyệt hỏi ngược Hàn Lập liệu có cho cô rời đi tự tu luyện không."},{"chuong":613,"tieuDe":"Chủ Phó Dữ Khí Linh","tomTat":"Hàn Lập chất vấn Ngân Nguyệt về sự kiện trong Hư Thiên Điện, nàng thừa nhận bản thân là hồn khí của Ngọc Như Ý và đã cố ý để hắn lấy vật ký thân vì tu vi tổn hao, thà rơi vào tay Kết Đan kỳ còn hơn Nguyên Anh kỳ. Ngân Nguyệt xác nhận đã biết rõ mọi bí mật của Hàn Lập bao gồm tiểu bình thần bí nghịch thiên, khiến Hàn Lập thần sắc đại biến, cân nhắc giết người diệt khẩu. Ngân Nguyệt chủ động đề nghị rời nguyên thần khỏi Ngọc Như Ý, chuyển sang làm hồn khí cho Thanh Trúc Phong Vân Kiếm — pháp bảo bổn mạng vốn chưa có hồn khí — sinh tử sẽ bị ý niệm Hàn Lập nắm giữ, đổi lại khi chủ nhân đạt Hóa Thần kỳ nàng có thể được tự do. Hàn Lập chấp nhận vì không có cách khống chế tốt hơn. Ngân Nguyệt linh lực hao hết, thu về dạng tiểu bạch hồ, bị Hàn Lập thi triển cấm chế tạm thời. Hàn Lập sắp xếp kế hoạch giao bạch hồ cho đệ tử Lạc Vân Tông, hẹn Ngân Nguyệt tự chuồn đi khi chia tay rồi hắn chờ trên đường."},{"chuong":614,"tieuDe":"Khứ Nhi Phục Phản","tomTat":"Hàn Lập thả Phệ Kim Trùng cắn nuốt Thi Tiêu nhưng bất thành — thi độc quá mạnh giết chết một bộ phận trùng, thân Thi Tiêu cứng hơn cả Độc Giao ngày trước. Hàn Lập quyết bỏ lại Thi Tiêu tự sinh tự diệt vì không đáng hy sinh trùng, đã mang đi hộp ngọc chứa chủ hồn. Bạch hồ phân xuất tiểu lang vàng đưa hai người xuyên vách núi ra ngoài, Hàn Lập diễn kịch bắt yêu hồ giao cho Khuê Hoán nhốt vào túi Bích Vân. Vương sư huynh chia phần: Hàn Lập ba phần, bốn người kia chia phần còn lại, rồi hai bên chia tay. Nửa canh giờ sau, bạch hồ dễ dàng trốn khỏi pháp khí cấp thấp, dùng độn thổ cảm ứng Ngọc Như Ý tìm về Hàn Lập, thu nhỏ trốn vào cổ tay áo. Hàn Lập bay xuống phường thị dưới núi Lạc Vân Tông mua đủ tài liệu hóa hồn khí để biến Ngân Nguyệt thành hồn khí. Khi về tới dược viên, Hàn Lập phát hiện Khuê Hoán và Vương sư huynh sắc mặt sầu khổ chờ sẵn trước cấm chế hỏi về bạch hồ mất tích, Hàn Lập giả vờ không biết nhưng hỏi đúng sự việc khiến Khuê Hoán kinh ngạc."},{"chuong":615,"tieuDe":"Thí Kiếm Đại Hội","tomTat":"Khuê Hoán và Vương sư huynh tìm gặp Hàn Lập thông báo con Tuyết Vân Hồ đã bí ẩn trốn thoát khỏi túi Bích vân trên đường đem bán ở phường thị. Hàn Lập bình tĩnh bỏ qua, chỉ yêu cầu hoàn lại linh thạch đã cho mượn mà không đòi phần bồi thường, khiến Vương sư huynh hổ thẹn và muốn kết giao. Hai thanh niên đồng môn mang linh thạch bán Địa Hoàng Tinh về giao cho Hàn Lập, Hàn Lập dùng thần thức kiểm tra rồi thu nhận. Vương sư huynh giới thiệu về Thí Kiếm Đại Hội — đại hội do ba phái Vân Mộng Sơn (Lạc Vân Tông, Cổ Kiếm Môn, Bách Xảo Viện) tổ chức cho đệ tử dưới 30 tuổi, mục đích thực chất là phân chia thuần dịch từ Linh Nhãn Chi Thụ. Phái thắng được lấy một nửa thuần dịch, quán quân được thưởng đỉnh cấp pháp khí và một viên Định Linh Đan. Cổ Kiếm Môn với lợi thế kiếm tu luôn đoạt quán quân từ trước tới nay. Hàn Lập tỏ vẻ ngưng trọng khi biết đại hội liên quan đến Linh Nhãn Chi Thụ."},{"chuong":616,"tieuDe":"Minh Thanh Linh Thuỷ","tomTat":"Hàn Lập hỏi Vương sư huynh và Khuê Hoán về quy chế Thí Kiếm Đại Hội, được biết đại hội không phân biệt Luyện Khí kỳ với Trúc Cơ kỳ, tất cả tỷ thí chung. Vương sư huynh tiết lộ phần thưởng hấp dẫn nhất cho top mười là Minh Thanh Linh Thuỷ, phối chế từ linh dịch thánh thụ cùng dược tài ngàn năm, dùng rửa mắt giúp xuyên sương mù nhìn thấu đá. Hàn Lập động tâm muốn đoạt cả Định Linh Đan lẫn linh thuỷ. Quay về động phủ, Hàn Lập vẽ trận pháp cổ quái theo chỉ dẫn của Ngân Nguyệt để tách chủ hồn khỏi Ngọc Như Ý. Ngân Nguyệt trải qua quá trình thống khổ nhưng thành công, Ngọc Như Ý quang mang ảm đạm. Ngay sau đó Ngân Nguyệt hợp nhất với Thanh Trúc Phong Vân Kiếm, chính thức trở thành khí linh pháp bảo. Hàn Lập nhận Truyền Âm Phù triệu tập đệ tử Thiên Tuyền Phong từ Phong chủ, ngự kiếm bay đi. Ngân Nguyệt sau khi thành khí linh tính tình thay đổi, nói nhiều và hồ mị hơn, nhắc nhở Hàn Lập đừng đoạt quán quân để tránh bị hoài nghi, Hàn Lập khẳng định sẽ giữ ẩn danh đến khi ngưng kết Nguyên Anh."},{"chuong":617,"tieuDe":"Bán Lộ Lai Khách","tomTat":"Ngân Nguyệt hỏi Hàn Lập vì sao vẫn muốn Minh Thanh Linh Thủy, Hàn Lập giải thích thông tin Ẩn Kiếm Phong nói sai — linh thủy không phải vô hiệu với tu sĩ cấp cao mà do sau tẩy tủy dịch kinh mắt đã nhìn thấu huyễn thuật đơn giản, lau một lần không đủ, hắn biết từ điển tịch cổ xưa đọc ở Loạn Tinh Hải. Hàn Lập tiết lộ mục đích thật: mượn Thí Kiếm Đại Hội tiếp cận Linh Nhãn Chi Thụ, lấy linh căn dùng tiểu bình nuôi dưỡng để có vô hạn linh thủy và linh đan, chỉ cần lọt top mười là đủ. Mộ Phái Linh bay đến, dùng Thiên Tinh đai mang Hàn Lập bay cùng đến Thiên Tuyền Phong, trên đường hỏi hắn có tu luyện Huyền Băng Quyết không. Gần tới nơi, tu sĩ họ Ngôn chặn đường đòi bàn hôn sự với Mộ Phái Linh, nàng tuyên bố khi nào tu vi hắn bằng nàng mới xem xét rồi bay vọt qua, tu sĩ họ Ngôn nhìn Hàn Lập bằng ánh mắt oán độc. Đến Tẩy Tâm Điện trên sườn Thiên Tuyền Phong, năm sáu trăm đệ tử Luyện Khí kỳ đã tụ tập bên ngoài chờ phong chủ triệu tập liên quan Thí Kiếm Đại Hội, Mộ Phái Linh vào điện cùng các tu sĩ Trúc Cơ, Hàn Lập bị các đệ tử nhìn bằng ánh mắt khác thường và chỉ trỏ bàn tán."},{"chuong":618,"tieuDe":"Đỗ Đông Hòa Cận Kiến","tomTat":"Hàn Lập cùng Mộ sư thúc đến Tẩy Tâm điện, dùng thần thức nghe đệ tử Thiên Tuyền Phong bàn tán về mình. Đỗ Đông chủ động đến chào hỏi, kể được Tương sư bá bồi dưỡng chế phù, rồi dò hỏi thông tin nội bộ; Hàn Lập cố ý dùng ánh mắt uy áp khiến hắn kinh hãi tự rời xa, vì nhận định Đỗ Đông thân phận bất minh, lẫn vào tông môn có mưu đồ. Ngân Nguyệt qua thần niệm hỏi lý do, Hàn Lập giải thích muốn tránh liên lụy, Ngân Nguyệt im lặng thừa nhận. Trong Tẩy Tâm điện, Tân phong chủ và Vũ phó phong chủ chủ trì, công bố Cổ Kiếm Môn gửi thông hàm: nửa năm sau Thí Kiếm đại hội tổ chức tại Bách Xảo Viện ở Vân Mông Tây Mạch, ba phái mỗi bên 30 đệ tử, chọn 10 người đầu trọng thưởng. Điều kiện tham gia: tuổi không quá 30, tu vi ít nhất Luyện Khí kỳ mười tầng. Sáu vị trí do Lục đại phong chủ chỉ định, 24 còn lại thi đấu tuyển chọn sau một tháng. Mộ sư thúc được chỉ định đại diện Thiên Tuyền Phong không cần thi đấu."},{"chuong":619,"tieuDe":"Tông Nội Sơ Thí","tomTat":"Tại Tẩy Tâm điện, Phong chủ họ Tân cho đệ tử không đủ điều kiện rời đi, còn lại khoảng ba bốn mươi người, đại sư huynh họ Miêu giảng quy tắc tỷ thí: cấm dùng công pháp và binh khí quá độc ác hoặc gây chết người. Hàn Lập trở về động phủ chuẩn bị cho tỷ thí tháng sau, quyết định che giấu tu vi Kết Đan kỳ bằng cách dùng linh phù sơ-trung cấp, vài kiện pháp khí đỉnh giai và tham ngộ hoàn toàn Lộng Diễm quyết chỉ trong vài ngày. Phệ Kim trùng ngân sắc bắt đầu thôn phệ lẫn nhau tiến hóa thêm bước mới, còn Đề Hồn thú vẫn ngủ li bì trong Linh thú thất. Một tháng sau, hơn bốn năm trăm đệ tử các phong thi đấu tại đấu trường dưới đỉnh núi với ba tòa pháp trận. Hàn Lập xem trận đấu giữa tu sĩ họ Viên (Thiên Tuyền Phong, dùng Bạch kim qua) và Kim Dung (Bạch Phượng Phong), Kim Dung dùng thuật ẩn thân kết hợp hồng vụ đánh bại đối thủ ngoạn mục. Trận tiếp theo, Hàn Lập được gọi tên đấu với Tuân Thông của Hoả Vân Tông, thanh niên áo trắng tướng mạo anh tuấn vừa bước vào trận pháp đã gây tao động."},{"chuong":620,"tieuDe":"Ngưu Đao Sát Kê","tomTat":"Hàn Lập tham gia tỷ thí nội môn Lạc Vân Tông. Vòng 1 đối đầu Tuân sư đệ — thanh niên xuất thân Tuân gia, tu vi Luyện Khí kỳ tầng mười hai, sở hữu Thiên Dương Hoả Mạch. Tuân sư đệ kích hoạt vòng bảo hộ Hỏa thuộc tính và thôi động pháp khí Hoả Lãng châu, nhưng Hàn Lập thản nhiên ném ba bốn mươi lá Hoả Đạn phù cấp thấp đồng loạt phá vỡ phòng ngự trong vài giây, trọng tài phải ra tay cứu mạng đối thủ. Cách đánh xa xỉ khiến Hàn Lập bị gọi là phá gia chi tử. Hai ngày sau vòng 1 kết thúc, vòng 2 bắt đầu. Đối thủ vòng 2 là thanh niên áo xanh học theo chiến thuật phù lục nhưng xông lên cận chiến, Hàn Lập thi triển La Yên bộ biến mất khỏi chỗ đứng rồi xuất hiện sau lưng, gõ một đao đánh ngất đối phương. Các đệ tử có lịch duyệt nhận ra đây là thân pháp võ thuật Thế tục giới đạt trình độ cao minh chưa từng thấy, Hàn Lập bắt đầu nổi danh trong tông môn."},{"chuong":621,"tieuDe":"Lầu Các Chi Nghị","tomTat":"Ngày thứ 13 của tông nội tỷ thí, vòng tuyển chọn cuối cùng kết thúc với 24 người trúng tuyển. Bảy tám tu sĩ Kết Đan kỳ Lạc Vân Tông họp tại lầu các sườn núi chính bàn ai dẫn đội tham dự Thí kiếm đại hội — cuộc tỷ thí liên hợp ba phái (Lạc Vân Tông, Cổ Kiếm Môn, Bách Xảo Viện). Đoạn sư đệ (Phong chủ Hoả Vân Phong) chủ động nhận làm chủ dẫn đội, Vũ sư đệ làm phó, thêm Tống sư muội của Bạch Phượng Phong. Thiên Tuyền Phong bất ngờ chiếm 6 suất, trong đó Hàn Lập và Đỗ Đông — mới nhập môn vài năm, Luyện Khí Kỳ tầng 10 — đều lọt vòng cuối. Đỗ Đông thắng nhờ đỉnh cấp pháp khí Hàn Nguyệt Luân thuộc tính băng, bị các trưởng lão nhận ra là trấn tộc chi bảo Đỗ gia đã bị diệt hai trăm năm trước, suy đoán hắn là hậu nhân mai danh ẩn tích. Chương kết thúc khi chưa kịp bàn cách Hàn Lập thắng."},{"chuong":622,"tieuDe":"Quỷ Ảnh Đề Hồn","tomTat":"Các tu sĩ Kết Đan Kỳ Hoàng Phong Cốc thảo luận kết quả tỷ thí, nhận xét Hàn Lập dùng hơn 30 Hoả đạn phù, vũ kỹ thế tục và thao túng hoả diễm để thắng, xác nhận gã là tán tu tinh thông thuật chế phù. Thiên Tuyền Phong và Hoả Vân Phong tranh luận ai dìu dắt gã. Hàn Lập trở về động phủ tiểu thạch sơn, phát hiện Minh hồn châu nóng rực — Đề Hồn thú bắt đầu tiến cấp. Trong linh thú thạch thất, Đề Hồn thú kết kén đen cao hơn một trượng, sáng ngày thứ hai phá kén thành tiểu hầu đen nhánh với lỗ mũi thứ ba và đồ án ác quỷ một sừng ba mắt trên lưng. Hàn Lập kiểm tra Phệ Kim Trùng chỉ còn hơn mười con, to hơn trước ba phần, đang chuẩn bị sinh sản. Gã vào tịnh thất tu luyện với Linh nhãn chi ngọc, phóng thích Ngân Nguyệt tu luyện cách một bức tường. Ngân Nguyệt giải thích tu vi khí linh Kết Đan Hậu Kỳ nhưng thân Yêu hồ chỉ cấp một yêu thú, tu vi khí linh không tăng qua tu luyện, chỉ tu vi Yêu hồ mới là nền tảng, nhờ đan dược Hàn Lập cung cấp mà hồi phục nhanh."},{"chuong":623,"tieuDe":"Thông Minh Linh Tê","tomTat":"Hàn Lập khổ tu Thanh Nguyên Kiếm Quyết ba tháng trong động phủ dược viên. Khuê Hoán đến xin lỗi về việc tiết lộ chế phù thuật, Mộ Phái Linh đến giảng giải chỗ nghi nan trong Huyền Băng Quyết cho hắn nửa ngày. Hàn Lập nhận Truyền Âm Phù từ Tống sư tổ, bay đến Bạch Phượng Phong — ngọn núi cực đông Lạc Vân Tông, nhỏ nhất nhưng tú lệ nhất, nơi nhiều nữ tu cư trú. Hắn bái kiến Tống sư tổ tại Phượng Các trên đỉnh núi. Tống sư tổ — nữ tu Kết Đan Sơ Kỳ dung mạo tuyệt sắc — dùng thần thông Thông Minh Linh Tê dò xét tâm thần Hàn Lập, hắn vội vận Đại Diễn Quyết bảo vệ và vượt qua kiểm tra. Sau khi Hàn Lập đọc thuộc khẩu quyết Huyền Băng Quyết rồi xuống tầng dưới chờ, Tống sư tổ lập lồng cách âm gửi Truyền Âm Phù báo cáo cho bạch tu sư huynh: Hàn Lập không sao nhưng Đỗ Đông có vấn đề. Bạch tu lão giả phân tích Đỗ Gia nắm đại quyền cùng Bách Xảo Viện và giao tình với Phó Gia, nếu thật là hậu nhân Đỗ Gia lẽ ra phải bái nhập Bách Xảo Viện chứ không phải Lạc Vân Tông — nghi Đỗ Đông giả mạo thân phận. Hơn hai tháng sau, cảnh chuyển sang tông môn Bách Xảo Viện phía tây Vân Mộng Sơn, mấy ngàn đệ tử tụ tập trong sơn cốc lo lắng chờ đợi điều gì đó."},{"chuong":624,"tieuDe":"Tam Phái Thí Kiếm (Thượng)","tomTat":"Bách Xảo Viện đăng cai Thí Kiếm Đại Hội ba phái, Phó lão giả (Viện chủ) dẫn bảy tám Kết Đan và mấy ngàn đệ tử nghênh đón. Cổ Kiếm Môn đến trước bằng kiếm khí phi hành, do Khương Vân dẫn đầu cùng cặp Bạch Bích Song Kiếm. Lạc Vân Tông đến sau trên lưng dị chủng thanh quang điêu khổng lồ, do Đoàn huynh (hồng sam lão giả Hỏa Vân Phong) dẫn đầu, Tống tiên tử (Bạch Phượng Tiên Tử) lần đầu lộ diện — thân mang Thiên Linh Căn, chưa trăm năm đã kết đan, được xưng tụng thiên tài ngàn năm có một. Đại hội khai mạc với quy chế mỗi phái mười đệ tử, chia ba tổ qua hai mươi hai trận chọn mười hai người rồi rút thăm chọn mười người thắng cuối cùng. Trận đầu tiên, Hàn Lập (Luyện Khí mười một tầng) đại diện Lạc Vân Tông đấu Diêu Phong (Trúc Cơ sơ kỳ) Cổ Kiếm Môn. Dù tu vi thấp hơn nhiều, Hàn Lập phóng năm sáu mươi hỏa cầu áp đảo rồi đạp bất tỉnh Diêu Phong, thắng trận dễ dàng khiến tất cả kinh ngạc."},{"chuong":625,"tieuDe":"Tam Phái Thí Kiếm (Hạ)","tomTat":"Hàn Lập được trọng tài tuyên bố chiến thắng trận đầu Thí Kiếm Đại Hội, đánh bại đệ tử Cổ Kiếm Môn bằng Hỏa đạn phù, khiến Khương Vân mất mặt. Các tu sĩ Kết Đan nhận xét thân pháp Hàn Lập giống khinh thân thuật thế tục, tăng ba phần thực lực, vốn là tán tu sở học hỗn tạp. Vòng 1 kéo dài hai ngày, ngoại trừ Hàn Lập, Lạc Vân Tông và Bách Xảo Viện đều thua Cổ Kiếm Môn. Vòng hai Hàn Lập bắt quyết biến Hỏa đạn phù thành hơn mười con Hỏa Điểu, dùng thần niệm điều khiển tấn công tứ phương bát hướng, phá vỡ vòng bảo hộ thủy thuộc tính của nữ tu Bách Xảo Viện buộc đối phương nhận thua. Năm ngày sau, nho sinh họ Bạch cùng Vũ đạo hữu đến sơn cốc bí mật trong Vân Mộng Sơn kiểm tra thánh địa Minh Thanh Linh Thủy, nơi đang điều chế dung dịch tẩy mắt cho mười đệ tử liên quan Linh Nhãn Chi Thụ. Quán quân đại hội thuộc về Mạnh Địch, sư điệt Cổ Kiếm Môn. Tam sư huynh Cổ Kiếm Môn đang bế quan đánh sâu Kết Đan hậu kỳ."},{"chuong":626,"tieuDe":"Tam Phái Cấm Địa","tomTat":"Nho sinh họ Bạch (Cổ Kiếm Môn, Kết Đan) dùng truyền tống trận trở về thạch thất Bách Xảo Viện, xác nhận thánh địa chuẩn bị xong. Lão giả họ Phó phân công ba tu sĩ Kết Đan đại diện ba phái đi theo: Uông trưởng lão (Bách Xảo Viện), Vũ phong chủ (Lạc Vân Tông), nho sinh họ Bạch (Cổ Kiếm Môn). Mười đệ tử top mười Thí Kiếm Đại Hội được dẫn đến, trong đó Lạc Vân Tông chiếm bốn suất (Hàn Lập hạng chín, Đỗ Đông hạng mười — cả hai cố ý giấu thực lực), quán quân Mạnh Địch (Cổ Kiếm Môn) sở hữu Cửu Linh Kiếm Thể tung hoành vô đối, được thưởng Định Linh Đan. Hàn Lập quyết tâm nếu không lấy được linh căn Linh Nhãn Chi Thụ thì sẽ mượn Định Linh Đan từ tay Mạnh Địch. Chúng nhân được truyền tống đến vùng hoang vu sương mù dày đặc, thần thức Hàn Lập bị cấm chế chặn ở hơn mười trượng. Tu sĩ Kết Đan họ Việt trấn thủ cấm địa năm sáu mươi năm, dùng lệnh bài vàng mở cấm chế nhiều tầng do Nguyên Anh Kỳ thiết lập, tạo thông đạo cho mọi người bay vào."},{"chuong":627,"tieuDe":"Đồng Tử","tomTat":"Tu sĩ áo vàng dùng lệnh bài phá cấm chế dẫn đoàn tu sĩ qua thông đạo vào gian thạch sảnh rộng lớn bên trong núi. Trong sảnh, đồng tử bảy tám tuổi đang đánh cờ vây với lão giả mặt dài (Hồ sư điệt) — đồng tử chính là Lam sư thúc, tiền bối Nguyên Anh sơ kỳ của Cổ Kiếm Môn, khiến ba tu sĩ Kết Đan vội bái kiến. Hàn Lập nhận ra tu vi đối phương nhưng nhanh chóng trấn định, tự tin có thể thoát nếu cần. Sau ván cờ, đồng tử lật tẩy nho sinh họ Bạch thực chất là nhập môn đệ tử Hạo Nhiên Các trà trộn hơn trăm năm. Nho sinh thừa nhận, bạo phát dùng Thái bạch hóa khí thủ nhắm bắt Mạnh Địch (Cửu Linh Kiếm Thể) nhưng bị đồng tử bắn kiếm khí hóa tơ — tuyến tơ tằm đỏ bao bọc hàn khí — hạ gục trong nháy mắt, chỉ Hàn Lập dùng thần thức phát hiện. Đồng tử ra lệnh nhốt nho sinh vào long quật, nói còn cần hắn hữu dụng. Hàn Lập quan sát Đỗ Đông hai tay nắm chặt, rõ ràng rất khẩn trương, âm thầm mỉm cười rồi bỏ qua."},{"chuong":628,"tieuDe":"Linh Nhãn Chi Thụ","tomTat":"Đồng tử họ Lam (Bạch đạo hữu) khoát tay đuổi mọi người ra khỏi đại sảnh, nói muốn ở lại nghiên cứu bàn cờ. Đoàn người do hoàng y tu sĩ dẫn đầu đi qua hành lang tới cánh cửa đá vàng xỉn, gặp Vệ sư huynh — tu sĩ Kết Đan kỳ Lạc Vân Tông đang vào cảnh giới giả anh, đã thề không rời thánh địa trước khi kết anh. Lão giả áo xám (Vũ sư đệ) nhận ra đây là sư huynh của mình, xúc động nhưng nuốt lời. Vệ sư huynh mở cấm chế dẫn mọi người vào hang động rộng vài trăm trượng có rừng trụ đá thạch nhũ. Trung tâm hang là Linh Nhãn Chi Thụ — trụ đá xanh nhạt phát linh khí tinh thuần cao hơn cả Linh Nhãn Chi Ngọc, được hào quang vàng bảo vệ, dưới gốc có bình ngọc chứa hương dược phối chế Minh Thanh Linh Thủy. Vệ sư huynh kiểm tra thấy Thuần dịch chưa tích đủ, cần chờ thêm ba bốn canh giờ. Trong lúc mọi người nghỉ ngơi, Hàn Lập âm thầm sai Ngân Nguyệt hóa tiểu lang dùng thổ độn thuật chui dưới đất vượt hào quang vàng đánh cắp linh căn Linh Nhãn Chi Thụ. Cuối chương Hàn Lập liếc sang Đỗ Đông đang ngồi tu luyện, khoé miệng nhếch lên trào phúng, ngầm phát hiện điều bất thường ở y."},{"chuong":629,"tieuDe":"Ngụy Biến","tomTat":"Hàn Lập dùng thần thức giám sát phát hiện Đỗ Đông lén liên lạc với một tu sĩ Kết Đan Kỳ nhưng chưa xác định ai. Ngân Nguyệt báo Linh Nhãn Chi Thụ được hào quang vàng bảo vệ, Hàn Lập từ chối đề nghị phá và triệu hồi Ngân Nguyệt trở về, dự đoán sắp có hỗn loạn. Bên ngoài nổ ra cuộc tấn công quy mô lớn của tu sĩ giấu mặt nghi là Ma Đạo Lục Tông, có cả Nguyên Anh Kỳ, Lam tiền bối chủ trì đại trận, ba tu sĩ Kết Đan Kỳ ra ứng chiến chỉ lưu Vệ sư huynh canh giữ. Mười đệ tử bị đưa vào tĩnh thất trú ẩn, Đỗ Đông dần bộc lộ bản chất dữ tợn khiến Mộ Phái Linh cảnh giác chất vấn. Bạch tu sĩ phá cửa tĩnh thất xông vào tự xưng đệ tử đích truyền Ma đạo Thiên Huyễn Tông, hé lộ đã đồng bọn với Đỗ Đông từ trước. Một đệ tử Cổ Kiếm Môn cố chạy trốn bị Bạch tu sĩ chém chết tại chỗ."},{"chuong":630,"tieuDe":"Đại La Thiên Huyễn Quyết Và Thiên Hồ Mê Linh","tomTat":"Đỗ Đông phát động Đại La Thiên Huyễn Quyết — trấn phái pháp quyết của Thiên Huyễn Tông — hóa cự hán hai trượng, tu vi tăng lên Kết Đan Trung Kỳ, xông tới giết phân thân giả Hàn Lập rồi cùng Nho sinh đánh hôn mê toàn bộ đệ tử. Hàn Lập thật đã dùng Ngọc Như Ý độn vào vách tường từ trước, Ngân Nguyệt dùng Thiên Hồ Mê Linh Đại Pháp tạo phân thân giả chịu chết thay. Sau khi hai kẻ rời đi, Hàn Lập hiện thân, sai Ngân Nguyệt lấy Định Linh Đan từ túi trữ vật Khuê Hoán. Hàn Lập bay tới Linh Nhãn Chi Thụ động quật, dùng thần thức phát hiện bên trong có bảy tám người gồm một tu sĩ Nguyên Anh Kỳ (lão giả tóc rối) và nhóm Kết Đan được đồng tử họ Lam che chở bằng quang tráo vàng. Lão giả tóc rối tiết lộ chánh tà hai phái phát hiện Huyền Thiên Tiên Đằng cổ thụ thượng cổ gần Mộ Lan thảo nguyên đã héo, cần thuần dịch Linh Nhãn Chi Thụ để cứu, đã cài đệ tử lén vào ba đại môn phái nhiều năm. Đỗ Đông lộ thân phận thiếu chủ Thiên Huyễn Tông, Nho sinh lộ là đệ tử Thiên Sát Tông bị Đỗ Đông gọi là Vệ huynh."},{"chuong":631,"tieuDe":"Toán Kế","tomTat":"Trong quang tráo nơi Linh Nhãn Chi Thụ, lão giả tóc rối (gián điệp Thiên Sát Tông nằm vùng Lạc Vân Tông hơn trăm năm) từ chối giao linh thụ cho Đỗ Đông vì ân nghĩa với Vân trưởng lão, chỉ đồng ý giao thuần dịch. Đồng thời nho sinh họ Bạch được tiết lộ là gián điệp Chánh đạo minh tuân lệnh Đỗ Đông — thiếu chủ Thiên Huyễn Tông. Khi lão giả tóc rối lấy bình thuần dịch, Hỏa Long Đồng Tử (đồng tử họ Lam) và tu sĩ ba phái bất ngờ xuất hiện: toàn bộ âm thanh tấn công trước đó là giả, nhằm dụ gián điệp chánh-ma lộ mặt. Tuy nhiên Thiên Sát Chân Quân (tông chủ Thiên Sát Tông) đã cài sẵn Phụ Thân Đại Pháp vào lão giả tóc rối, phụ thân kích hoạt tấn công đồng tử. Lão giả họ Khương bay vào báo: tu sĩ ba phái mai phục bên ngoài bị Thiên Sát Tông và Thiên Huyễn Tông phản mai phục. Hàn Lập ẩn mình quan sát, nhận ra công pháp phụ thân, lập tức truyền âm cho Ngân Nguyệt quay về tĩnh thất giả dạng hắn bị trọng thương. Thiên Sát Chân Quân ném bình thuần dịch cho Đỗ Đông rồi xông tấn công lão giả họ Khương."},{"chuong":632,"tieuDe":"Đắc Linh Căn","tomTat":"Thiên Sát Chân Quân dùng mưu lừa bạch y thiếu phụ, cướp lão giả mặt dài về phe mình rồi dùng Tử La Huyền Công quấn chân Đồng Tử họ Lam. Lão giả mặt dài tiết lộ đã phá hoại cấm chế bên ngoài chỉ còn một phần mười uy lực, Đỗ Đông cùng nho sinh và lão giả mặt dài đánh xuyên phòng tuyến Phó lão giả đào thoát. Đồng Tử họ Lam tuyên bố không để ma đạo mang thuần dịch Vân Mộng Sơn đi, truy đuổi ra ngoài cùng Thiên Sát. Hàn Lập thừa lúc động quật vắng người, dùng Ngọc Như Ý thi triển thổ độn xâm nhập quang tráo kim sắc, cắt đứt một tiểu linh căn từ Linh Nhãn Chi Thụ cất vào hộp ngọc. Phát hiện ngọc giản lục quang của lão giả họ Vệ chứa công pháp tu luyện và phương pháp luyện chế Định Linh Đan cùng Minh Thanh Linh Thủy, sao chép nội dung rồi đặt bản gốc lại. Cuối cùng dùng Thanh Nguyên Kiếm Quang phá quang tráo rời đi."},{"chuong":633,"tieuDe":"Phản Hồi","tomTat":"Hàn Lập trở về tĩnh thất, dùng Huyễn thuật phù tự chế để giải thích lý do sống sót trước mặt hoàng y tu sĩ họ Phó và đám đệ tử, hầu hết không hoài nghi dù Tôn Hỏa và Mộ Phái Linh còn ngờ vực. Hoàng y tu sĩ giải thuật hôn mê cho đám đệ tử, cùng thượng tầng ba phái phát pháp khí bồi thường rồi tuyên bố Thí Kiếm Đại Hội kết thúc. Về Lạc Vân Tông, Hàn Lập biết được toàn cảnh: đám Đỗ Đông được Thiên Sát Tông tông chủ dùng Phụ Thân Đại Pháp che chở thoát cùng thuần dịch, nho sinh họ Bạch bị giết tại chỗ, trưởng lão Nguyên Anh kỳ họ Trình bị trọng thương trong trận mai phục của Thiên Huyễn Tông và Thiên Sát Tông. Thuần dịch tưới cho Huyền Thiên Tiên Đằng nhưng cây vẫn héo rũ không hồi sinh, ba phái và Thiên Đạo Minh thở phào. Hàn Lập trồng linh căn Linh Nhãn Chi Thụ gần Cửu Khúc Linh Sâm trong động phủ, đột phá chướng ngại Đại Diễn Quyết nhờ Dưỡng Hồn Mộc Châu cường hóa thần thức, đồng tu Đại Diễn Quyết và Thanh Nguyên Kiếm Quyết, luyện tập thuật luyện đan. Khổ tu hơn hai mươi năm tại Lạc Vân Tông, ngày ngưng kết Nguyên Anh sắp tới."},{"chuong":634,"tieuDe":"Kết Anh (Thượng)","tomTat":"Hàn Lập luyện thành công Cửu Khúc Linh Sâm đan sau nhiều lần thất bại, nguyên liệu Mã Não Giác và Bạn Yêu Thảo gần cạn kiệt. Hắn phát hiện phương pháp dùng lục dịch nhỏ vào Cửu Khúc Linh Sâm để hồi phục nguyên khí, tạo nguồn tham dịch liên tục không dứt. Đại Diễn Quyết tầng bốn đã thành từ lâu, Thanh Nguyên Kiếm Quyết đại viên mãn tầng chín đưa tu vi vào giả anh, mọi chuẩn bị hoàn tất. Hàn Lập ra Vân Mộng Sơn hồi tưởng nhân sinh ba ngày rồi lĩnh ngộ thiên địa chi đạo một tháng, đạt trạng thái đỉnh điểm thân tâm pháp lực. Trở về động phủ, hắn dặn Ngân Nguyệt bảo vệ cửa, vào tĩnh thất bố trí cấm chế, chính thức bế quan kết Nguyên Anh. Ngân Nguyệt đoán biết, mặt hiện vẻ hâm mộ khát vọng không cam lòng rồi thở dài rời đi. Tuyến phụ: Mộ Phái Linh bị trưởng lão Mộ gia ép thành thân với Ngôn sư huynh, dọa cắt linh thạch và liên lụy người thân, nàng bất lực chạy trốn tới dược viên Hàn Lập, vẫn đánh giá sai Hàn Lập là đệ tử bình thường tư chất kém."},{"chuong":635,"tieuDe":"Kết Anh (Trung)","tomTat":"Hàn Lập đang kết Nguyên Anh bên trong động phủ tiểu sơn thạch tại Vân Mộng Sơn, gây dị tượng thiên địa: linh quang ngũ sắc đầy trời trong phạm vi trăm dặm, linh khí hỗn loạn quay cuồng, mưa gió sấm sét nổi lên. Mộ Phái Linh đang phi hành gần đó bị áp lực linh khí đè suýt ngã, chứng kiến kỳ cảnh kinh hãi. Hàng ngàn tu sĩ Lạc Vân Tông cảm ứng biến đổi, tu sĩ Luyện Khí Kỳ bị linh áp đè khó thở. Trên chủ phong, hai vị Nguyên Anh Trình sư huynh và Lữ sư đệ phát hiện hiện tượng, xác nhận có người kết anh ngay trong lãnh thổ tông môn, suy đoán là tán tu lén vào. Hai người quyết định không can thiệp: nếu thất bại sẽ xử lý, nếu thành công sẽ lôi kéo kết giao. Lữ sư đệ nhắc lại bản thân khi kết anh phải dùng Định Linh Đan mới vượt qua tâm ma cắn trả. Cuối cùng, thanh quang trụ từ động phủ phun ra, quang đoàn trên trời ngưng tụ thành viên châu trong suốt cỡ nắm tay ẩn chứa linh khí khổng lồ, khiến tu sĩ xung quanh sắc mặt đại biến."},{"chuong":636,"tieuDe":"Kết Anh (Hạ)","tomTat":"Viên châu ngũ sắc hóa đám mây chui vào sơn thạch, tiếng rồng ngâm vang trời, quang ảnh hình người trăm trượng hiện trên không phát ra uy áp khủng khiếp khiến tu sĩ xung quanh quỳ gối. Trong tĩnh thất, Nguyên Anh hình đứa trẻ một tấc giống hệt Hàn Lập xuất hiện trên Thiên Linh Cái — hắn chính thức bước vào Nguyên Anh Sơ Kỳ. Ngân Nguyệt hóa hình thiếu phụ diễm lệ canh giữ bên ngoài, lần đầu gọi Hàn Lập là chủ nhân với thái độ thật sự cung kính, tiết lộ hắn mới khoảng hai trăm tuổi, thọ mệnh giờ hơn ngàn năm. Thiên triệu kết anh gây chấn động toàn Lạc Vân Tông, hơn ngàn đệ tử tụ tập bàn tán, năm sáu tu sĩ Kết Đan bay đến phong tỏa mười dặm quanh núi thành cấm địa. Mộ Phái Linh xác nhận Hàn Lập là đệ tử Luyện Khí Kỳ quản dược viên, hồng sam lão giả nhớ ra hắn từng lọt vào mười người đứng đầu Thí Kiếm Đại Hội hai mươi năm trước. Hai vị sư thúc Nguyên Anh đích thân bay đến ra lệnh đám Kết Đan rời đi, Trình Thiên Khôn xưng danh bái phỏng chúc mừng Hàn Lập kết anh và xin cùng sư đệ vào phủ."},{"chuong":637,"tieuDe":"Lời Mời","tomTat":"Hàn Lập dặn Ngân Nguyệt gỡ cấm chế nhưng không được lộ diện vì yêu khí trên thân sẽ bị tu sĩ Nguyên Anh phát hiện. Hai trưởng lão Lạc Vân Tông — lão giả tóc bạc họ Trịnh và tu sĩ họ Lữ — vào động phủ, cười khổ khi thấy trận pháp lợi hại trong sơn môn mình mà không hề cảm ứng. Hàn Lập dùng khôi lỗi cự viên hình vượn bưng trà tiếp khách, khiến hai người kinh ngạc vì biết Khôi Lỗi Thuật. Hàn Lập nửa thật nửa giả tiết lộ xuất thân Việt Quốc, học Khôi Lỗi Thuật từ điển tịch vô danh, từng dùng Định Nhan Đan giữ dung mạo trẻ trung. Khi tiết lộ chỉ hơn hai trăm tuổi đã ngưng kết Nguyên Anh, hai trưởng lão cực kỳ chấn kinh — lão giả tóc bạc nhớ lại lịch sử Thiên Nam chỉ hơn mười người làm được, trong đó có một vị đột phá Nguyên Anh hậu kỳ rồi phi thăng vào giới khác. Lão giả tóc bạc chính thức mời Hàn Lập gia nhập Lạc Vân Tông làm trưởng lão ngang hàng, nhưng Hàn Lập nhíu mày chần chờ chưa quyết định."},{"chuong":638,"tieuDe":"Hư Thiên Đỉnh, Bình Nhỏ, Thông Thiên Linh Bảo","tomTat":"Hai trưởng lão Lạc Vân Tông tha thiết mời Hàn Lập ở lại làm Thái thượng trưởng lão, hứa hàng năm cung phụng hơn ngàn linh thạch, đệ tử phục vụ và chỉ điểm tu luyện. Hàn Lập xin hoãn ba ngày suy nghĩ. Sau khi hai trưởng lão rời đi, Ngân Nguyệt khôi phục nguyên hình bạch hồ do pháp lực không đủ duy trì hình người. Ngân Nguyệt tiết lộ Hư Thiên Đỉnh thực chất là Thông Thiên Linh Bảo, uy lực vượt xa cổ bảo thông thường, muốn khống chế phải luyện hóa Kiềm Lam Băng Diễm làm bước đầu tiên. Trong đỉnh ngoài hai khối Bổ Thiên Đan đã không còn cổ bảo nào. Ngân Nguyệt bình luận tiểu bình thần bí của Hàn Lập có khả năng thúc dục linh dược là nghịch thiên, phỏng đoán do tu sĩ linh giới hoặc tiên nhân tiên giới luyện chế. Hàn Lập chấn động, lấy tiểu bình ra xem xét hồi lâu rồi hỏi ý Ngân Nguyệt nên ở lại Lạc Vân Tông hay tìm nơi tốt hơn."},{"chuong":639,"tieuDe":"Nhất Phái Trưởng Lão","tomTat":"Sau khi kết anh thành công, Ngân Nguyệt phân tích tình hình Lạc Vân Tông và khuyên Hàn Lập tạm lưu lại để có Nguyên Anh Kỳ tu sĩ chỉ điểm. Hàn Lập cho biết kế hoạch: tạm ngưng cố nguyên anh, sau đó đi cực tây lấy Đại Diễn Quyết tầng ba, rồi đến Nguyên Vũ Quốc diệt gia tộc họ Phó theo lời hứa năm xưa. Nằm trên giường, hắn hồi tưởng chi tiết quá trình kết anh: toái đan đau đớn nhờ Cửu Khúc Linh Sâm, hai đợt tâm ma — sợ hãi và mê luyến — suýt trầm luân, nhờ Định Linh Đan, Dưỡng Hồn Mộc, Bà La Châu mới thoát, rồi trải nghiệm nguyên anh xuất khiếu lần đầu và giấc mộng tuổi thơ. Hàn Lập đồng ý gia nhập Lạc Vân Tông làm trưởng lão Nguyên Anh Kỳ thứ ba, từ chối đại điển, chỉ thông báo hai phái khác ở Vân Mộng Sơn. Các Kết Đan đệ tử triệu kiến cung kính gọi Hàn sư thúc, nữ tử họ Tống lộ vẻ phức tạp khi gọi sư thúc. Hàn Lập chọn ngọn núi phía đông lập động phủ, bố trận pháp sương mù bao phủ hơn mười dặm. Cuối cùng hắn quay lại dược viên cũ thu dọn, gặp Mộ Phái Linh chờ sẵn xin bái sư, nguyện cả đời phụng dưỡng."},{"chuong":640,"tieuDe":"Biến Giả Thành Thật","tomTat":"Mộ Phái Linh xin làm môn hạ Hàn Lập để tránh hôn ước song tu ép buộc với Ngôn sư huynh, nhưng bị Hàn Lập cự tuyệt, phất tay áo tạo cuồng phong thổi nàng ra xa rồi ẩn thân. Hàn Lập trở về động phủ trong núi đá, kiểm tra trùng thất thấy gần vạn Phệ Kim Trùng đã tiến giai từ kim ngân lên xích kim với năng lực cắn nuốt và độ cứng vượt xa tam sắc phi trùng, hắn lo cấm chế sẽ mất hiệu lực khi chúng tiến hóa tiếp và tách nhóm lớn nhất tự dưỡng thúc dục. Hắn di chuyển Linh Nhãn Chi Thụ sắp sản linh dịch cùng Cửu Khúc Linh Sâm đã hồi phục quá nửa về tân động phủ, bỏ lại tạp linh dược. Tại tân động phủ, Hàn Lập nhập tĩnh thất trăm ngày ngưng thể nguyên anh cực kỳ thuận lợi, sơ bộ hợp nhất tâm thần với nguyên anh, nguyên anh tái xuất khiếu khống chế dễ dàng. Ra khỏi tĩnh thất, Ngân Nguyệt báo tin Mộ Phái Linh đã tự xưng với Ngôn gia và Mộ gia rằng nàng bị Hàn Lập nhận làm thị thiếp, khiến hai tộc truyền âm phù cáo lỗi và giải trừ hôn ước. Ban đầu tức giận, nhưng sau khi Ngân Nguyệt phân tích tâm lý, Hàn Lập bất ngờ đổi thái độ, quyết định lộng giả thành chân chấp nhận nạp Mộ nữ tử làm thị thiếp để nếm thử song tu, đồng thời lộ lời nếu gặp lại Văn Tư Nguyệt sẽ không dễ dàng buông tha."},{"chuong":641,"tieuDe":"Ước Hẹn Ba Mươi Năm","tomTat":"Hàn Lập sai Ngân Nguyệt đưa Mộ Phái Linh vào đại sảnh để gặp riêng, không giải thích mục đích thật với Ngân Nguyệt. Hắn chất vấn Mộ Phái Linh về lời đồn tự nhận quan hệ với hắn đã lan khắp tu tiên giới, nói rằng bên ngoài chỉ có thể coi nàng là thiếp của hắn, rồi đưa hai lựa chọn: làm thị nữ hai mươi năm hoặc làm thị thiếp chịu cấm thần thuật. Mộ Phái Linh xin hai ngày suy nghĩ rồi xuống núi. Ngân Nguyệt nhận xét Mộ Phái Linh gây cho mình cảm giác thân thiết kỳ lạ như từng thân cận với một người tương tự, sau đó cùng Hàn Lập bàn cách luyện hóa Kiền Lam Băng Diễm. Khi quay lại, Mộ Phái Linh chọn làm thiếp và chấp nhận cấm chế cả đời, nhưng đặt điều kiện ba mươi năm Hàn Lập không chiếm nguyên âm vì công pháp nàng cần thân xử nữ. Hàn Lập đồng ý, tuyên bố sẽ báo các trưởng lão chính thức nhận nàng làm thiếp, tạo động phủ riêng cho nàng tu luyện và bảo nàng đổi cách xưng hô sang công tử."},{"chuong":642,"tieuDe":"Điên Phượng Bồi Nguyên Công","tomTat":"Hàn Lập giao lệnh bài cấm chế màu tím cho Mộ Phái Linh, đặt điều kiện nàng phải dứt bỏ mọi quan hệ cũ trước khi chính thức trở thành thiếp. Mộ Phái Linh khẳng định không có người trong lòng và thuận phục rời đi theo cự viên khôi lỗi. Sau đó Hàn Lập tiết lộ với Ngân Nguyệt rằng mục đích thật sự là dùng Điên Phượng Bồi Nguyên công — bí thuật song tu ma đạo do Lục đạo cực thánh sáng tạo, ghi trong ngọc giản lấy từ túi trữ vật Lục đạo thiếu chủ — để chờ Mộ Phái Linh kết đan rồi kiêm tu, nhằm hỗ trợ hắn đột phá sau Nguyên Anh. Dù sẽ dùng cấm thần thuật khống chế sinh tử nàng, Hàn Lập vẫn nghi ngờ nàng có mục đích riêng, giao Ngân Nguyệt âm thầm theo dõi. Hàn Lập thi triển cấm thần thuật, tặng đan dược Trúc Cơ Kỳ, hai trưởng lão Lạc Vân tông cũng tặng pháp khí chúc mừng. Mộ Phái Linh bắt đầu bế quan khổ tu bên Hàn Lập, còn hắn thỉnh thoảng sang thỉnh giáo hai trưởng lão Nguyên Anh. Mấy tháng sau Linh Nhãn Chi Thụ sinh thuần dịch, Hàn Lập phối chế thành Minh Thanh Linh Thủy và dẫn linh thủy bắn hai đạo lam quang vào mắt, gây biến hóa nóng lạnh bất thường khiến hắn giật mình nhắm mắt."},{"chuong":643,"tieuDe":"Đại Canh Kiếm Trận","tomTat":"Hàn Lập hoàn tất thanh tẩy hai mắt bằng Minh Thanh Linh Thủy, đắc được lam quang có thể nhìn xuyên vách tường khi vận linh lực, quyết định nửa tháng thanh tẩy một lần để bồi dưỡng thần thông cho mắt. Ngày hôm sau lấy giấy vàng Thanh Nguyên Kiếm Quyết xem lại, xác nhận kiếm quyết gồm 13 tầng từ Thanh Nguyên Kiếm Quang đến Đại Canh Kiếm Trận. Nhờ tu vi đã đạt Nguyên Anh Kỳ, hắn phun thanh quang giải cấm chế trên giấy vàng, khai mở tầng 13 và ngồi lĩnh ngộ Đại Canh Kiếm Trận suốt 3 ngày 3 đêm. Kiếm trận tu đến đỉnh chỉ cần 1/3 uy lực đã tung hoành Thiên Nam, nhưng cần 72 phi kiếm Thanh Trúc Phong Vân mỗi thanh trộn thêm Canh Tinh — tài liệu cực hiếm mấy ngàn năm không xuất hiện. Cuối cùng Hàn Lập chuyển sang lấy Kiền Lam Băng Diễm ra, xác định nay tu vi đủ khống chế, nếu luyện hóa thành công thì Hư Thiên Đỉnh có hy vọng."},{"chuong":644,"tieuDe":"Nặc Ngôn Hòa Khải Trình","tomTat":"Hàn Lập chọn bí thuật từ Huyền Âm Kinh để luyện hóa Kiền Lam Băng Diễm, dùng Ích Tà Thần Lôi kết điện võng áp chế băng châu khiến nó hiện nguyên hình rồi hóa thành lam diễm tràn hàn khí khắp phòng. Khi một tia lam diễm thoát khỏi điện võng, hắn để Nguyên Anh xuất khiếu dùng bổn mệnh tinh khí bao lại rồi nuốt vào luyện hóa, nhận ra chỉ một tia nhỏ đã cần thời gian dài bồi luyện nên không dám mạo hiểm luyện toàn bộ. Sau đó hắn ghé Tử Phong động phủ kiểm tra Mộ Phái Linh đang bế quan khổ tu, thấy tu vi tiến bộ nên âm thầm rời đi. Hắn đến chỗ ngân phát lão giả hỏi tin Canh Tinh nhưng không có kết quả, được biết hai năm sau ở Ngu quốc sẽ có hội giao dịch lớn nhất Thiên Nam có thể tìm được Canh Tinh. Hàn Lập cáo từ với lý do du lịch, phong kín động phủ rồi rời Vân Mộng sơn hướng Nguyên Vũ quốc để giải quyết lời hứa năm xưa với Tần Như Âm. Chương kết bằng việc giới thiệu Phó gia Nguyên Vũ quốc — gia tộc đầu nhập Ma Diễm Tông khi ma đạo xâm lấn, nhờ đó vươn lên thành đệ nhất gia tộc, đồng thời đoạn tuyệt quan hệ với Phó gia Bách Xảo Viện."},{"chuong":645,"tieuDe":"Ba Người Đồng Hành","tomTat":"Tọa địa Phó gia nằm trong thâm sơn Tử Đạo Sơn ở phía tây Nguyên Vũ quốc, bị tử vụ độc bao phủ và trận Độc Vân Tử Chướng Trận bảo vệ; gần đây nhiều tu sĩ kéo tới ngoài tử vụ chờ dịp thọ đản lão tổ Phó gia. Hàn Lập cải trang thành tán tu tóc dài, đồng hành cùng La huynh (tu sĩ béo lùn) và một đại hán cao lớn, ba người đến trấn Thái Hòa cách Tử Đạo Sơn mười dặm, trọ tại khách điếm Vĩnh Khúc chờ ngày vào Phó gia bảo tìm cơ duyên. Tại khách điếm, Hàn Lập dùng Kinh hồn thuật lên tiểu nhị A Nhị, chỉ qua tiếp xúc đã nhận ra A Nhị có linh căn tư chất đủ tu tới luyện khí kỳ tầng ba bốn, khiến hai bạn đồng hành kinh ngạc gọi là thần thông kinh người. Bị gặng hỏi lai lịch, Hàn Lập khai giả là tu sĩ Việt Quốc mới sang Nguyên Vũ Quốc, viện cớ không vào được Quỷ Linh Môn nên tìm cơ hội qua thọ đản. Sau khi Hàn Lập rời sang phòng bên nghỉ, La huynh lập tức đổi vẻ dữ tợn, lấy Cách âm phù bao bọc phòng bạch quang cách âm, cùng đại hán bàn nhau kết luận Hàn Lập quá nửa là đệ tử tông phái nào đó chứ không phải tán tu thật."},{"chuong":646,"tieuDe":"Tâm Hoài Quỷ Thai","tomTat":"Tại Nguyên Vũ Quốc, cặp hung tu Bành Dịch Song Hung gồm tu sĩ ục ịch họ La và đại hán đầu hói bàn mưu giết Hàn Lập đoạt bảo, nhận định hắn là tu sĩ tiểu phái giả tán tu vì sở hữu phi kiếm ngự khí đỉnh cấp và túi trữ vật căng phồng. Tuy nhiên Hàn Lập nghe trọn âm mưu qua vách vì lồng cách âm của chúng không che nổi thần thức tu sĩ Nguyên Anh Kỳ. Chương tiết lộ Hàn Lập đã cải dung đến Nguyên Vũ Quốc từ hai tháng trước để điều tra Phó Gia, phát hiện Phó Gia có ba tu sĩ Kết Đan Kỳ và nhiều đệ tử đã vào Ma Diễm Môn, khiến việc thực hiện lời hứa với Tân Như Âm phức tạp hơn. Khi biết Phó Gia lão tổ sắp mừng thọ, hắn quyết chờ đúng ngày để mọi chi hệ tụ về rồi một lưới bắt hết, đồng thời lợi dụng Bành Dịch Song Hung che giấu thân phận. Hai ngày trước thọ yến, hai hung tu dẫn Hàn Lập tới tiểu sơn vắng người nơi đã bố trí trận pháp vây địch trong tiểu cốc. Hàn Lập phát hiện bẫy bằng thần thức, không vào cốc mà chủ động vạch mặt ý đồ, khiến La huynh đành ra hiệu cùng đồng bọn đồng loạt động thủ."},{"chuong":647,"tieuDe":"Yêu Anh","tomTat":"Đúng lúc Hàn Lập giả dạng Trúc Cơ đối mặt Bành Dịch Song Hung, một tiếng nữ đồng bí ẩn vang lên vạch trần hắn là tu sĩ Nguyên Anh kỳ. Hàn Lập dùng thần thức quét mười dặm nhưng không tìm ra đối phương, trong khi nguyên anh trong đan điền tự tỉnh dậy biểu hiện sợ hãi. Không thể che giấu nữa, Hàn Lập lộ khí thế Nguyên Anh và phóng bảy mươi hai Thanh Trúc Phong Vân Kiếm hộ thân, rồi đuổi kịp chém chết đại hán đầu bóng đang dùng Kim độn phù bỏ chạy. Nhờ Minh Thanh Linh Nhãn, Hàn Lập phát hiện đối phương ngụy trang thành cây nhỏ bằng Huyễn quang hóa vật quyết và ép hiện hình. Đối phương hóa thành tiểu nhân lục quang diện mục thanh tú, bị Hàn Lập gọi là Yêu Anh, lập tức chui vào thân tu sĩ ục ịch rút tinh hồn nuốt mất. Yêu Anh tuyên bố muốn nuốt Nguyên Anh của Hàn Lập để thử tiến cấp Nguyên Anh trung kỳ. Hàn Lập phóng Ích Tà Thần Lôi công kích nhưng đối phương không sợ, chế giễu rằng nó không tu ma công quỷ pháp nên thần lôi vô dụng."},{"chuong":648,"tieuDe":"Mộc Linh Anh","tomTat":"Hàn Lập nhận ra lục sắc tiểu nhân chỉ đủ sức đối phó tu sĩ cấp thấp chứ không thể cắn nuốt Nguyên Anh. Hắn điều mười hai thanh phi kiếm Kim Lôi Trúc chém đối phương thành vô số mảnh nhưng nó lập tức hợp nhất. Hàn Lập chuyển sang dùng Ích Tà Thần Lôi kết thành kim hồ điện võng co rút nhốt lục sắc tiểu nhân thành kim cầu, gia cố bằng nhiều lớp kim hồ rồi phong vào hộp bạch ngọc dán phù lục cấm chế. Hắn thiêu hủy tu sĩ ục ịch đã mất hồn phách và trở về khách điếm chờ thọ yến. Tại Kỳ Linh Sơn phía tây Thiên La Quốc, lão già Ngự Linh Tông phát hiện Mộc Linh Anh bị giam cầm, giận dữ ra lệnh đệ tử ở Nguyên Vũ Quốc tìm trong ba tháng và giữ kín với Ma Diễm Môn, đồng thời sai Vân Chi và Liễu Ngọc đến vì linh căn mộc thuộc tính có thể cảm ứng linh anh. Ở Tử đạo sơn, Phó gia tất bật chuẩn bị thọ yến bốn trăm tuổi cho gia chủ Phó Thiên Hóa, hai hộ pháp Ma Diễm Môn đã hứa tới chúc thọ."},{"chuong":649,"tieuDe":"Dự Triệu","tomTat":"Trong thính phòng Phó Gia Bảo, Phó Gia lão tổ tâm thần bất an cảm nhận linh triệu đại kiếp sắp tới trước ngày mừng thọ. Ông ra lệnh phòng bị toàn diện: gấp đôi canh gác, mở đại trận hộ bảo không ngừng, đặc biệt để ý tán tu lạ, và triệu tam thúc cùng Thiết Bối thánh thú trấn tộc xuất quan phòng biến. Bạch diện trung niên (tôn nhi) phân tích Đàm Gia và Hỗ Gia là kẻ thù nguy hiểm nhất có thể liên thủ báo thù nhân dịp này. Bên ngoài sườn núi, Hàn Lập trà trộn giữa đám tán tu Trúc Cơ Kỳ, cảm khái số tán tu Trúc Cơ tăng mạnh sau trăm năm loạn động. Tôn hộ pháp và Mạc hộ pháp Ma Diễm Môn (hai tu sĩ Kết Đan Kỳ) dẫn đệ tử bay tới dự thọ, ôm hai mỹ nữ Phó Gia làm thị thiếp. Sau vài canh giờ, quản sự Phó Gia mời tán tu vào bảo dự tiệc. Hàn Lập đi cuối đoàn, bỗng nhiên tàng hình biến mất mà đại trận lẫn đệ tử giám thị đều không phát hiện, lẻn vào đại sảnh nơi hai ba trăm tân khách hội tụ chờ lão tổ xuất hiện."},{"chuong":650,"tieuDe":"Diệt Tộc (Thượng)","tomTat":"Phó Gia lão tổ Phó Thiên Hóa đang cùng cháu trai (đại hán Kết Đan sơ kỳ) bàn chuyện ngọc giản từ Ngự Linh Tông yêu cầu dò tìm vật bí ẩn tại Nguyên Vũ Quốc, đồng thời tiết lộ chiến lược ngoại giao đa chiều của Phó Gia. Hàn Lập bất ngờ lén vào Phó Gia bảo, xuất hiện trước hai người, tuyên bố đến đòi nợ và sẽ diệt toàn tộc. Phó Gia lão tổ dùng thổ độn phù xuyên tường tẩu thoát, Hàn Lập bắn thanh quang giết chết đại hán trong nháy mắt rồi thu Túi linh thú. Hàn Lập triệu bạch hồ Ngân Nguyệt giao nhiệm vụ truy sát Phó Gia lão tổ, sau đó thả vô số tam sắc Phệ Kim Trùng ngưng thành phi kiếm ba màu, vận Đại Diễn Quyết dùng thần thức bao phủ toàn bảo, tàn sát toàn bộ tu sĩ Phó Gia nhưng bỏ qua phàm nhân. Phó Gia lão tổ thổ độn chạy trốn dưới lòng đất, bỏ mặc đệ tử, tự an ủi chỉ cần mình còn sống thì Phó Gia chưa diệt vong."},{"chuong":651,"tieuDe":"Diệt Tộc (Hạ)","tomTat":"Phó Gia lão tổ thổ độn chạy trốn ra ngoài phạm vi Phó Gia bảo nhưng bị Ngân Nguyệt chặn đường, dùng khói hương phấn hồng làm hôn mê rồi chặt đầu giết chết. Trong đại sảnh, lão già lam bào (đường đệ Phó Gia lão tổ, tu sĩ Kết Đan thứ ba) cố trấn an tân khách, phái đệ tử ra xem nhưng đệ tử lập tức bị giết. Lão già lam bào cùng hai hộ pháp Kết Đan Kỳ Ma Diễm Môn tiến ra cửa đại sảnh, bị đạo cầu vồng dài hơn mười trượng bay vào xoay quanh phóng thanh mang, cả ba bị tứ phân ngũ liệt, hơn mười tu sĩ Phó Gia khác cũng bị chặt đầu trong khoảnh khắc. Hàn Lập (không lộ diện) ra lệnh cảnh cáo hơn trăm tân khách trong đại sảnh: trong vòng một canh giờ không ai được rời phòng, ai ra thì giết. Trong thời gian đó tiếng kêu thảm thiết liên tục vang lên rồi dứt hẳn, toàn bộ tu sĩ Phó Gia bị tận diệt không ai có lực hoàn thủ. Sau đúng một canh giờ, một tu sĩ Kết Đan đánh bạo ra trước bình yên vô sự, các tân khách khác mới dám đi ra."},{"chuong":652,"tieuDe":"Cựu Nhân","tomTat":"Phó Gia bảo trống trơn sau khi bị diệt tộc, trực hệ tiêu diệt hoàn toàn, chỉ phàm nhân và đệ tử cấp thấp bên ngoài bảo sống sót. Tin diệt tộc Phó Gia lan khắp tu tiên giới Nguyên Vũ Quốc gây chấn động, linh khoáng và phường thị bị các thế lực khác chia cắt. Ma Diễm Môn mất hai hộ pháp Kết Đan kỳ, phái người truy tìm hung thủ nhưng thực chất chỉ hư trương thanh thế. Hàn Lập không rời Nguyên Vũ Quốc, mang thủ cấp Phó Gia lão tổ bay tới ngọn tiểu sơn vô danh — nơi ẩn cư cũ của Tân Như Âm — bái tế Tân Như Âm và Tề Vân Tiêu, coi như thay hai người báo đại cừu. Tại trúc lâu cổ xưa, Hàn Lập gặp trung niên phụ nhân là hậu nhân của Tiểu Mai, phụ nhân nhận ra Hàn Lập nhờ bức chân dung tổ mẫu để lại. Hàn Lập cảm thán cô bé Tiểu Mai năm xưa đã thành tổ mẫu, rồi dùng thần thức theo dõi phụ nhân đi lấy bức tranh, thấy tầng hai lầu các có hai bài vị mang tục danh Tề Vân Tiêu và Tân Như Âm, trong lòng buồn bã hồi tưởng."},{"chuong":653,"tieuDe":"Di Ngôn Và Tặng Vật","tomTat":"Hàn Lập mở bức tranh vẽ hình dáng bản thân do tổ mẫu phụ nhân lưu lại để nhận diện. Hắn lấy từ Túi trữ vật ra hộp gỗ chứa thủ cấp Phó Gia lão tổ, xác nhận đã diệt sạch cả nhà Phó Gia, hoàn thành lời hứa năm xưa với Tân Như Âm và Tề Vân Tiêu. Phụ nhân hậu duệ nha hoàn giao hộp ngọc chứa ngọc giản di vật do Tân Như Âm lưu lại trước khi bệnh mất, với điều kiện Hàn Lập phải diệt Phó Gia trước mới được nhận. Hàn Lập dễ dàng phá phù lục phong ấn trên ngọc giản, xem xong xác nhận nội dung trợ giúp rất nhiều rồi thu đi. Hắn từ chối thu con phụ nhân làm đệ tử, thay vào đó tặng một viên Trúc Cơ Đan cùng hai bình đan dược cho Luyện Khí Kỳ. Hàn Lập nhắc khi diệt Phó Gia cũng thuận tay giết hai tu sĩ Ma Diễm Môn, xác nhận phụ nhân giữ bí mật. Khi hắn chuẩn bị cáo từ, Ngân Nguyệt theo lệnh hóa thân tiểu hồ đánh bất tỉnh phụ nhân, rồi trêu đùa hỏi chủ nhân vì sao ra tay."},{"chuong":654,"tieuDe":"Huyền Mẫu Hóa Anh Đại Pháp","tomTat":"Hàn Lập dùng Dẫn Mộng Thuật trong Huyền Âm Kinh phong ấn trí nhớ phụ nhân Tề Vân Tiêu liên quan đến mình, cải biến thành ký ức gặp cao nhân ban đan dược. Sau đó lên lầu các bái tế linh vị Tân Như Âm và Tề Vân Tiêu, hóa thủ cấp Phó Gia lão tổ thành tro bụi rồi lặng lẽ rời đi. Trên đường bay, Hàn Lập tiết lộ cho Ngân Nguyệt về Huyền Mẫu Hóa Anh Đại Pháp — bí công ma đạo ghi trong ngọc giản trận pháp thượng cổ, có thể bồi dưỡng nguyên thần thứ hai và thúc đẩy nguyên anh thứ hai đi ra, cấp bậc gần ngang Nhất Khí Hóa Tam Thanh. Ngân Nguyệt nhắc nhở cẩn thận vì bí công ma đạo thường có tính tà môn. Hàn Lập quyết định không về Khê Quốc mà đi Việt Quốc nơi xuất thân để giải trần duyên thế tục. Cách đó hai ngàn dặm, nhóm tu sĩ Ngự Linh Tông hoảng loạn vì Mộc Linh Anh thoát cấm chế sau khi Trữ sư thúc kháng mệnh tự dung hợp bị cắn trả chết. Trung niên nho sinh trong nhóm nghi ngờ người cấm chế Linh Anh và kẻ diệt Phó Gia là cùng một lão quái Nguyên Anh Kỳ. Lão già hoàng mi tiết lộ Hạm và Liễu sư thúc đang trên đường tới hỗ trợ, hai người có bí công cảm ứng Linh Anh. Cuối chương, hai nữ tử áo trắng dáng người nổi bật bước ra trước nhóm."},{"chuong":655,"tieuDe":"Cố Cư Linh Tuyền","tomTat":"Hạm Vân Chi tái xuất với tu vi Kết Đan Sơ Kỳ, giữ vị trí sư thúc Ngự Linh Tông, cùng Liễu sư muội nghe bốn đệ tử báo cáo chuyện Mộc Linh Anh chạy thoát khi đi qua Côn Mộc sơn, Linh Anh bị cấm chế và cả nhà Phó Gia bị diệt. Hàn Lập lén trở về Việt Quốc — nơi đã hoàn toàn thuộc Quỷ Linh Môn, Hoàng Phong Cốc là phân đàn. Hắn bay thẳng tới Thái Nhạc Sơn Mạch, mở lại động phủ ẩn dưới đống loạn thạch, bên trong vẫn nguyên vẹn. Hàn Lập thi triển pháp thuật thu gọn toàn bộ Linh Nhãn Chi Tuyền thành viên châu cỡ nắm tay cất vào hộp ngọc, nhưng trong quá trình linh khí trắng bắn xuyên nóc ra ngoài. Nhóm tu sĩ Quỷ Linh Môn do Vu Hồng (đệ tử Toái Hồn Chân Nhân) dẫn đầu phát hiện linh khí dị thường, tới tấn công khôi lỗi cự vượn. Hàn Lập hiển lộ tu vi Nguyên Anh Kỳ, Vu Hồng hoảng sợ xưng tên cầu hòa. Hàn Lập nảy sát ý muốn giết cả nhóm để bịt miệng, nhưng ngay lúc chuẩn bị ra tay thì một lão già trong đám tu sĩ áo đen đột nhiên nhận ra hắn, tỏ vẻ kinh ngạc."},{"chuong":656,"tieuDe":"Toái Hồn Môn Nhân","tomTat":"Hàn Lập tuyên bố lấy mạng cả nhóm tu sĩ Quỷ Linh Môn, phóng kiếm quang biến thành ba bốn mươi đạo chém chết đám tu sĩ cấp thấp, rồi hợp cự kiếm xanh tiêu diệt thủ lĩnh Vu Hồng (Kết Đan Kỳ) đang bỏ chạy. Hàn Lập sưu hồn lão già áo đen, phát hiện lão vốn là cựu đệ tử Hợp Hoan Tông, thuộc hạ Đổng Huyên Nhi, vi phạm môn quy nên đầu nhập Quỷ Linh Môn. Qua ký ức, Hàn Lập biết Đổng Huyên Nhi đã kết Kim Đan và sai nhiều đệ tử mạo hiểm vào Cửu Quốc Minh tìm hắn, nhưng không hiểu lý do và bỏ qua, rời Thái Nhạc Sơn nhắm hướng Hoàng Phong Cốc. Tại Yểm Nguyệt Tông, Toái Hồn Chân Nhân của Quỷ Linh Môn cảm ứng bổn mạng lệnh bài Lục sư đệ tắt linh quang, triệu tập ba đệ tử Kết Đan Kỳ ra lệnh truy tìm hung thủ. Tam sư huynh phân công Ngũ sư muội liên lạc Nhạc phân đàn, Khuyết sư đệ hỏi các Đàn chủ, tự mình đi tìm manh mối. Ngày hôm sau ba người tìm tới Thái Nhạc Sơn phát hiện động phủ cũ của Hàn Lập chỉ còn hố to do Linh Nhãn Chi Tuyền gây ra, Hàn Lập đã rời đi. Cuối chương, Hạm Vân Chi cùng nữ tử họ Liễu dẫn đệ tử Ngự Linh Tông xuất hiện trên rừng núi rậm rạp, chuẩn bị tiến vào Việt Quốc."},{"chuong":657,"tieuDe":"Trấn Nhỏ Ngày Xưa","tomTat":"Hàn Lập bay ngang Kính Châu, chứng kiến hơn trăm tên thổ phỉ khăn đen tấn công đoàn xe được tiêu cục Thiên Vũ hộ tống. Trong xe có trung niên nho sinh họ Hàn và đại hán Lệ Phong — hậu duệ phàm nhân của hai gia tộc Hàn và Lệ. Lệ Phong lao ra đánh bại ba thủ lĩnh thổ phỉ. Nho sinh họ Hàn kể lai lịch: tiên tổ hai nhà từng là đồng môn nội đệ tử Thất Huyền Môn ở thành Kinh Châu, nhà Hàn có vị thúc tổ thân thiết với tiên tổ nhà Lệ nhưng sau này không ai nghe nhắc tới nữa. Hàn Lập nhận ra thành trấn bên dưới chính là Thanh Ngưu Trấn nơi hắn sống thời niên thiếu, nay đã phồn hoa sau hơn trăm năm. Hắn thi triển ẩn nặc pháp thuật biến thành người thường đi bộ vào trấn, chần chừ trước tiểu sơn thôn nơi từng sống cùng đại hán Thanh Sơn rồi dừng lại trước tửu lâu Hương Xuân cũ nát — nơi từng sống hai năm với Tam thúc — hoài niệm ký ức xưa với vẻ mặt buồn bã đau thương, rồi định thần bước tới tửu lâu."},{"chuong":658,"tieuDe":"Hàn Gia Từ","tomTat":"Hàn Lập tới tửu lâu tại Kính Châu, nghe hai nho sinh trẻ bàn luận về Hàn gia quê mình đã quật khởi chưa đầy trăm năm, nay có thanh thế ngang hai nhà Phạm, Lý — trở thành tam đại thế gia Kính Châu. Hắn chủ động hỏi đường, biết Hàn gia gốc ở Ngũ Lý Câu nhưng đã dời đi hơn mười dặm. Bay về Thanh Sơn nhìn xuống quê cũ đã thay đổi hoàn toàn — nhà cỏ thành đại viện lợp ngói, đường lót đá. Hàn Lập thi triển ẩn thân thuật và độn thuật xuyên vào Hàn Gia Từ, lên tầng lầu nhìn thấy linh vị Hàn Chú, Hàn Thiết, Hàn Thiên Sinh — trong lòng đau nhói, miên man hồi ức người thân. Trung niên nho sinh họ Hàn và đại hán Lệ huynh lên lầu xem bản chép tay gia tổ, phát hiện Hàn Lập đứng trước linh vị. Đại hán cho là kẻ trộm, lao tới tấn công, nhưng Hàn Lập vẫn đứng im đưa lưng không nhúc nhích."},{"chuong":659,"tieuDe":"Tứ Thúc Tổ","tomTat":"Lệ đại hán đấm vào lưng Hàn Lập nhưng bị thanh quang phản chấn bay ngược. Trung niên nho sinh Hàn Thiên Khiếu tự xưng chủ nhân hiện tại của Hàn gia, cùng đại hán thất thanh khi nhận ra dung mạo Hàn Lập giống hệt bức họa Tứ thúc tổ được lưu giữ trong gia tộc. Hàn Thiên Khiếu nghi Hàn Lập dịch dung giả dạng tổ tiên và chất vấn sắc bén. Hàn Lập dùng thần thông linh quang nâng bản chép tay bí mật gia tộc từ hộp gỗ trên bàn thờ bay tới tay mình, khiến hai phàm nhân kinh hoàng. Đọc bản chép tay, Hàn Lập biết con gái Lệ Phi Vũ đã kết thông gia với Hàn gia, cảm thán Lệ Phi Vũ dùng Trừu Tủy Hoàn nên đan dược lưu lại không cứu được mạng. Hàn Lập nhận diện đúng các vật cũ tổ tiên trên bàn thờ gồm cung tên nhỏ của nhị ca Hàn Chú và cài tóc gỗ của gia mẫu. Hàn Thiên Khiếu hoàn toàn tin tưởng, kéo đại hán quỳ xuống hành đại lễ bái kiến Tứ thúc tổ. Hàn Lập bày tỏ chỉ muốn xem qua lần cuối rồi kết thúc mọi việc ở trần gian."},{"chuong":660,"tieuDe":"Phệ Linh Kiếm","tomTat":"Hàn Lập đứng trước hậu nhân Hàn gia (Vân Thiên Khiếu) và Lệ gia (Lệ Phong, hậu nhân đời thứ 11 của Lệ Phi Vũ) tại tông đường, cảm khái về việc Hàn gia đã trở thành đại gia tộc. Hắn dùng thần thức dò xét toàn bộ mấy trăm người Hàn gia nhưng không ai có linh căn, tiếc nuối không thể mang ai đi tu luyện. Hàn Lập khuyên hai nhà Hàn-Lệ không nên cho đệ tử bước vào tu tiên giới vì hiện tại phá môn diệt phái liên miên, sợ liên lụy gia tộc. Hắn tặng Lệ Phong bảy tám bình đan dược luyện võ cho Lệ gia, rồi triệu hơn 1000 con tam sắc Phệ Kim Trùng hợp thể luyện thành bảo kiếm ba màu, phun linh khí phong ấn tạo vỏ kiếm, đặt tên Phệ Linh Kiếm, đặt tại tông đường làm bảo vật trấn gia. Hàn Lập giao ngọc bội chứa tinh khí cho Nho sinh, dặn truyền cho lịch đại chưởng quản, kiếm chỉ dùng được ba lần và không thể mang ra khỏi tông đường. Hắn tặng riêng hai bình đan dược kéo dài tuổi thọ cho Thiên Khiếu và Lệ Phong, rồi xem bức họa cũ của bản thân thời trẻ, phụ thân và các huynh trưởng giấu trong vách tường tông đường, xúc động ngập tràn. Cuối cùng Hàn Lập bùng sáng biến mất, truyền âm dặn giữ bí mật vì có cừu nhân lợi hại, nói sẽ không bao giờ gặp lại họ nữa."},{"chuong":661,"tieuDe":"Hành Tích Bại Lộ","tomTat":"Hàn Lập rời Thanh Ngưu trấn, tâm sự rằng cha mẹ cùng huynh trưởng tiểu muội mới là người nhà thật sự, vướng bận quê hương được hóa giải. Hắn ghé Gia Nguyên Thành phát hiện Ngũ Sắc Môn sụp đổ, Tôn Nhị Cẩu cùng Tứ Bình Bang tan, Thiên Nhất Hội thay thế; hỏi thăm Mặc Ngọc Châu và Anh Trữ không có kết quả. Trên đường về Lạc Vân Tông qua Nguyên Vũ Quốc, nhờ thần thức Đại Diễn Quyết tầng 4 cường đại dị thường, Hàn Lập phát hiện một đạo linh lực bí mật quanh quẩn bên người, xác định có vài tu sĩ bám theo ngoài hai trăm dặm. Hắn đoán nguyên nhân do vụ thu thập tu sĩ Quỷ Linh Môn ở Thái Nhạc Sơn mạch, động sát tâm phi độn truy đuổi. Phía bên kia, nhóm sáu người Ngự Linh Tông gồm Hạm Vân Chi và nữ tử họ Liễu dùng bí công sư tổ truyền cảm ứng vị trí Mộc Linh Anh trên người Hàn Lập. Khi phát hiện đối phương là tu sĩ Nguyên Anh đang bay về phía mình, sáu người hoảng sợ thi triển Linh Hợp Quyết liên kết pháp lực phi độn chạy về phân đàn Quỷ Linh Môn Lam Châu. Lộ ra Mộc Linh Anh chỉ có một, Hạm Vân Chi và Liễu sư muội tuy bề ngoài sư tỷ muội nhưng ngầm cạnh tranh kịch liệt. Khi sắp bị đuổi kịp, nhóm gặp đội hơn mười tu sĩ Quỷ Linh Môn hắc y, trong đó ba Kết Đan Kỳ nhận ra Hạm Vân Chi và Liễu sư muội."},{"chuong":662,"tieuDe":"Văn Phong Nhi Đào","tomTat":"Ba đệ tử môn hạ Toái Hồn Chân Nhân (Quỷ Linh Môn) gồm tu sĩ họ Tuân, cẩm y nho sinh họ Khuyết và phụ nhân họ Lâm chặn hỏi nữ tử họ Liễu cùng Hạm Vân Chi (Ngự Linh Tông) tại Việt Quốc. Họ Tuân truy vấn về vụ Lục sư đệ cùng một số môn nhân bị sát hại tại Thái Nhạc Sơn mạch — cố địa Hoàng Phong Cốc — hài cốt không còn, sư phụ cực kỳ giận dữ. Nữ tử họ Liễu phủ nhận đi qua đó nhưng tiết lộ dò xét thấy tu sĩ khác dừng chân tại đó hơn nửa ngày. Đúng lúc căng thẳng, thần thức cường đại lạnh như băng từ tu sĩ Nguyên Anh Kỳ bao trùm xuống, khiến cả hai phe hoảng hốt chia nhau đào tẩu. Hàn Lập triển Phong Lôi Sí kết hợp Ích Tà Thần Lôi thi triển Lôi độn thần thuật, chớp mắt truy đuổi đến nơi đám tu sĩ vừa tản ra. Dùng thần thức quét toàn bộ vị trí, hắn nhắm vào tên Kết Đan Kỳ chạy xa nhất. Phụ nhân họ Lâm dù chỉ Kết Đan Sơ Kỳ nhưng nhờ Phong hỏa chi độn cổ quái phối hợp pháp bảo Phiêu Linh Đái đạt tốc độ ngang Nguyên Anh Sơ Kỳ, chạy xa bốn năm mươi dặm. Nàng đang tự đắc thì nghe tiếng lôi minh từ xa vọng lại, quay đầu nhìn."},{"chuong":663,"tieuDe":"Tung Hoành Phi Mỹ","tomTat":"Hàn Lập truy sát toàn diện nhóm ma đạo đang bỏ chạy sau trận chiến trước đó. Hắn dùng Phong Lôi Sí đuổi kịp phụ nhân Kết Đan Kỳ có độn thuật cực nhanh, bắn năm đạo kiếm khí phá vỡ vòm phong hỏa hộ thân giết chết nàng, đốt thi thể thu Túi Trữ Vật. Tiếp đó dùng Thanh Trúc Phong Vân Kiếm một kích giết tu sĩ áo đen Kết Đan Trung Kỳ đỉnh phong đang cưỡi hắc đoản nhận bỏ chạy. Dùng Phệ Kim Trùng kim sắc tiến hóa hóa kim vân nuốt sạch tu sĩ cẩm y cả người lẫn pháp bảo. Thả Phệ Kim Trùng tam sắc hóa phi kiếm phân tán diệt các tu sĩ Trúc Cơ. Hàn Lập nhận thấy Phệ Kim Trùng tiến hóa mạnh hơn nhiều nhưng ngày càng khó khống chế, thu hồi chúng lưu luyến không chịu vào túi. Hạm Vân Chi cưỡi linh cầm trắng noãn phi hành, dùng đĩa ngọc lục sắc theo dõi vị trí đồng bạn, phát hiện bốn đệ tử Trúc Cơ gần như cùng lúc bị giết, chỉ còn nàng và Liễu sư muội. Nàng cười khổ tự nhận đã quá coi thường thần thông Nguyên Anh Kỳ lão quái, hối hận không tập hợp cùng đánh."},{"chuong":664,"tieuDe":"Lục Dực Sương Công","tomTat":"Hạm Vân Chi dốc sức trốn chạy trên linh cầm bạch điểu, thi triển bí thuật tăng tốc gấp rưỡi nhưng cực hao nguyên khí. Hàn Lập dùng Phong Lôi Sí bay tới, định tấn công nhưng nhận ra Hạm Vân Chi nên thu hồi công kích, đánh ngất nàng bằng kim hồ rồi đặt lên tiểu sơn an toàn, không xâm phạm — vì nhớ tới tiểu muội dịu dàng năm xưa. Hạm Vân Chi tỉnh lại phát hiện mình bình an, dùng đĩa ngọc kiểm tra thì đoán Liễu sư muội phần nhiều đã bị giết hoặc ngoài phạm vi, rồi cưỡi linh cầm bay đi. Hàn Lập đổi hướng đuổi theo nữ tu Ngự Linh Tông khác (Liễu sư muội), nữ tu thả đám ấu trùng kỳ trùng Lục Dực Sương Công xếp hạng 18 trên bảng kỳ trùng phun băng sương chống cự nhưng vô hiệu vì Hàn Lập đã luyện Kiền Lam Băng Diễm. Hắn thu hết linh trùng, bắt sống nữ tử dán cấm chế rồi ôm bay đi — mục đích ép gỡ cấm chế nhận chủ trên linh trùng và đoạt bí thuật khống trùng Ngự Linh Tông để tăng cường khống chế Phệ Kim Trùng. Hàn Lập bay không ngừng về Khê Quốc, nhận định Thiên Đạo Minh và ma đạo đối địch kiêng kị nhau nên dù bại lộ cũng không sợ bị bắt."},{"chuong":665,"tieuDe":"Ngũ Hành Linh Anh","tomTat":"Toái Hồn Chân Nhân (Nguyên Anh Kỳ, Yểm Nguyệt Tông) hay tin đệ tử bị giết, xuất quan phát phù truyền tin truy tra nhưng Hàn Lập đã bay khỏi Việt Quốc. Hạm Vân Chi ủ rũ trở về Kỳ Linh Sơn thỉnh tội sư bá, cố ý giấu việc bị đối phương nhận ra rồi thả đi. Lão giả trong thạch thất và trung niên nam tử dùng bí thuật kiểm tra, xác nhận nàng giấu diếm nhưng tha lỗi vì nể Hạm sư đệ. Hai người tiết lộ bí mật Ngũ Hành Linh Anh: đại bí thuật thất truyền vừa khôi phục, kế hoạch dung hợp năm Linh Anh tạo năm tu sĩ có thần thông Nguyên Anh Kỳ tranh đua Hợp Hoan Tông, tiếc nuối Mộc Linh Anh bị mất vì nó có thể cho thần thông Nguyên Anh Trung Kỳ. Hơn một tháng sau, Hàn Lập về tới Vân Mộng Sơn, đưa Liễu Ngọc vào tĩnh thất, xem Mộ Phái Linh đang bế quan, bái phỏng hai trưởng lão kể chuyện giết tu sĩ Kết Đan ma đạo được khen hay. Liễu Ngọc tỉnh lại trong mật thất, gặp Ngân Nguyệt, thất thanh nhận ra mình đang ở đất Thiên Đạo Minh."},{"chuong":666,"tieuDe":"Liễu Ngọc","tomTat":"Ngân Nguyệt dẫn Liễu Ngọc đến đại sảnh Lạc Vân Tông gặp Hàn Lập rồi lui ra vì giới hạn biến thân. Hàn Lập dùng một đạo điện hồ đánh ngã Thiết Tê Thú trong quang tráo để thị uy, khiến Liễu Ngọc kinh hãi khi suy đoán hắn đã diệt Phó Gia tại Nguyên Vũ Quốc và đoạt linh thú tổ truyền. Hàn Lập thẩm vấn Liễu Ngọc, biết nàng là tu sĩ Ngự Linh Tông được phái truy tìm để đòi lại Mộc Linh Anh bị giam cầm. Liễu Ngọc tiết lộ bí thuật cảm ứng phương vị Linh Anh từ xa mà nàng cùng đồng môn sư tỷ tu luyện, giới hạn mười mấy vạn dặm. Dưới áp lực thẩm vấn, Liễu Ngọc buộc phải khai ra toàn bộ bí mật cốt lõi: Dung hợp Linh Anh đại pháp cho phép tu sĩ Kết Đan dùng năm loại Linh Anh thuộc tính khác nhau thay thế Nguyên Anh, trực tiếp đạt tu vi Nguyên Anh Kỳ. Điều kiện luyện chế Linh Anh cực khắt khe, cần trưởng lão sắp tọa hóa, xác suất cực thấp, Kim Linh Anh hiếm nhất mới luyện được hơn mười năm trước. Khuyết điểm: thọ mệnh vẫn ở mức Kết Đan, vĩnh viễn mất cơ hội kết Nguyên Anh thật, tu vi đình trệ — Hàn Lập liên tưởng đây là phương pháp tốc hành giống tu sĩ Sát Đan."},{"chuong":667,"tieuDe":"Sương Hoa Dữ Lam Diễm","tomTat":"Hàn Lập nhận định Mộc Linh Anh là linh vật luyện chế giống Đề Hồn Thú nhưng hung hãn hơn, có thể cắn nuốt nguyên anh tu sĩ. Liễu Ngọc kể nguồn gốc Lục Dực Sương Công: nàng tìm được trứng trùng cổ trong động phủ thượng cổ tu sĩ, may mắn ấp nở vài con, trưởng bối Ngự Linh Tông cho biết cần một ngàn năm mới trưởng thành. Hàn Lập đề nghị giao dịch — thúc trùng tăng cấp đổi lấy trứng trùng và Khu Trùng Thuật cao cấp của Ngự Linh Tông, nhưng Liễu Ngọc lo lắng vì tiết lộ bí thuật tông môn phạm đại tội quất hồn luyện phách. Liễu Ngọc phân tích tình thế bế tắc: biết lai lịch Hàn Lập nên khó thoát, thành tán tu thì không thể ngưng kết nguyên anh, nên chủ động xin bái Hàn Lập làm sư phụ. Hàn Lập đồng ý nhận nàng làm ký danh đệ tử với điều kiện hạ cấm thần thuật và gia nhập Lạc Vân Tông đổi tên. Sau khi Liễu Ngọc rời đi, Ngân Nguyệt hiện ra từ vách tường, Hàn Lập tiết lộ mục đích thật: cần hàn khí Lục Dực Sương Công để rút ngắn thời gian luyện hóa Kiềm Lam Băng Diễm từ khoảng hai trăm năm xuống, đồng thời hàn khí có tác dụng tăng phúc kỳ diệu. Hàn Lập trình diễn dung hợp sương hoa trắng và băng diễm xanh biếc thành một con chim lửa màu tím nhỏ bay múa linh hoạt, rồi hỏi Ngân Nguyệt có nhớ Huyền Cốt lão ma thi triển Tu La Thánh Hỏa không — ám chỉ hắn đang phát triển một dạng hỏa thuật mới."},{"chuong":668,"tieuDe":"Trùng Giáp Thuật","tomTat":"Hàn Lập bàn luận với Ngân Nguyệt về ma diễm tím vô danh phát hiện từ hàn khí rết Lục Dực Sương Công, uy lực hơn Kiền Lam Băng Diễm và tiềm năng ngang Tu La Thánh Hỏa. Hàn Lập quyết định phát triển thế lực tại Lạc Vân Tông, nhận Liễu Ngọc làm ký danh đệ tử, hạ cấm thần thuật lên nàng và ban pháp bảo đan dược. Liễu Ngọc chính thức đổi tên thành Liễu Mi, phục chế Khu Trùng Thuật vào ngọc giản và giao đám rết Lục Dực Sương Công cho Hàn Lập làm lễ bái sư. Liễu Mi gia nhập Lạc Vân Tông, khai mở động phủ tại Bạch Phượng Phong, nhận chức phó phong chủ, làm phó thủ cho nữ tử họ Tống. Hàn Lập giao tê thú cho Ngân Nguyệt dạy dỗ, dự định đem đi đổi vật quý tại đại hội giao dịch Ngu Quốc hai năm sau. Hàn Lập dùng Nghê Thường Thảo thúc sinh trưởng rết, rồi vào mật thất nghiên cứu Khu Trùng Thuật cùng Huyền Mẫu Hóa Anh Đại Pháp, luyện thành công Trùng Giáp Thuật — triệu hồi mấy ngàn con tam sắc Phệ Kim Trùng ngưng tụ thành bảo giáp chiến giáp ba màu trên thân, thanh quang lóng lánh cực kỳ chắc chắn."},{"chuong":669,"tieuDe":"Nguyên Anh Thứ Hai","tomTat":"Hàn Lập hoàn thành tu luyện Khu trùng thuật và pháp quyết Trùng Giáp Thuật, chỉ huy tam sắc Phệ Kim Trùng ngưng kết thành chiến giáp hộ thể thành công sau hơn một tháng. Tiếp đó hắn lấy ngọc giản di vật của Tân Như Âm ra nghiên cứu, mất hơn nửa năm hiểu được hơn phân nửa công pháp Huyền Mẫu Hóa Anh Đại Pháp — thần thông nghịch thiên do tu sĩ ma đạo thượng cổ sáng tạo, cho phép tạo nguyên anh thứ hai độc lập và hóa thân tự chủ cách xa ngàn dặm, vượt trội hoàn toàn so với phân thân Khúc Hồn trước kia. Tuy nhiên công pháp có hạn chế lớn: phải xâm chiếm nguyên anh tu sĩ khác, nguy cơ hóa thân phản khách vi chủ, cần dùng bí thuật Quy Nhất Quyết định kỳ để đồng hóa nguyên thần. Hàn Lập lấy hộp ngọc giam Mộc Linh Anh, nhận định tám chín phần có thể dùng nó làm nguyên anh thứ hai nhờ bản chất giống nguyên anh, nhưng lo ngại quá trình đồng hóa phải chia thần niệm ảnh hưởng thần trí nên chần chừ chưa quyết định."},{"chuong":670,"tieuDe":"Giao Dịch Hội","tomTat":"Hàn Lập cất hộp ngọc liên quan Huyễn Mẫu Hóa Anh Đại Pháp, lấy ngọc giản xanh nghiên cứu khẩu quyết, đắn đo rồi quyết tâm bế quan chìm vào pháp quyết, tiến vào cảnh giới vong ngã suốt một năm. Ngân Nguyệt cũng đang tiềm tu ở thạch thất gần đó. Trình trưởng lão và Lữ trưởng lão Lạc Vân Tông đến thăm động phủ Hàn Lập, dùng Truyền tín phù liên lạc. Trình trưởng lão thổ lộ thương thế nguyên khí hao tổn không bù đắp được, nhiều lắm chỉ sống thêm sáu bảy chục năm, tiết lộ đã phái đệ tử vào Việt quốc tra lai lịch Hàn Lập, xác nhận hắn là cựu đệ tử Trúc Cơ Kỳ Hoàng Phong Cốc, từng bị Lệnh Hồ lão quái làm vật hy sinh. Trình trưởng lão đánh giá Hàn Lập không có mục đích xấu, dự định tại Giao dịch hội lựa chọn cao thủ môn nội bồi dưỡng cho Hàn Lập để gắn bó hắn với tông môn. Giao dịch hội sắp mở tại tổng đàn liên minh chín nước phía bắc Thiên Nam đế quốc, liên minh đã kích hoạt Thượng Nguyên Diệt Quang trận, phòng đấu giá bắt đầu tiếp nhận tài liệu. Cuối chương, ba tu sĩ lạ mặt — hai nam một nữ — bay đến gần thành, danh tính chưa rõ."},{"chuong":671,"tieuDe":"Nam Lũng Hầu","tomTat":"Hàn Lập cùng Lữ Lạc và thị thiếp Mộ Phái Linh từ Khê Quốc vượt đường dài đến phụ cận Thiên Thành để dự Thiên Nam đệ nhất Giao dịch hội, Trình trưởng lão ở lại tọa trấn Lạc Vân Tông. Trên đường đi, hai tu sĩ Nguyên Anh Kỳ không che giấu tu vi khiến tu sĩ khắp nơi sợ hãi bỏ chạy. Lữ Lạc kể lịch sử Giao dịch hội: trước do Chính tà lần lượt tổ chức tại Thiên La Đế Quốc và Phong Đô Đế Quốc, sau Cửu Quốc Minh giành quyền tổ chức tại Thiên Thành. Hàn Lập nhắc trận chiến năm xưa khi Thiên Quốc thành dùng Thượng Nguyên Diệt Quang Trận tiêu diệt toàn bộ liên quân tu sĩ. Lữ Lạc nhận ra Hàn Lập có biến hóa sau bế quan, Hàn Lập thừa nhận vừa tu luyện bộ công pháp mới nhưng chưa đại thành rồi khéo léo chuyển đề tài. Lữ Lạc tiết lộ Ngân Lăng Quyết có hai loại bảo hộ tính mạng. Hàn Lập nhờ thần thức cường đại cảm ứng được đội ngũ Nam Lũng Hầu — lão quái vật Nguyên Anh Kỳ tính tình quái dị, xuất hiện với đoàn tùy tùng vương giả gồm binh lính kim giáp, xe kéo bởi Thanh Lân Phi Giáp và phượng hoàng, cung nữ bạch hạc. Lữ Lạc dặn Hàn Lập cẩn thận rồi chủ động chào hỏi xưng danh đồ đệ Mộc Ly Thượng Nhân. Nam Lũng Hầu nhận ra Lữ Lạc, tiếc nuối Mộc Ly đã qua đời, cuối cùng hỏi lai lịch Hàn Lập."},{"chuong":672,"tieuDe":"Cường Hành Giao Dịch","tomTat":"Lữ Lạc giới thiệu Hàn Lập và Mộ Phái Linh với Nam Lũng Hầu, tu sĩ Nguyên Anh Trung Kỳ tính cách cổ quái phong lưu, ngồi trên xe vàng cùng hơn mười thị thiếp. Nam Lũng Hầu phát hiện thần thức Hàn Lập mạnh bất thường so với tu sĩ mới kết anh, bèn dùng quy tắc Cường hành giao dịch ép Hàn Lập: hoặc đổi Mộ Phái Linh lấy hai thị thiếp của mình, hoặc so đấu thần thức. Lữ Lạc giải thích quy tắc này nhằm vào tu sĩ Nguyên Anh Kỳ, cách thành ngàn dặm có thể ép giao dịch bằng tu vi, chỉ được gây thương không được giết. Mộ Phái Linh vô cùng hoảng sợ hối hận, sợ bị đối xử như hàng hóa. Hàn Lập bình tĩnh đồng ý tỷ thí nhưng đặt điều kiện nếu thắng muốn biết lý do thật sự của cuộc tỷ thí. Nam Lũng Hầu thừa nhận có nguyên nhân sâu xa, chỉ tiết lộ nếu thần thức Hàn Lập đủ mạnh. Hai người bay lên không trung đối mặt chuẩn bị so đấu, Nam Lũng Hầu khinh thường khoảng cách tu vi giữa Sơ Kỳ và Trung Kỳ."},{"chuong":673,"tieuDe":"Thần Thức Biến Hóa","tomTat":"Hàn Lập và Nam Lũng Hầu tỷ thí thần thức, hai luồng thần thức va chạm tạo cuồng phong dữ dội quét bốn phương. Hàn Lập thi triển thần thức hóa hình — thần thông lý thuyết chỉ tu sĩ Nguyên Anh Trung Kỳ mới nắm giữ, khiến Lữ Lạc kinh ngạc. Nam Lũng Hầu dùng bảy thành công lực mà Hàn Lập tiếp nhận dễ dàng, kết quả ngang tay. Dư ba tỷ thí phá vỡ kim quang tấm chắn của đoàn hộ tống, không ít thị nữ thất khiếu chảy máu; Lữ Lạc dựng vòng bảo hộ che Mộ Phái Linh. Sau tỷ thí, Nam Lũng Hầu tiết lộ mục đích thật là kiểm tra thần thức Hàn Lập, truyền mật ngữ và trao ngọc giản chứa bản đồ, mời Hàn Lập ngày thứ tư giao dịch hội đến tụ hội cùng vài đạo hữu khác để chia sẻ chuyện vô cùng tốt. Mộ Phái Linh chứng kiến trận đấu, trong lòng gợn sóng, cảm thấy ở bên Hàn Lập có cảm giác ấm áp. Lữ Lạc vui mừng, lớp ngăn cách cuối cùng với Hàn Lập biến mất hoàn toàn. Cả nhóm quyết định nhanh chóng đến Thiên Thành."},{"chuong":674,"tieuDe":"Gặp Lại Đồng Tử","tomTat":"Hàn Lập cùng Lữ Lạc và Mộ Phái Linh đứng trên sườn núi nhìn xuống Điền Thiên Thành — thạch thành cự đại do Cửu Quốc Minh xây dựng, xếp top năm thành lớn nhất Thiên Nam. Ba người che tu vi xuống Trúc Cơ Kỳ, đi bộ qua cửa thành mà không bị tu sĩ chấp pháp phát hiện. Lữ Lạc dẫn đường đến khu lầu các dành riêng tu sĩ Nguyên Anh, được bảo vệ bằng bạch sắc quang mạc cấm chế. Hàn Lập phá cấm chế nhẹ nhàng bằng thanh quang, ôm Mộ Phái Linh bay vào, khiến Lữ Lạc thoáng kinh ngạc trước thực lực. Hỏa Long Đồng Tử xuất hiện từ tiểu lâu phụ cận, nhờ trí nhớ siêu cường nhận ra Hàn Lập từ Thí Kiếm Đại Hội hơn hai mươi năm trước, cả kinh khi biết Hàn Lập nay đã Nguyên Anh và là tân trưởng lão Lạc Vân Tông. Hắn mời Hàn Lập và Lữ Lạc tham gia Giao hoán hội nhỏ dành tu sĩ Nguyên Anh tại Tinh Long Các, do Thiên Tinh Chân Nhân tổ chức vì đang cấp bách tìm đồ vật trân quý. Hàn Lập dặn Mộ Phái Linh ở lại, rồi ba người cùng đến Tinh Long Các — lầu các ba tầng trắng noãn như ngọc."},{"chuong":675,"tieuDe":"Nguyên Anh Tụ","tomTat":"Hỏa Long Đồng Tử dẫn Hàn Lập và Lữ Lạc đến một lầu các bí mật tại Điền Thiên Thành, bên ngoài phủ huyễn thuật trông như tửu lâu bình thường. Bước vào bên trong, cảnh huyễn thuật tan biến, lộ ra Thiên Tinh Chân Nhân — người tổ chức Giao hoán hội — đang ngồi chờ. Hàn Lập tự giới thiệu là tu sĩ Lạc Vân Tông mới tiến cấp Nguyên Anh, được Thiên Tinh Chân Nhân khen ngợi. Thiên Tinh phát mặt nạ ô linh cho Hàn Lập và Lữ Lạc để che giấu thân phận, Hỏa Long Đồng Tử từ chối vì vóc người quá đặc biệt. Ba người lên tầng hai, nơi đã có hơn hai mươi tu sĩ Nguyên Anh kỳ tụ tập, trong đó có hai vị Nguyên Anh Trung Kỳ ngồi cô lập. Lữ Lạc truyền âm cảnh báo Hàn Lập về Phì Xá song ma thuộc Hợp Hoan Tông, hai người liên thủ bằng song tu bí thuật có thể chống lại Nguyên Anh Trung Kỳ. Thiên Tinh Chân Nhân là người cuối cùng lên tầng hai và tuyên bố Giao hoán hội chính thức bắt đầu."},{"chuong":676,"tieuDe":"Xích Tinh Chi","tomTat":"Tại hội trao đổi tu sĩ Nguyên Anh do Thiên Tinh Chân Nhân chủ trì, cẩm bào tu sĩ mở đầu bằng việc trưng ra Xích tinh chi ba ngàn năm — linh chi thuộc loại Băng hỏa tinh chi, toàn thân hỏa hồng, chỉ sinh trưởng quanh dung nham — với giá mười vạn linh thạch hoặc tài liệu thổ thuộc tính cùng cấp. Hỏa Long Đồng Tử tu luyện hỏa công pháp rất muốn nhưng không có tài liệu phù hợp. Hàn Lập nhận thấy giá thấp hơn dự đoán, truyền âm đề nghị đổi bằng yêu đan thổ thuộc tính, đưa ra một khỏa thất cấp yêu đan và giao dịch thành công. Lữ Lạc cùng Hỏa Long Đồng Tử kinh ngạc truyền âm chúc mừng, nhiều tu sĩ Nguyên Anh bắt đầu đánh giá lại Hàn Lập. Tiếp theo, nữ tu sĩ áo xanh nhạt tinh thông luyện khí thuật giới thiệu Khốn Tiên Hoàn — pháp bảo do nàng tự luyện chế bằng kim tinh, kiêm công thủ, chưa nhận chủ — biểu diễn tinh hoàn biến lớn thành một trượng với ngân bạch sắc phù văn tản linh khí kinh người."},{"chuong":677,"tieuDe":"Trụy Ma Cốc","tomTat":"Trao đổi hội Nguyên Anh tiếp tục tại Điền Thiên Thành. Phụ nhân đem Khốn Tiên Hoàn chưa nhận chủ đổi thành công lấy đan dược xúc tiến tu vi. Hỏa Long Đồng Tử muốn đổi tam sắc kỳ hoa lấy Độc Phù Mộc nhưng thất bại, Lữ Lạc dùng linh thảo trấp dịch đổi được hỏa hồng tiểu kiếm. Hàn Lập đem yêu đan cấp sáu và linh thảo ngàn năm ra tìm Canh tinh nhưng không ai đáp lại, tinh ý phát hiện Thiên Tinh Chân Nhân ánh mắt lộ tia chần chờ khi nghe nhắc Canh tinh, phán đoán đối phương biết tin tức nhưng trầm ổn chờ thời cơ. Chương giới thiệu Trụy Ma Cốc — đệ nhất hung địa Thiên Nam, chiến trường thượng cổ nơi ma tu chém giết, không gian xé rách, gần vạn năm không ai sống sót, pháp bảo vô số lạc lại bên trong. Thiên Tinh Chân Nhân đưa ra bảy tám khôi lỗi thú trình độ Kết Đan Sơ Kỳ tìm được ở cổ di chỉ để trao đổi, không phải loại trong chân kinh Thiên Trúc Giáo, khiến Hàn Lập kinh ngạc. Lão Cúc Hợp Hoan Tông hỏi đùa chuyện cải tu Khôi Lỗi Thuật, Thiên Tinh Chân Nhân giải thích chỉ tìm được chứ không cải tu, đồng thời hứa sẽ tổ chức trao đổi hội quy mô lớn hơn."},{"chuong":678,"tieuDe":"Hồn Thạch","tomTat":"Tại buổi trao đổi hội trong Tinh Long Các, Thiên Tinh Chân Nhân đưa ra đám khôi lỗi thú do thượng cổ tu sĩ chế tạo và tuyên bố muốn dùng chúng đổi lấy một loại tinh thạch gọi là Hồn Thạch, đồng thời trưng ra viên mẫu xanh ngọc phát ba động âm hàn kỳ lạ. Hàn Lập sắc mặt đại biến khi nhận ra Hồn Thạch chính là Âm minh thú tinh mà hắn từng thu được, chỉ khác cách gọi thượng cổ, đồng thời liên tưởng rằng khôi lỗi trong Hư Thiên Điện đều ngậm loại thạch này nên suy đoán Thiên Tinh Chân Nhân có mưu đồ sâu xa. Hàn Lập đưa ra viên Hồn Thạch cỡ trứng gà lớn hơn viên mẫu rất nhiều, mặc cả đổi lấy toàn bộ sáu con khôi lỗi còn lại; ban đầu Thiên Tinh Chân Nhân chỉ chịu hai con, nhưng Hàn Lập ám chỉ biết rõ giá trị thật của Hồn Thạch đối với lão nên buộc lão phải đồng ý, và lúc cúi đầu thu khôi lỗi còn truyền âm bí mật khiến lão đạo lộ tia kinh hãi. Sau khi trao đổi hội kết thúc, ba người rời Tinh Long Các; Hỏa Long Đồng Tử cáo từ vì có ước hẹn khác, Lữ Lạc tiết lộ Đồng Tử họ Lam hồi nhỏ ăn nhầm dị thảo nên giữ dáng trẻ con, là trưởng lão Cổ Kiếm Môn duy nhất thân quen với Lạc Vân Tông. Lữ Lạc cũng tách ra đi phòng đấu giá, Hàn Lập một mình đến phường thị phía tây Thành Điền Thiên mua nguyên liệu chế giấy phù và mực cao cấp để chuẩn bị luyện Hàng Linh Phù, một loại mật phù ngũ hành uy lực cực lớn ghi trên cốt phiến. Tuy nhiên bút chế phù đỉnh cấp trên phường thị chỉ đủ dùng cho phù lục thông thường, không đáp ứng yêu cầu luyện mật phù, khiến việc tìm bút thích hợp vẫn còn bỏ ngỏ."},{"chuong":679,"tieuDe":"Tàn Phù","tomTat":"Hàn Lập dạo phố Thành Điền Thiên tìm bút chế phù đỉnh cấp cả ngày không kết quả, chỉ cửa hàng khổng lồ mới có khả năng bán. Trong lúc đi, hắn suy tư về pháp thuật cao cấp — bản thân sau khi ngưng tụ Nguyên Anh đã lĩnh ngộ ba bốn loại nhưng tốc độ thi triển quá chậm, không dùng được trong đấu pháp, nhớ tới pháp sĩ Mạc Lan đã đột phá giới hạn này. Khi trời tối, Hàn Lập nghe tiếng tranh chấp liên quan tới Lạc Vân Tông và nhận ra Tôn Hỏa, đệ tử Hỏa Vân Phong mười năm không gặp, đang bị chưởng quỹ tiệm tạp hóa đòi ba trăm linh thạch bồi thường vì phá hư Hỏa vân phù. Tôn Hỏa hết linh thạch, muốn để lệnh bài làm tin bị từ chối, đành lấy phù lục cấp thấp ra trả. Trong đám phù, Tôn Hỏa bất ngờ phát hiện một tờ phù lục màu vàng tàn phá gần nửa, biến sắc giữ lại không chịu giao. Hàn Lập tự nhận mình là tam đại trưởng lão Lạc Vân Tông nên can thiệp, xuất hiện giữ lại đám phù, thả linh áp Nguyên Anh Kỳ đè xuống khiến tu sĩ tu vi thấp nửa quỳ, hai tu sĩ Kết Đan đi ngang dao động, một người thất thanh nhận ra đây là tu sĩ Nguyên Anh Kỳ."},{"chuong":680,"tieuDe":"Thệ Ngôn Dữ Tuyển Trạch","tomTat":"Hàn Lập dùng linh áp Nguyên Anh Kỳ trấn áp chưởng quỹ tiệm tạp hóa cùng hai tiểu nhị vì dám bán Hỏa vân phù hàng thường rồi chê bai Lạc Vân Tông. Chấp pháp sử Vũ Phỉ thuộc Cửu Quốc Minh bay đến xử lý, chưởng quỹ thừa nhận lừa đảo và bị phạt nặng. Hàn Lập dùng thổ độn thuật đưa Tôn Hỏa tới một thạch ốc vắng, ghép hai nửa phù lục xác nhận hoàn toàn ăn khớp rồi thiêu hủy cả hai phiến. Tôn Hỏa khai mình là huyền tôn đời thứ bảy của Tôn Nhị Cẩu, bái Hàn Lập làm chủ nhân. Hàn Lập nhắc lại lời thề năm xưa của Tôn Nhị Cẩu nhưng thừa nhận Tôn gia chưa từng chính thức làm nô bộc vì mình vắng mặt, rồi đưa ra hai lựa chọn: nhận đan dược pháp khí rồi cắt đứt quan hệ, hoặc kế thừa lời thề bị hạ cấm chế nhưng được chỉ điểm tu luyện có hy vọng kết đan. Hàn Lập bảo Tôn Hỏa suy nghĩ kỹ đợi sau hội giao dịch mới trả lời. Tôn Hỏa trầm ngâm hơn nửa ngày rồi thở dài rời đi, Hàn Lập trở về lầu các nhìn màn đêm với vẻ mặt cổ quái."},{"chuong":681,"tieuDe":"Hồn Thạch Và Thượng Cổ Khôi Lỗi Thuật","tomTat":"Hàn Lập trở về lầu các, tặng Mộ Phái Linh một chiếc bích lam ngọc bội tương xứng tâm linh có công năng phòng hộ và cảm ứng ngàn dặm, tự giữ chiếc còn lại. Ban đêm, hắn đến Tinh Long Các bái phỏng Thiên Tinh Chân Nhân theo ước hẹn truyền âm từ ban ngày, tặng không một viên hồn thạch tỏa âm khí xanh lục để đổi thông tin. Thiên Tinh Chân Nhân tiết lộ Canh tinh có thể xuất hiện trong kỳ đấu giá sắp tới, chủ nhân là tu sĩ Nguyên Anh Kỳ Cửu Quốc Minh đang ở núi nhỏ phía tây, nhưng cảnh báo các môn phái kiếm tu sẽ quyết tranh mua. Hàn Lập chuyển sang hỏi về hồn thạch, nói thẳng hắn biết Thiên Tinh Chân Nhân đang thu thập hồn thạch để luyện khôi lỗi, hé lộ từng tìm được hài cốt khôi lỗi thú thượng cổ trong động phủ. Hắn xuất thêm hai khối hồn thạch lớn gây áp lực, hai bên thỏa thuận trao đổi. Thiên Tinh Chân Nhân xác nhận đã cùng bằng hữu phát hiện thuật luyện chế khôi lỗi thượng cổ từ di vật cổ tu sĩ, nói khôi lỗi thú uy lực lợi hại nhưng cần hồn thạch rất khó kiếm. Hàn Lập tiết lộ hồn thạch sinh ra từ Âm minh yêu thú, khiến lão đạo hưng phấn, rồi bình tĩnh hỏi lão định luyện loại khôi lỗi nào và xin xem thuật luyện chế."},{"chuong":682,"tieuDe":"Gặp Lại Nam Lũng","tomTat":"Hàn Lập đàm phán với Thiên Tinh Chân Nhân, dùng hai ba mươi khối Hồn Thạch đổi lấy bạch ngọc giản gốc ghi Thượng cổ Khôi Lỗi Thuật. Thiên Tinh tự đắc cho rằng thuật luyện chế vô dụng vì tài liệu quá hiếm, nhưng Hàn Lập biết mình có cách kiếm vạn năm thiết mộc và nhớ trong Hư Thiên Điện có hài cốt Khôi Lỗi. Thuật luyện chế ghi nhiều cấp: Khôi Lỗi cao cấp ngang Nguyên Anh Trung Kỳ và cấp thấp ngang Kết Đan Kỳ, nhưng chi phí rất lớn. Hàn Lập tham gia đấu giá Canh Tinh cho Đại Canh Kiếm Trận nhưng thất bại vì khối Canh Tinh bán với giá 76 vạn linh thạch, vượt khả năng. Sau khi mua tài liệu phụ trợ luyện Khôi Lỗi, Hàn Lập đến gặp Nam Lũng Hầu tại một căn nhà đá bình thường ở góc Điền Thiên Thành. Nam Lũng Hầu vui mừng đón tiếp, nói sẽ giới thiệu thêm vài vị đồng đạo."},{"chuong":683,"tieuDe":"Mật Hội","tomTat":"Hàn Lập theo Nam Lũng Hầu đi vào mật thất dưới lòng đất, nơi bảy tám tu sĩ (phần lớn Nguyên Anh Kỳ) đã chờ sẵn. Hắn tái ngộ kẻ thù cũ Vương Thiền — Thiếu chủ Quỷ Linh Môn, người từng hai ba lần truy sát mình năm xưa. Nhị bá của Vương Thiền là Vương Thiên Cổ (Nguyên Anh Kỳ) xin Hàn Lập bỏ qua thù cũ, nhưng ngầm dùng lời khen tiết lộ Hàn Lập chỉ mất hai trăm năm từ Trúc Cơ lên Nguyên Anh, biến hắn thành bia ngắm trước mọi người. Hàn Lập nhận ra bên cạnh Vương Thiền có Yến Như Yên — nữ tử Thiên Linh Căn Yến gia được gả cho Thiếu chủ, hai người tinh thông bí thuật liên thủ hợp nhất thần thức ngang Nguyên Anh Kỳ. Khi đối mắt một lão giả bí ẩn, Hàn Lập cảm thấy lạnh như cắt muốn vỡ tâm can. Nam Lũng Hầu chủ trì mật hội, tuyên bố tiêu chí chung là thần thức cường đại, rồi tiết lộ mục đích chuyến đi là Mạc Lan thảo nguyên — khiến phần lớn tu sĩ kinh ngạc, Hàn Lập sắc mặt thay đổi."},{"chuong":684,"tieuDe":"Thương Khôn Di Bảo","tomTat":"Nam Lũng Hầu tiết lộ mục tiêu dẫn nhóm đi vòng ngoài Mộ Lan thảo nguyên tìm động phủ bí mật của Thương Khôn Thượng Nhân — vị tán tu đệ nhất Thiên Nam năm nghìn năm trước, thần thông cao thâm khiến cả chánh ma lưỡng đạo khiếp sợ. Bạch sam lão giả tiết lộ sự thật: Thượng Nhân năm đó không bị đánh chết mà tự bạo Khôi Lỗi dùng đạo thuật thoát thân, sau liều chết xông vào Truỵ Ma Cốc sống sót trở thành đệ nhất nhân trong cốc, lấy nhiều bảo vật rồi toạ hoá tại vòng ngoài thảo nguyên. Hai người kể đã từng tìm được động phủ nhưng bên ngoài có Thái Diệu Thần Cấm — thượng cổ pháp trận thất truyền thuộc thập đại cổ cấm — công kích mấy tháng không phá nổi, cần tám tu sĩ thần thức cường đại dùng thần thức biến hoá phá giải. Vương Thiên Cổ nhận ra ngay đây là thập đại thượng cổ cấm chế, được khen am hiểu trận pháp. Hàn Lập hỏi thẳng lý do triệu tập, buộc giải thích rõ. Mọi người đều động tâm trước bảo vật, không ai rời đi. Nam Lũng Hầu đề nghị điều kiện phân chia: hai người chọn trước mỗi người một bảo vật, phần còn lại chia đều."},{"chuong":685,"tieuDe":"Hoang Địa Hung Hiểm","tomTat":"Đoàn chín tu sĩ Nguyên Anh đồng ý phương án phân chia bảo vật của Nam Lũng Hầu, phát thệ không tiết lộ tin tức và quyết định khởi hành sau hai ngày chuẩn bị mà không đợi hội giao dịch kết thúc. Hàn Lập tham gia vì Thanh Nguyên Kiếm Quyết tiến triển chậm do thiếu đan dược, coi chuyến đi Trụy Ma Cốc là cơ duyên đột phá không thể bỏ qua. Trên đường, Hàn Lập nảy sát ý muốn tìm cơ hội diệt Vương Thiền. Cùng lúc, Vương Thiên Cổ dặn vợ chồng Vương Thiền không rời xa mình, tiết lộ Huyết Linh đột phá tầng thứ bảy sẽ tương đương Nguyên Anh, đồng thời kiêng kỵ Lệnh Hồ lão tổ Hoàng Phong Cốc cũng tới đại hội. Hàn Lập dặn dò Mộ Phái Linh rồi nhờ sư huynh Lữ Lạc đưa cô về. Chín người rời Điền Thiên thành hướng nam, bay qua vùng hoang dã hàng ngàn dặm giữa Cửu Quốc Minh và Mộ Lan thảo nguyên. Bạch sam lão giả phát hiện cơn gió rất mạnh bất thường phía trước, Thai phu nhân khẳng định cơn gió tuyệt đối không tự nhiên, đoàn chuẩn bị ứng phó."},{"chuong":686,"tieuDe":"Pháp Sĩ Sơ Hiện","tomTat":"Hàn Lập dùng thần thức cường đại dò ra bão cát khổng lồ đang bay đến từ ngoài trăm dặm. Nam Lũng Hầu nhận diện đây là Phong Linh Thuật Hồng Trần Vạn Trượng của Người Mộ Lan, Vương Thiên Cổ chỉ ra rằng hơn trăm năm đình chiến đã đủ để Người Mộ Lan nghỉ dưỡng, chiến tranh mới sắp bắt đầu. Bạch sam lão giả đề xuất phương án ẩn nặc đi vòng qua bên cạnh quân tiên phong rồi phóng tới Mộ Lan hư không thảo nguyên lấy bảo khố. Trước khi hành động, cả nhóm thả Truyền tín phù cảnh báo cứ điểm Cửu Quốc Minh gần đó. Chín người thu liễm khí tức ẩn hình di chuyển, cự phong trụ rộng trăm trượng lướt qua mà không phát hiện. Tuy nhiên Hàn Lập nhận ra cảnh sắc xung quanh không thay đổi và không gặp pháp sĩ nào dù đi trong bão cát lâu, phát hiện nhóm đang bị cấm chế ám toán. Nam Lũng Hầu xác nhận đối phương đã phát hiện nhóm, không thể tránh đại chiến."},{"chuong":687,"tieuDe":"Đại Thượng Sư","tomTat":"Nhóm tu sĩ Hàn Lập hợp lực tấn công cấm chế ảo trận cát vàng do Hoàng Sa Bộ bố trí, xé rách dễ dàng và bay thoát. Hàn Lập phản ứng nhanh nhất, bay ra đầu tiên rồi dùng năng lực đặc biệt (đồng tử phát lam quang) phát hiện chỗ cát vàng bất động — nơi Tu Di Trùng thượng cổ kỳ trùng ẩn náu — mà hai Nguyên Anh Trung Kỳ không nhận ra, nhưng cố tình che giấu. Nam Lũng Hầu lấy tinh bàn dị bảo xác định phương hướng trong bão cát, dẫn cả đoàn bay đi. Vương Thiền cúi đầu không dám nhìn Hàn Lập, Yến Như Yên bình tĩnh lắc đầu. Sau khi nhóm rời đi, Tu Di Trùng lộ diện cùng ba pháp sĩ Mộ Lan Hoàng Sa Bộ: Đại Thượng Sư (bích lục quang), pháp sĩ bạch quang và pháp sĩ điện hồ. Đại Thượng Sư cấm dùng trấn tộc thánh khí Ma Trần Phiên (36 can), hé lộ Hoàng Sa Bộ dẫn đầu liên quân mười đại bộ tộc nhờ thánh khí này. Hắn nghi Mục Thượng Sư Thiên Phong Bộ mượn cơ trả thù, và đánh giá Hàn Lập không tầm thường vì phát hiện được Tu Di Trùng."},{"chuong":688,"tieuDe":"Ngự Phong Xa","tomTat":"Khi rời Hoàng Sa Phong Trận, Hàn Lập thi triển Minh Thanh Linh Mục nhìn xuyên bão cát, phát hiện vòng tròn bóng đen chứa mấy người có pháp lực vượt Nguyên Anh đang ẩn thân giám sát nhóm, hắn giả vờ không biết. Nhóm bay nửa ngày thấy vùng đất xanh biếc thì Ngự Phong Xa của pháp sĩ Mộ Lan chở năm Nguyên Anh Kỳ truy đuổi tới. Nam Lũng Hầu quyết định tản ra, phát ngọc giản hẹn ba ngày sau tập hợp, mỗi người thi triển bí thuật riêng bay đi các hướng. Bốn pháp sĩ xuống xe chia bốn hướng đuổi theo nhóm, riêng Ngự Phong Xa quay sang nhắm Hàn Lập. Hắn khoác huyết sắc phi phong hóa huyết quang tăng tốc ba phần giằng co với Ngự Phong Xa, hai luồng sáng cách hơn mười dặm bay sâu vào Mộ Lan thảo nguyên chưa phân thắng bại."},{"chuong":689,"tieuDe":"Sơ Thí Thần Thông","tomTat":"Hàn Lập dùng áo choàng đỏ sậm phi độn hết tốc lực nhưng vẫn không bỏ được Ngự Phong Xa truy đuổi phía sau. Nhận ra mình tu thành Nguyên Anh nhưng chưa từng thực chiến với tu sĩ đồng cấp, hắn quyết định dừng lại nghênh chiến để thử sức. Hàn Lập triển khai 72 phi kiếm Thanh Trúc Phong Vân Kiếm nhất hóa ba thành hơn 200 kiếm quang bày kiếm trận, thả Tam Sắc Phệ Kim Trùng lần đầu kết thành trùng giáp bọc toàn thân phòng hộ, tế Kinh Long chung phóng sóng âm bạc tấn công. Pháp sĩ Mộ Lan trên xe bay xuống lộ diện — Mục lão giả, Nguyên Anh Sơ Kỳ đỉnh cấp, hai má hình xăm xanh, tự xưng thượng sư. Mục lão giả dùng bảo châu lam tạo quang mạc chặn kiếm quang, phun lam ti tằm hóa cự mãng đấu kiếm trận, rồi đề nghị Hàn Lập dừng tay trả lời câu hỏi nhưng bị cự tuyệt. Hàn Lập hợp nhất kiếm quang thành cự kiếm hai ba mươi trượng chém đứt cự mãng lam rồi chém thẳng vào Mục lão giả. Mục lão giả dùng bảo châu phóng lam sắc tế ti kết quang võng chống đỡ, trận đấu chưa phân thắng bại."},{"chuong":690,"tieuDe":"Băng Tinh Cùng Hắc Phong","tomTat":"Cự kiếm thanh sắc của Hàn Lập bị Bích lục ti võng của Mạc lão giả vây chặt không phá nổi. Mạc lão giả thi triển Băng Tinh Thuật — linh thuật pháp sĩ phóng vô số băng tinh huyền tinh hàn khí, nhưng Hàn Lập xuất hoa lam cổ bảo hóa bạch khí hút thu băng tinh, đồng thời thả Phệ Kim Trùng tạo trùng tráo phòng ngự tự phục hồi, hóa giải hoàn toàn. Hàn Lập dùng Kinh Long chung phát âm ba chấn Mạc lão giả suýt rơi, phá vỡ ti võng giải phóng cự kiếm truy kích. Mạc lão giả kiêng dè hoa lam cổ bảo phát băng hàn linh lực kinh người, hỏi nguồn gốc nhưng Hàn Lập đề nghị đổi thông tin linh thuật, bị từ chối. Lão giả xuất pháp bảo hắc phong — tòa tiểu sơn đen phóng to gần trăm trượng đè xuống đầu Hàn Lập, cự kiếm chém vết dài bảy tám trượng nhưng hắc phong tự phục hồi cực nhanh. Hàn Lập kích hoạt Phong Lôi Sí thuấn di hơn mười trượng thoát nạn. Mạc lão giả kinh sợ nhận ra đối phương không phải Nguyên Anh Kỳ bình thường, khu sử hắc phong tổn hao pháp lực lớn không dám lạm dụng."},{"chuong":691,"tieuDe":"Đóng Băng","tomTat":"Hàn Lập quyết tâm giết Mục lão giả để đoạt ngọn hắc sơn cổ bảo và Ngự Phong Xa, tự tin Kiền Lam Băng Diễm khắc chế hoàn toàn băng thuộc tính đối phương. Hắn triển khai tổng lực: cự kiếm hóa mấy trăm kiếm khí phối hợp ngân chung vây công, dùng Phong Lôi Sí lôi độn tiếp cận rồi phóng Thanh Minh Châm, nhưng phù bảo bị Tinh Băng Thuẫn hóa giải. Mục lão giả dùng hắc sơn cổ bảo phóng quang hoa áp chế đại bộ phận uy lực Hàn Lập, nhận ra Kiền Lam Băng Diễm nguy hiểm liền triệu Ngự Phong Xa bỏ chạy. Hàn Lập phục kích ngay bên trong xe, đâm Kiền Lam Băng Diễm trực tiếp vào người lão già, lam băng từ năm ngón tay phóng ra đóng băng toàn thân đối phương. Mục lão giả điều đan dương chi hỏa chống cự thất bại, trong tuyệt vọng phá thiên linh cái cho Nguyên Anh thoát ra, hóa lam mang dùng Lôi Độn Chi Thuật chạy trốn thành công, thu bảo châu theo rồi biến mất ở chân trời với ánh mắt oán độc. Hàn Lập không đuổi theo vì nhận ra Phong Lôi Sí thua Lôi Độn thuần túy về truy đuổi, đấm vỡ thân xác đóng băng của lão già hóa lam tinh quang tan thành cát bụi."},{"chuong":692,"tieuDe":"Tái Tụ","tomTat":"Hàn Lập thu Túi Trữ Vật màu bạc của lão giả họ Mục nhưng thất vọng vì bên trong chỉ có Linh Thạch Bậc Trung và nguyên liệu tầm thường, không có ngọc giản pháp quyết nào. Hắn thu được cổ bảo vô chủ Thiên Trọng Phong — ngọn núi đen thu nhỏ, dưới đáy khắc ba chữ vàng kim — cùng Ngự Phong Xa rồi bay đến điểm hẹn. Tại đó, Nam Lũng Hầu cùng bạch sam lão giả, lão phụ nhân và hán tử mặt đen đã chờ sẵn, vui mừng đón Hàn Lập nhưng ngầm kinh ngạc vì hắn thoát được Ngự Phong Xa truy đuổi. Nhóm người bàn luận tình hình chiến tranh Mộ Lan thảo nguyên: Thiên Đạo Minh sẽ phái người tham chiến, Lạc Vân Tông có thể phải cử trưởng lão Nguyên Anh Kỳ trợ chiến, và Mộ Lan nhân có thể đã có thêm đại bộ lạc tăng viện. Vương Thiên Cổ cùng hai vãn bối (gồm Vương Thiền) đến sau, giải thích thoát truy đuổi bằng bí pháp độn thuật liên thủ của Quỷ Linh Môn. Cuối chương, Vưu đạo hữu — thành viên cuối cùng — xuất hiện trong trạng thái cuống quít bị hai đạo ánh sáng đuổi sát, khiến Nam Lũng Hầu thần sắc âm trầm."},{"chuong":693,"tieuDe":"Kinh Sợ Thối Lui","tomTat":"Nam Lũng Hầu dẫn cả nhóm bay lên nghênh đón tu sĩ họ Vưu đang bị thương chạy trốn sau khi giao đấu và bị hai pháp sĩ Mộ Lan truy đuổi hai ngày hai đêm. Hai pháp sĩ Nguyên Anh Sơ Kỳ — ma quan pháp sĩ và áo lục pháp sĩ — chặn đường, tuyên bố chỉ cần trì hoãn nửa ngày thì nhóm sẽ hết cơ hội rời đi. Nam Lũng Hầu nổi giận, Bạch sam lão giả phun ngân sắc bảo vật, cả nhóm chuẩn bị giao chiến. Đúng lúc sắp động thủ, một Truyền Âm Phù bay đến khiến ma quan pháp sĩ kinh hô, hai pháp sĩ nhìn chằm chằm Hàn Lập rồi chần chừ rút lui — Hàn Lập đoán nội dung liên quan đến lão giả họ Mục bị mình đánh trọng thương. Vương Thiên Cổ dò hỏi Hàn Lập nhưng bị gạt đi. Nhóm bay về hướng tây đến một thạch sơn trụi lủi cao hơn trăm trượng ẩn chứa động phủ thượng nhân, Nam Lũng Hầu và Bạch sam lão giả dùng hai lá tiểu kỳ phá cấm chế ngoại tầng, mặt đất rung chuyển dữ dội khiến Hàn Lập cả kinh."},{"chuong":694,"tieuDe":"Lôi Hỏa Trùy","tomTat":"Nam Lũng Hầu và bạch sam lão giả dùng chú ngữ bửa đôi tiểu thạch sơn, lộ ra bậc thang đá dẫn xuống lòng đất. Bạch sam lão giả hưng phấn dẫn đầu đi vào, Nam Lũng Hầu chủ động đi sau thể hiện nhún nhường, khiến Hàn Lập nhận ra vị thế thực sự của lão giả này cao hơn dự đoán. Đoàn người đi sâu hơn trăm trượng vào đại sảnh bốn vách tường lam quang trong suốt, thần thức mọi người bị bắn ngược khi dò — Hàn Lập nhận định đây là Thái Diệu Thần Cấm. Đột nhiên lối vào biến mất, cấm chế bên ngoài tự khởi động khép khe núi, đại sảnh biến thành không gian kín. Nam Lũng Hầu trấn định giải thích cần đợi ba ngày đến lúc cấm chế yếu nhất. Thai phu nhân đề nghị dùng dị bảo phá cấm chế để đổi quyền ưu tiên chọn bảo vật, được đồng ý. Phụ nhân rút Lôi Hỏa Trùy — Cổ Bảo song thuộc tính lôi hỏa — ra thi triển, hỏa lãng cực nóng tràn sảnh khiến Vương Thiền và Yến Như Yên không chịu nổi. Tốc độ bay tự thân của bảo vật cực nhanh, Hàn Lập đánh giá Nguyên Anh Kỳ cũng khó tránh, chỉ Phong Lôi Sí mới phòng bị được."},{"chuong":695,"tieuDe":"Ra Tay","tomTat":"Thai phu nhân dùng Cổ Bảo Lôi Hỏa Trùy tấn công Thái Diệu Thần Cấm bảo vệ tinh tường lam sắc. Lần đầu chỉ thăm dò, tinh tường hoàn toàn vô dạng. Lần hai toàn lực kích phát, lôi điện và hỏa diễm dung hợp thành xích hồng sắc điện hồ, Lôi Hỏa Trùy xuyên được một đoạn vào tinh tường nhưng bạch sắc quang ti từ bên trong phun ra quấn chặt rồi bạo liệt hủy diệt hoàn toàn Cổ Bảo. Thai phu nhân mất bảo vật, suýt thổ huyết. Sau tấm gương đó không ai dám thử tiếp, Vương Thiên Cổ tự biết chưa từng tiếp xúc thập đại cổ cấm chế nên im lặng. Hàn Lập bất ngờ chủ động xin ra tay, bí mật dùng lam quang trong mắt quan sát sâu vào tinh tường hơn nửa khắc, rồi lấy hơn mười cái trận kỳ nhiều màu bày trước tinh tường chuẩn bị lấy trận phá trận. Yến Như Yên vô tình bắt gặp vẻ châm chọc của Hàn Lập trước đó, sinh nghi hoặc và có vẻ đang liên tưởng đến ai đó."},{"chuong":696,"tieuDe":"Phá Cấm Quyển Trục","tomTat":"Hàn Lập dùng mười mấy thanh trận kỳ bày pháp trận cổ quái trên bốn mặt tinh tường, phối hợp bích lục trận bàn ở trung tâm đại sảnh, phát bạch quang chói mắt che giấu huyền cơ. Sau nửa canh giờ bố trí, Hàn Lập hô Phá phá hủy hoàn toàn hai tầng cấm chế, tinh tường biến mất lộ ra thạch môn cao bảy tám trượng. Nam Lũng Hầu mừng rỡ tuyên bố giữ lời hứa: sau khi y và Vân đạo hữu mỗi người chọn trước một bảo vật, Hàn Lập được ưu tiên chọn tiếp. Qua thạch môn là không gian rộng lớn chứa lầu các bạch ngọc hai tầng mang tên Ngọc Ki Các. Trước lầu các có bàn thờ đen cổ kính thờ quyển trục ngân bạch, mở ra lộ bức tranh nho sinh lưng đeo trường kiếm ngửa mặt nhìn trời, nghi là chân dung Thương Khôn Thượng Nhân. Lão giả họ Vân thử đánh pháp quyết vào bức tranh nhưng không có phản ứng, quyển trục được tạm thu vào Túi Trữ Vật chờ phân chia. Đoàn người vào tầng một Ngọc Ki Các, thấy ba giá gỗ lớn bày đầy đồ vật tỏa hào quang chói mắt, tất cả kiềm chế lửa nóng trong lòng bắt đầu đánh giá bảo vật."},{"chuong":697,"tieuDe":"Chia Cắt","tomTat":"Nhóm người khám phá tầng một Hư Thiên điện, nơi chứa ba giá gỗ gồm Cổ Bảo, pháp bảo, tài liệu và đan dược. Hàn Lập chú ý bồ đoàn và chậu Âm Ngưng thảo nhưng bồ đoàn bị Bạch sam lão giả nhanh tay hơn lấy trước. Yến Như Yên bắt chuyện với Hàn Lập, đề nghị hóa giải cừu oán giữa Hàn Lập và phu quân Vương Thiên Cổ nhưng bị cự tuyệt thẳng thừng. Nam Lũng Hầu chủ trì phân chia bảo vật: chọn Cổ Bảo thì thôi pháp bảo, Hàn Lập chọn Cổ Bảo hình ống trúc chưa rõ uy lực. Vương Thiên Cổ khiêu khích hỏi tại sao Nam Lũng Hầu và Vân đạo hữu không chọn trước, ám chỉ tầng hai không có gì. Lên tầng hai — phòng ngủ Thương Khôn Thượng Nhân — Hàn Lập phát hiện tượng vàng yêu thần ba đầu sáu tay trên điện thờ giống hệt yêu thú trên Phạm Thánh Chân Phiến. Bạch sam lão giả lao tới giường hàn ngọc chụp hộp ngọc nhưng bị một nhân ảnh bắn hắc mang ngăn cản, kinh nộ chất vấn, chương kết thúc ở cao trào xung đột."},{"chuong":698,"tieuDe":"Tính Kế","tomTat":"Vương Thiên Cổ ngăn Nam Lũng Hầu và lão giả họ Vân mở ba hộp ngọc trên giường hàn ngọc, lý luận bên trong có thể chứa công pháp Thương Khôn Thượng Nhân và bí mật Trụy Ma Cốc. Thai phu nhân, tu sĩ mặt đen và tu sĩ họ Vưu lần lượt đứng về phe Vương Thiên Cổ, hình thành liên minh bốn Nguyên Anh sơ kỳ cùng hai Kết Đan hậu kỳ. Hàn Lập tuyên bố trung lập, lùi xa hai phe giữ khoảng cách. Bất ngờ lão giả họ Vân — hảo hữu kết giao hơn trăm năm của Nam Lũng Hầu — giả vờ muốn tấn công phe Vương Thiên Cổ rồi quay đầu phóng ngân luân đánh trọng thương Nam Lũng Hầu, phá hộ thể kim quang, rồi bay sang phe địch. Nam Lũng nhờ mặc Thanh Tê Giáp bên trong nên giữ mạng nhưng nội thương rất nặng. Hàn Lập định trốn qua cầu thang nhưng phát hiện Thai phu nhân đã chặn lối, vách tường bị cấm chế, nhận ra mình bị Vương Thiên Cổ định sẵn làm vật bồi táng. Nam Lũng Hầu đề nghị Hàn Lập liên thủ, cảnh báo nếu không hợp tác sẽ bị hình thần câu diệt."},{"chuong":699,"tieuDe":"Họa Thủy Đông Di","tomTat":"Nam Lũng Hầu dùng bí thuật tạm thời khống chế thương thế trên ngực, lão giả họ Vân nhận định đây chỉ là tạm thời và đề nghị phái một người cuốn lấy Hàn Lập, còn lại tập trung diệt Nam Lũng Hầu. Vương Thiên Cổ phân công tu sĩ họ Vưu canh giữ Hàn Lập, bổ sung Vương Thiền và Yến Như Yên hiệp trợ; bản thân phóng hắc quang chuẩn bị đối phó Nam Lũng Hầu. Nam Lũng Hầu bất ngờ cuốn ba hộp ngọc trên giường ngọc, ném một cái cho Hàn Lập kèm tuyên bố cho hắn nếu không cùng phe Vương Thiên Cổ, nhằm phân tán lực lượng đối phương. Hàn Lập hiểu rõ ý đồ chuyển họa nhưng vẫn thu hộp ngọc vào Túi trữ vật không do dự. Các bên rơi vào thế giằng co không ai dám ra tay trước — phe Vương Thiên Cổ sợ phản kháng liều mạng của tu sĩ Nguyên Anh Trung Kỳ sắp chết, Nam Lũng Hầu đứng yên với nét đỏ trên gò má ngày càng tươi. Hàn Lập bất ngờ chủ động phá thế: ném Cực Nhạc Thần Quang Đỉnh biến lớn bảy tám trượng chắn ngang như bức tường, dùng Phong Lôi Sí hiện thân sát bên tu sĩ họ Vưu, há miệng phun sợi tơ lửa xanh (Thanh Trúc Bách Luyện Hỏa) xuyên thủng bạch quang tráo đánh trúng người tu sĩ họ Vưu."},{"chuong":700,"tieuDe":"Tiên Thủ","tomTat":"Hàn Lập dùng Kiềm Lam Băng Diễm đánh vào cổ tu sĩ họ Vưu Nguyên Anh Sơ Kỳ, đóng băng toàn thân đối phương trong nháy mắt và đoạt hồ lô xanh. Vương Thiền hoảng sợ chạy về ép Yến Như Yên hợp lực thi triển Huyết Linh Đại Pháp, tạo huyết vụ tím che thân. Nam Lũng Hầu đề nghị liên thủ và chia thêm hộp ngọc nhưng bị Hàn Lập cười lạnh từ chối vì phân tích rủi ro quá lớn. Hàn Lập kích hoạt ngọn núi đen đè nhóm Vương Thiên Cổ tạo hỗn loạn, trong khi Nam Lũng Hầu nhân cơ hội hóa kim quang dùng bí thuật và cổ bảo hỗn chiến không rơi hạ phong. Hàn Lập thu ngọn núi đen rồi dùng Âm Ma Trảm trảm vào huyết vụ tím, gây trọng thương Vương Thiền nhưng quyết định không mạo hiểm diệt hẳn vì e ngại Vương Thiên Cổ, dùng Lôi Độn Thuật rời đi. Khi bay qua đại sảnh tầng một, Ngân Nguyệt từ một góc bắn ra trốn vào tay áo Hàn Lập, hưng phấn muốn báo cáo thu hoạch. Hàn Lập tiết lộ hậu thủ: lúc phá Thái Diệu Thần Cấm đã cố ý dùng linh quang chói mắt nhiễu loạn linh giác mọi người, mở lỗ hổng đưa Ngân Nguyệt lẻn vào bên trong thu hoạch trước, đây cũng là lý do không cần liên thủ với Nam Lũng Hầu."},{"chuong":701,"tieuDe":"Vạn Xích Nhất Tuyến","tomTat":"Hàn Lập bắn ra khỏi Ngọc Ki Các ngay khi Nam Lũng Hầu phá nát lầu các, xuất hiện vòng sáng vàng bao quanh. Nam Lũng Hầu dùng cổ bảo bát vàng tạm vây lão giả họ Vân và Vương Thiên Cổ, nhờ Hàn Lập trì hoãn truy binh bằng cách tái kích hoạt Thái Diệu Thần Cấm qua trận bàn xanh biếc. Hàn Lập khoác Trùng Giáp Thuật phòng thân, rồi dùng Phong Lôi Sí kết hợp Lôi Độn Thuật đào thoát với tốc độ vượt cả Nam Lũng Hầu. Nam Lũng Hầu bay ra ngoài thi triển bí thuật Vạn Xích Nhất Tuyến (do Thương Khôn Thượng Nhân tự tạo), biến độn quang thành tơ tằm cực nhỏ thu liễm khí tức biến mất, nhưng trả giá bằng phần lớn nguyên khí và tinh huyết, bị đánh giá sẽ mất cảnh giới Nguyên Anh Trung Kỳ vĩnh viễn. Vương Thiên Cổ, lão phụ nhân và hán tử mặt đen phá cấm chế truy ra nhưng không kịp. Lão giả họ Vân tiết lộ thân phận thực sự là Trưởng lão Quỷ Linh Môn, không phải tán tu, và tuyên bố đã sớm động tay chân lên Nam Lũng Hầu. Lão giải thích động cơ: phát hiện Nam Lũng Hầu lén kết giao Thiên Cực Môn có ý gia nhập, muốn trợ giúp chính đạo vào Trụy Ma Cốc lấy bảo, nên quyết hạ độc thủ bảo vệ lợi ích ma đạo."},{"chuong":702,"tieuDe":"Luyện Anh","tomTat":"Sau khi để Nam Lũng Hầu chạy thoát, lão giả họ Vân cùng Vương Thiên Cổ, lão phụ nhân và hán tử mặt đen bàn bạc đối sách. Lão giả họ Vân tiết lộ Nam Lũng Hầu có liên quan đến Thiên Cực Môn, mời hai tán tu gia nhập Quỷ Linh Môn nhưng đều bị từ chối. Nhóm lên kế hoạch truy sát Nam Lũng Hầu để dùng Sưu hồn thuật khai thác tin tức Trụy Ma Cốc, đồng thời tính phương án ép Hàn Lập giao bản đồ lộ tuyến hoặc tiết lộ cho toàn bộ tông môn Thiên Nam. Lão giả họ Vân thừa nhận thần thông Hàn Lập quỷ dị, đơn đả độc đấu không chắc thắng nổi. Nhóm trở lại Ngọc Ki Các, thấy Vương Thiền bị chặt đứt hai bắp đùi bởi quang phiến hắc hồng sắc của Hàn Lập, vết thương có hắc khí tà ác ngăn ghép chi. Vương Thiên Cổ trích hắc khí thu vào bình nhỏ để nghiên cứu, sau đó Yến Như Yên mới ghép chi thành công. Hán tử mặt đen thử phá lam băng nhốt tu sĩ họ Vưu bằng mảnh ngọc và chân hỏa trắng nhưng đều bị hóa giải. Nguyên Anh tu sĩ họ Vưu xuất khiếu cố phá băng bằng nguyên dương anh hỏa và ngọc bội, nhưng lam băng bùng thành lam sắc hỏa diễm nuốt trọn Nguyên Anh, luyện hóa thành bạch quang — tu sĩ họ Vưu hình thần câu diệt, không thể tái sinh."},{"chuong":703,"tieuDe":"Bảo Vật Trong Hộp","tomTat":"Hàn Lập dùng Lôi Độn Thuật rời khỏi khu vực Lạc Vân Tông, mặc huyết sắc phi phong bay về Thiên Nam. Trên đường phát hiện đoàn vài vạn phàm nhân Mộ Lan đang tiến về Thiên Nam cướp bóc tài nguyên, hắn quyết định ẩn thân trong xe ngựa trà trộn theo đoàn để tránh pháp sĩ Mộ Lan lẫn che giấu tung tích trước nhóm Vương Thiên Cổ. Hắn nghe phàm nhân Mộ Lan trò chuyện, cảm thán sự sùng bái cuồng tín của họ đối với pháp sĩ. Sau đó triệu Ngân Nguyệt kiểm kê chiến lợi phẩm: Ngân Nguyệt tiết lộ đã lén lấy ba hộp ngọc ở Cổ Bảo tầng hai nhờ độn thuật Lang Tộc kết hợp tính năng che linh khí của hộp ngọc, cộng thêm một hộp Hàn Lập đã có, tổng cộng bốn trong sáu hộp ngọc Thương Khôn Thượng Nhân nằm trong tay hắn. Hàn Lập mở hộp thứ nhất lấy ngọc giản lam nhạt, đọc xong cau mày trầm ngâm nhưng không tiết lộ nội dung. Mở hộp thứ hai lấy nhẫn đen vô quang, phán đoán bề ngoài là pháp khí bình thường nhưng tin rằng có công dụng đặc biệt. Còn hai hộp ngọc chưa mở."},{"chuong":704,"tieuDe":"Lộ Phùng Cựu Nhân","tomTat":"Hàn Lập kiểm tra hộp ngọc chiến lợi phẩm còn lại, thu được bình sứ chứa chất cay độc dị thường và Tử Vân Đấu — Cổ Bảo phòng ngự đỉnh bậc có thể che kín ngàn trượng và phóng Ngọc Dương Chân Hỏa diệt địch. Ngân Nguyệt nhận ra Tử Vân Đấu từ ký ức sót lại trước khi bị luyện hóa thành khí linh, thừa nhận hình như từng sở hữu kiện tương tự. Ngọc giản chứa công pháp Vọng Nguyệt quyết của Thương Khôn Thượng Nhân mà Hàn Lập không tu luyện được nhưng tham khảo bí thuật. Hàn Lập nấp trong xe ngựa hai ngày đêm qua mặt pháp sĩ kiểm tra, lặng lẽ rời đội ngũ Mộ Lan xuyên hoang nguyên về Thiên Nam, dùng thần thức trăm dặm né pháp sĩ, thuận lợi vào Phong Nguyên Quốc. Phát hiện Cửu Quốc Minh bị Mộ Lan đánh lén, tu sĩ tạm lui phòng thủ, đại chiến chưa bắt đầu. Bay qua núi nhỏ vô danh, thần thức cảm ứng năm Kết Đan tu sĩ liên thủ đánh pháp sĩ Nguyên Anh Sơ Kỳ hoàng bào muốn bắt sống tuyệt sắc nữ tử làm lô đỉnh. Hàn Lập nhận ra lão giả to béo dùng bạch sắc lôi hồ và cự kiếm phóng điện quang là cố nhân, vẻ mặt phức tạp. Pháp sĩ hoàng bào mất kiên nhẫn, phun ra vũ phiến tạo cuồng phong cuốn gọn cả năm tu sĩ."},{"chuong":705,"tieuDe":"Câu Linh Thổ Long","tomTat":"Pháp sĩ họ Đàm (Nguyên Anh Kỳ) dùng cuồng phong từ vũ phiến khống chế năm tu sĩ gồm Niếp Doanh và Lôi Vạn Hạc, định bắt sống Niếp Doanh. Hàn Lập từ xa bắn Thanh Nguyên kiếm khí phá tan cuồng phong giải cứu cả nhóm, chê pháp sĩ mới tiến cấp Nguyên Anh không lâu nên tu vi không đủ phát hiện hắn. Pháp sĩ họ Đàm triệu hoán hai con Câu Linh Thổ Long bằng đạn hoàn vàng, nhưng bị Hàn Lập dùng Kiềm Lam Băng Diễm đông cứng rồi kiếm khí kích nát, thu hai khỏa đạn hoàn. Hàn Lập lần đầu chính thức khu sử Phệ Kim Trùng đối địch, nhưng pháp sĩ họ Đàm nhận ra ngay loài trùng này, kinh sợ hóa hoàng hồng bỏ chạy. Hàn Lập do dự rồi buông tha vì nơi trống trải khó truy sát Nguyên Anh xuất khiếu. Hàn Lập mơ hồ nhận ra đã gặp Niếp Doanh ở đâu đó, cả hai bên không nhận ra nhau sau gần hai trăm năm. Lôi Vạn Hạc xưng danh Hoàng Phong Cốc cảm tạ, ba tu sĩ còn lại cũng bái tạ: Cự Kiếm Môn Thạch Tề Vân, Yểm Nguyệt Tông Đường Minh Hoa, Thiên Khuyết Bảo Tiễn Hoàn."},{"chuong":706,"tieuDe":"Lôi Vạn Hạc Đích Chấn Kinh","tomTat":"Hàn Lập nhận ra lão giả mập chính là Lôi Vạn Hạc — sư bá đồng môn cũ tại Hoàng Phong Cốc, và nữ tử Niếp Doanh là Niếp sư tỷ năm xưa, nay đã kết Kim Đan thành công. Hai bên nhận ra nhau, Lôi Vạn Hạc kinh ngạc tột độ vì tiểu bối Trúc Cơ kỳ ngày nào nay đã thành tu sĩ Nguyên Anh kỳ, từ chối nhận xưng hô sư bá và đổi sang gọi Hàn Lập là tiền bối. Hàn Lập lấy Ngự Phong Xa phóng to hơn mười trượng chở cả năm người bay đi thoát hiểm. Lôi Vạn Hạc kể nhóm phụng mệnh liên minh làm nhiệm vụ trọng yếu, bị chậm trễ, phát hiện Phong Nguyên quốc đã bị Mộ Lan xâm nhập, trên đường trốn về bị pháp sĩ Nguyên Anh kỳ truy sát. Hàn Lập được biết gia sư Lý Hóa Nguyên đã tử trận hơn trăm năm trước trong chiến đấu với Mộ Lan pháp sĩ, phu nhân cũng đã mất vì không kết được Kim Đan, các đồng môn đều đã tọa hóa — hắn nhớ lại Vu Khôn, Tống Mông, Chung Vệ Nương và buồn bã thở dài. Hàn Lập từ chối quay về Hoàng Phong Cốc, tự xưng hiện là trưởng lão Lạc Vân Tông thuộc Thiên Đạo Minh. Cuối chương, Niếp Doanh hỏi Hàn Lập có nhớ Tiêu Thúy Nhi không, trong đầu hắn hiện lên hình ảnh tinh nghịch của nàng."},{"chuong":707,"tieuDe":"Nam Cung Chi Tấn","tomTat":"Hàn Lập hỏi thăm Niếp Doanh về Tiêu sư muội, biết nàng đã Kết Đan và lập gia đình, cảm thán cảnh còn người mất và không còn muốn trở về Hoàng Phong cốc — nơi năm xưa đệ tử hạch tâm bỏ rơi hắn làm tốt thí. Hàn Lập chủ động hỏi Đường Minh Hoa (Yểm Nguyệt Tông) về Nam Cung Uyển, vui mừng khi biết nàng đã kết Nguyên Anh thành trưởng lão, nhưng nghe tin ba tháng sau nàng sẽ cùng Ngụy Ly Thần (trưởng lão Hóa Ý Môn, Nguyên Anh kỳ) cử hành song tu đại điển thì phản ứng dữ dội, tự nhận là người ái mộ năm xưa và biểu thị sẽ tham dự. Truy hỏi về Nam Cung Bình, Hàn Lập nhận ra đó chính là Nam Cung Uyển đã dịch dung cải trang. Sắc mặt âm trầm, Hàn Lập chia tay nhóm Lôi Vạn Hạc gần biên giới Phong Nguyên Quốc rồi đổi hướng bay đi. Sau khi hắn rời đi, tu sĩ họ Tiễn phân tích Hàn Lập tuổi khoảng 200 năm mà đã Nguyên Anh, rất có khả năng tiến vào Hóa Thần kỳ — cảnh giới mấy vạn năm mới xuất hiện một lần ở Thiên Nam."},{"chuong":708,"tieuDe":"Hàn Lập Đích Quyết Tâm","tomTat":"Năm tu sĩ lục phái gồm Lôi Vạn Hạc, Niếp Doanh, Tiễn Hoàn, đại hán Cự Kiếm Môn và Đường Minh Hoa bàn luận về Hàn Lập, muốn lôi kéo hắn gia nhập lục phái nhưng nhận ra không có gì đủ hấp dẫn vì hắn đã là trưởng lão Lạc Vân Tông. Lôi Vạn Hạc gợi ý nhờ Nam Cung Uyển làm cầu nối, đề nghị cả nhóm nhanh trở về Cửu Quốc Minh chờ khánh điển ba tháng sau. Nội tâm Lôi Vạn Hạc lo lắng không biết phải báo cáo Lệnh Hồ lão tổ thế nào về đệ tử bị bỏ rơi năm xưa giờ đã ngang hàng lão. Hàn Lập thu Ngự Phong xa để tránh chú ý, suy ngẫm sâu về quan hệ với Nam Cung Uyển, quyết tâm không để nàng thành đạo lữ song tu của Ngụy Ly Thần. Hắn phân tích ba phương án — lén bắt cóc, ám sát Ngụy Ly Thần, quang minh chính đại cầu hôn — rồi chọn phương pháp điều hòa: trước tới Yểm Nguyệt Tông hỏi tâm ý Nam Cung Uyển, sau tùy cơ ứng biến. Chương mô tả hiện trạng lục phái tại Bắc Lương Quốc sau trăm năm bén rễ, và Yểm Nguyệt Tông đặt tân sơn môn tại Linh Lung Sơn. Cuối chương giới thiệu Viên Khôn — quản sự Luyện Khí kỳ duy nhất của Yểm Nguyệt Tông, cháu ruột gia chủ Viên gia — bị Hàn Lập từ tửu lâu gần đó phóng thần thức dính chặt lên thân để do thám."},{"chuong":709,"tieuDe":"Hóa Hình Nhập Sơn","tomTat":"Hàn Lập sau nửa tháng chạy không nghỉ tới Bắc Lương Quốc, quyết định len lén tìm Nam Cung Uyển thay vì bái sơn đường hoàng. Hắn dừng lại tiểu thành dưới chân Linh Lung sơn, dùng thần thức dò tìm tu sĩ Yểm Nguyệt Tông cấp thấp và đánh dấu quản sự Viên Khôn làm mục tiêu. Ngân Nguyệt phục kích giữa đường bắt giữ Viên Khôn cùng hai tu sĩ tùy hành, Hàn Lập dùng Mộng Dẫn thuật phối hợp huyễn thuật moi hết ký ức ba người. Từ đó biết được Nam Cung Uyển là nữ tu sĩ Nguyên Anh kỳ trẻ nhất tông, sắp song tu với Ngụy Ly Thần thuộc Hóa Ý Môn nhưng không rõ lý do, khiến Hàn Lập thất vọng. Hàn Lập dùng Hoán Hình Quyết biến thành Viên Khôn, ẩn tu vi xuống Luyện Khí kỳ, dùng lệnh bài quản sự trà trộn vào Yểm Nguyệt Tông xử lý công việc nửa ngày mà không bị lộ. Trời tối hắn tiến lên tầng hai rồi ngự khí bay thấp tới ranh giới tầng ba, bị hai tu sĩ Trúc Cơ canh gác chặn lại quát mắng khi giả lắp bắp xin gặp Nam Cung sư tổ."},{"chuong":710,"tieuDe":"Nam Cung Uyển","tomTat":"Hàn Lập giả dạng đệ tử Luyện Khí kỳ họ Viên để xâm nhập thượng tầng Linh Lung sơn gặp Nam Cung Uyển. Hắn bịa chuyện bị tiền bối tu vi cao thâm hạ cấm chế trên người và nhờ chuyển hộ lễ vật, dùng linh lực mô phỏng cấm chế cổ quái lừa qua hai tu sĩ Trúc Cơ canh cổng và tu sĩ Kết Đan sơ kỳ Lam sư bá. Gửi hộp gỗ chứa thanh kiếm ngân quang lên trước, Nam Cung Uyển xác nhận người gửi là bạn cũ và đồng ý triệu kiến. Trên đường lên núi, Hàn Lập thấy Lam sư bá thi triển Vô hình độn pháp biến mất vô ảnh vô tung, liên tưởng tới Khung lão quái từng xuất hiện tại Huyết Sắc thí luyện. Cuối chương Hàn Lập bước vào đại sảnh động phủ, thấy thiếu nữ áo trắng tóc dài đang cúi đầu xem thanh kiếm ngân quang, hộp gỗ đã mở và trống không."},{"chuong":711,"tieuDe":"Tích Nhật Chi Tâm","tomTat":"Hàn Lập bước vào đại sảnh gặp Nam Cung Uyển đang vuốt ve ngân kiếm, sai nữ đệ tử Ngọc Nhi lui ra rồi giải trừ dịch dung hiện nguyên hình thật. Nam Cung Uyển không hề ngạc nhiên, tiết lộ đã biết trước qua Truyền Âm phù của Đường sư điệt, nắm rõ mọi tình huống kể cả thị thiếp của Hàn Lập vẫn ở Điền Thiên thành. Khi nàng hỏi Hàn Lập tới để ngăn hôn sự hay chỉ nhìn rồi đi, Hàn Lập dứt khoát tuyên bố muốn nàng làm thê tử, ai muốn đoạt phải hỏi qua hắn. Nam Cung Uyển kể lại toàn bộ tâm lộ trình từ Huyết Sắc Thí Luyện: sau khi thất thân, từng muốn dùng Chu Tước Hoàn trả thù nhưng buông tha, hình bóng Hàn Lập trở thành tâm ma chỉ có thể giải bằng gả hoặc giết. Nàng tiết lộ thân phận Nam Cung Bình hoàn toàn do mình dịch dung, trên đời không có người tên đó. Nàng từng quay về cứu Hàn Lập khi Thất phái đại bại nhưng đến muộn, bị tu sĩ Kết Đan Ma đạo đánh trọng thương. Tác giả bình luận nếu Hàn Lập ngày đó đáp ứng về Yểm Nguyệt Tông, Nam Cung Uyển rất có thể sẽ thất vọng vì hắn dễ dãi mà tâm ma tự giải, rồi thờ ơ lãnh đạm."},{"chuong":712,"tieuDe":"Khốn Tâm Thuật","tomTat":"Nam Cung Uyển kể tiếp quá khứ: từng quay về Việt Quốc tìm Hàn Lập, biết hắn bị Quỷ Linh Môn đuổi giết rồi mất tin tức, tưởng hắn đã chết, tâm ma dần tiêu, may mắn ngưng kết Nguyên Anh thành công trở thành trưởng lão Yểm Nguyệt Tông. Nàng tiết lộ Ngụy Ly Thần là ngụy quân tử, lén tu luyện thuật Thái Âm Bổ Dương, đã nhiều lần cự tuyệt cầu hôn hắn — thân thúc tổ của hắn là Ngụy Vô Nhai, một trong tam đại tu sĩ Nguyên Anh Hậu Kỳ Thiên Nam, thái thượng trưởng lão Cửu Quốc Minh. Đại trưởng lão sư tỷ mới của Yểm Nguyệt Tông (Nguyên Anh Trung Kỳ) câu kết Ngụy Vô Nhai, thừa lúc Nam Cung Uyển thi triển Tố Nữ Luân Hồi Công ra tay chế trụ nàng, hạ Khốn Tâm Thuật bằng máu huyết, tự ý truyền tin nàng đồng ý song tu để ép gạo nấu thành cơm. Nam Cung Uyển xác nhận chưa bao giờ đáp ứng hôn sự, Hàn Lập mừng rỡ. Hai người bày tỏ tâm tư, Hàn Lập tự nhận đã do dự không dám đối diện tình cảm, Nam Cung Uyển nói suy nghĩ hai ngày đêm rồi mới nghe theo con tim chấp nhận hắn, hai người nắm tay nhau. Nam Cung Uyển tiết lộ mấu chốt Khốn Tâm Thuật nằm ở một khối lệnh bài trong tay sư tỷ, phạm vi trăm dặm, Hàn Lập hào khí nhận lời đi lấy lệnh bài dù nàng khuyên lén trốn."},{"chuong":713,"tieuDe":"Thiết Phục","tomTat":"Hàn Lập và Nam Cung Uyển bàn kế dụ sư tỷ Nguyên Anh trung kỳ đến đại sảnh động phủ để phục kích, mượn lực cấm chế bí mật chưa bị phát hiện. Nam Cung Uyển tiết lộ Yểm Nguyệt Tông còn có một sư huynh cũng là tu sĩ Nguyên Anh Kỳ nên nàng không thể và không muốn khống chế tông môn, chỉ muốn rời đi tu luyện yên tĩnh. Hàn Lập bố trí trận kỳ trận bàn khắp sảnh, triệu hoán Ngân Nguyệt ra giao bảo vật bí ẩn để hiệp trợ, phóng Phệ Kim Trùng tam sắc ẩn nóc đại sảnh tạo nhiều tầng mai phục. Nam Cung Uyển bắt đầu giải trừ cấm chế trên người, toàn thân phát quang diễm đỏ đậm, Hàn Lập kích hoạt quang mạc xanh từ cột đá che chắn dao động linh khí. Hàn Lập đề xuất nếu thuận lợi sẽ đưa Nam Cung Uyển về Lạc Vân Tông, nhận định Ngụy Vô Nhai không dám đắc tội Thiên Đạo Minh trong lúc pháp sĩ xâm lấn. Hàn Lập phát hiện cô gái áo vàng Trúc Cơ kỳ dùng Linh Ẩn Phù cấp cao do thám bên ngoài đại sảnh, chất vấn rồi bắt giữ khi cô ta bỏ chạy bằng phù lục độn quang, Ngân Nguyệt phun hồng sắc hương vụ khiến cô ngã quỵ bất tỉnh."},{"chuong":714,"tieuDe":"Thức Phá Dữ Phục Kích","tomTat":"Đại trưởng lão Yểm Nguyệt Tông nhận Truyền Âm phù từ Nam Cung Uyển, rời Lạc Nhật Điện tới động phủ gặp sư muội. Cô gái áo vàng (gián điệp giám thị) báo cáo rằng Nam Cung Uyển nhận ngân kiếm từ một đệ tử quản sự cấp thấp (Hàn Lập giả dạng) rồi bất ngờ muốn gặp sư tỷ. Đại trưởng lão bước vào thính đường, bị dụ buột miệng tiết lộ âm mưu ép Nam Cung Uyển gả cho trưởng lão Hóa Ý Môn Ngụy Vô Nhai để mượn thực lực hưng thịnh tông môn. Phát hiện bị lừa, đại trưởng lão phát kiếm tấn công cô gái áo vàng nhưng cô gái cười quỷ dị, dùng thổ độn thuật biến vào vách đá mất tích. Hàn Lập xuất hiện bên ngoài với kiếm trận chặn đường thoát. Đại trưởng lão rút cấm chế lệnh bài đỏ uy hiếp, phất tay thả đôi Âm Dương Băng Hỏa kiếm. Nam Cung Uyển bình tĩnh phản bác, phun ra bổn mạng pháp bảo Chu Tước Hoàn sẵn sàng ứng chiến. Hàn Lập tung Kinh Long chung phát sóng âm tấn công thần thức đại trưởng lão ngăn niệm chú, đồng thời kích hoạt pháp trận cấm chế đã bố trí sẵn trong đại sảnh."},{"chuong":715,"tieuDe":"Ngưng Quang Bảo Kính Và Luân Hồi Thần Quang","tomTat":"Trong đại sảnh, băng lãnh nữ tử (sư tỷ Nam Cung Uyển) dùng hắc bạch phi kiếm đỡ đợt cấm chế quang hà và sóng âm. Nam Cung Uyển thúc giục Chu Tước Hoàn hóa lửa nghi binh, đồng thời lén phóng Tru Tà Thứ đả thương tay sư tỷ, khiến nàng mất lệnh bài cấm chế. Sư tỷ thi triển Ngưng Quang Bảo Kính — cổ bảo thành danh toàn thân đen bóng — phun ngũ sắc quang trụ phá sạch cấm chế quang hà, hỏa diễm và vây khốn Chu Tước Hoàn. Hàn Lập nhận ra đây là nguyên bản của Thanh Ngưng Kính, uy lực gấp trăm lần, rồi triển khai Thiên Trọng Phong phóng to năm sáu trượng phun hắc quang đối kháng, giằng co ngang ngửa, hình thành cục diện hai đánh một. Ba bên đồng loạt leo thang: Hàn Lập phóng thích Phệ Kim Trùng tạo trùng vân, Nam Cung Uyển thi triển Luân Hồi Thần Quang khiến sư tỷ kinh hãi, còn sư tỷ phun ra Huyết Ma Kiếm — ma kiếm đỏ trong suốt có hắc khí tự rung, máu tanh tràn ngập nhưng có nguy cơ cắn trả chủ nhân. Cuối cùng sư tỷ đe dọa lần cuối buộc Nam Cung Uyển gả cho Ngụy Ly Thần, Hàn Lập thay nàng trả lời dứt khoát, gọi nàng thân mật là Uyển nhi và tuyên bố quyết không đồng ý. Sư tỷ truy vấn thân phận Hàn Lập, suy đoán hắn là nguyên nhân sư muội không chịu lập gia đình, ánh mắt nổi sát khí."},{"chuong":716,"tieuDe":"Huyết Ma Kiếm","tomTat":"Hàn Lập yêu cầu băng lãnh nữ tử (sư tỷ của Nam Cung Uyển) giao lệnh bài cấm chế Khốn Tâm Thuật. Nữ tử cắn lưỡi phun tiên huyết kích hoạt Huyết Ma kiếm, chém ra kiếm khí huyết sắc khổng lồ giam cầm Hàn Lập, hấp thu toàn bộ thiên địa linh khí xung quanh. Hàn Lập kích hoạt Ích Tà Thần Lôi tạo điện võng vây khốn kiếm khí — đây là lần đầu gặp tà khí mà thần lôi không hoàn toàn khắc chế, phải xuất thêm lượng lớn mới phá tan kiếm khí thành quả cầu vàng thu vào tay. Nam Cung Uyển cưỡng kích Luân Hồi Thần Quang dù chưa hoàn thành, hào quang bị lục vụ từ cờ tam giác của nữ tử cản trở nhưng chiếm thượng phong, cuối cùng phát tiếng phượng minh phá tan lục vụ chụp xuống đối phương. Hàn Lập thả Phệ Kim Trùng tấn công, trùng bị tiểu kiếm bạc thi triển Hóa kiếm vi ti chém rơi nhiều lần, nhưng đồng loạt phục sinh giương cánh bay lên tái chiến. Băng lãnh nữ tử nhận ra không địch nổi liên thủ của Hàn Lập và Nam Cung Uyển, hóa cầu vồng hắc bạch xuyên nóc đại sảnh đào tẩu, dự tính triệu tập đệ tử Yểm Nguyệt Tông và phát động đại trận trấn phái vây khốn hai người. Lai lịch Huyết Ma kiếm được hé lộ: xuất hiện quỷ dị ở Thiên Nam, không rõ Cổ bảo hay Pháp bảo, ai có cũng dùng được nhưng tổn hao máu huyết và nhiễm ma tính vào chân nguyên."},{"chuong":717,"tieuDe":"Chỉ Hoàn","tomTat":"Đại trưởng lão Yểm Nguyệt Tông cố thoát thân bằng phù lục, kiếm khí và lục hỏa nhưng bị cấm chế ẩn bí trong phủ của Nam Cung Uyển chặn lại. Ngân Nguyệt dùng Tử Vân Đâu phóng tử võng chụp bắt và cầm cố đại trưởng lão khi nàng đang xuyên đỉnh đại sảnh trốn thoát. Đại trưởng lão bạo phát linh lực chuẩn bị liều mạng, Nam Cung Uyển kịp thi triển Luân Hồi Thần Quang mê hồn nàng hôn mê bất tỉnh nhưng cố ý giữ mạng để báo đáp ân tình sư môn, tránh cho Yểm Nguyệt Tông bị diệt môn. Nam Cung Uyển hạ cấm chế lên sư tỷ, thu hồi lệnh bài Khốn Tâm Thuật từ túi trữ vật. Hàn Lập phát hiện trong đống đồ sư tỷ một chiếc nhẫn đen tinh xảo (Chỉ Hoàn) giống hệt chiếc nhẫn đen mình đã sở hữu từ trước, cả hai không có linh khí, cất chung vào hộp ngọc. Nam Cung Uyển rút Huyết Ma Kiếm từ thân sư tỷ, nhận định ma khí quá mạnh bản thân không dùng, đưa cho Hàn Lập giữ vì kim hồ có khả năng khắc chế. Nam Cung Uyển chính thức xác nhận rời Yểm Nguyệt Tông theo Hàn Lập."},{"chuong":718,"tieuDe":"Trọng Phản Điền Thiên Thành","tomTat":"Hàn Lập thu lấy Huyết Ma kiếm có ma khí phản phệ, để lại Ngưng Quang Kính cho sư tỷ băng lãnh. Nam Cung Uyển dùng cấm chế lệnh bài giải trừ hoàn toàn Khốn Tâm Thuật, lưu lời trong ngọc giản cho sư tỷ rồi đặt vào túi trữ vật bên hông nàng ta. Tại biên giới Bắc Lương Quốc, hai người chia tay: Hàn Lập khuyên Nam Cung Uyển về Lạc Vân Tông trước vì thân phận Nguyên Anh kỳ Yểm Nguyệt Tông dễ bị nhận ra. Nam Cung Uyển tặng Hàn Lập khăn lụa cổ bảo phòng thân và Ích Hỏa bội (tín vật sai khiến đệ tử ký danh), tiết lộ có đệ tử đang mở hàng tại Điền Thiên Thành. Trên đường tới Ngu Quốc, Hàn Lập nghe tin quân chủ lực Cửu Quốc Minh đại bại ba trận liên tiếp trước Mộ Lan pháp sĩ dùng man hoang cự thú, buộc phải phát hội minh cầu viện. Hàn Lập suốt đêm bay tới Điền Thiên Thành, nơi đã mở Thượng Nguyên Diệt Quang Trận vào trạng thái chiến tranh. Xưng danh Lạc Vân Tông trưởng lão vào thành, hắn dùng thần thức tìm thấy Mộ Phái Linh tại lầu các cũ, nàng vui mừng lẫn sợ hãi khi thấy hắn trở về."},{"chuong":719,"tieuDe":"Thiên Cực Môn","tomTat":"Hàn Lập trở về Điền Thiên Thành, gặp lại Mộ Phái Linh đã đột phá Trúc Cơ Hậu Kỳ nhờ đan dược hắn cho trước đó. Một thanh niên Kết Đan Kỳ tên Bạch Thư Quân, đệ tử Thiên Cực Môn, đến dây dưa theo đuổi Mộ Phái Linh. Hàn Lập phóng linh áp Nguyên Anh ép gã suýt quỳ, tuyên bố quyền sở hữu thị thiếp. Lỗ Vệ Anh trưởng lão Thiên Cực Môn lộ diện giải vây, thừa nhận đã sai đệ tử dây dưa để tìm cách gặp Hàn Lập, trao ngọc giản lục sắc hẹn gặp riêng đêm nay với mục đích bí ẩn. Hàn Lập sau đó tới nghị sự đại điện ở giữa Điền Thiên Thành, nơi hơn mười tu sĩ Nguyên Anh Kỳ đang thương nghị đối sách chống pháp sĩ Mộ Lan xâm lấn. Tại đây hắn nhận ra Lữ trưởng lão, Hỏa Long Đồng Tử, và đặc biệt nhận ra một hoàng bào lão giả chính là Lệnh Hồ Lão Tổ ngày xưa của Hoàng Phong Cốc."},{"chuong":720,"tieuDe":"Điện Nghị","tomTat":"Hàn Lập bước vào đại điện dự hội nghị Nguyên Anh tu sĩ Thiên Nam do Bối Diệp Tông tông chủ Ngô Bằng và Hóa Ý Môn Thích phu nhân chủ trì, cùng Lữ trưởng lão, Hỏa Long Đồng Tử, Lệnh Hồ lão tổ, trưởng lão Ngự Linh Tông và nhiều tu sĩ khác. Ngô Bằng thông báo chiến báo bất lợi: đám Dư trưởng lão đại bại, hai cấm chế đại trận bị cự thú phá tan, Ám Ảnh Tông Hoàn đạo hữu tử chiến — là Nguyên Anh thứ hai chết trận. Hai pháp sĩ Nguyên Anh Sơ Kỳ cổ quái dùng bảo vật hắc hồng quang phong tỏa Nguyên Anh sau khi xuất khiếu, chặn thuấn di thần thông dẫn tới tử vong. Thích phu nhân tiết lộ hai pháp sĩ này tướng mạo dị thường, trực tiếp hấp thực linh hồn người chết, nghi là yêu dị hóa hình hoặc Mộ Lan cấu kết thế lực khác. Hàn Lập chủ động phân tích: Mộ Lan nhân ra tay không kiêng nể chứng tỏ muốn đánh nhanh, suy đoán thảo nguyên Mộ Lan có biến cố lớn, khiến Ngô Bằng và Thích phu nhân sắc mặt đại biến. Ngô Bằng kết luận phải tổng động viên tất cả tông môn Thiên Nam và phái viện quân thứ hai."},{"chuong":721,"tieuDe":"Lệnh Hồ Chi Yêu","tomTat":"Hội nghị các đại phái Thiên Nam kết thúc, Thích phu nhân đề nghị giữ bí mật nội dung thương nghị trong phạm vi Nguyên Anh Kỳ và thông tri cho Ngụy Vô Nhai triệu tập tam đại tu sĩ cấp Hóa Thần đối phó thần sư Mộ Lan nhân. Hàn Lập cùng Lữ tu sĩ và Hỏa Long Đồng Tử rời đại điện, Hàn Lập nhận truyền âm rồi tách đi một mình. Hỏa Long Đồng Tử tiết lộ Cổ Kiếm Môn đã điều tra xuất thân Hoàng Phong Cốc của Hàn Lập, phân tích Lệnh Hồ lão tổ sắp đại hạn nên đang lôi kéo Hàn Lập quay về, Lữ tu sĩ lo âu nhưng thừa nhận không thể trói buộc. Tại quán trà hai tầng, Lệnh Hồ lão tổ — sắc mặt vàng vọt, thân bận hoàng bào — thẳng thắn mời Hàn Lập quay lại Hoàng Phong Cốc làm trưởng lão kế vị, tiết lộ bản thân chỉ còn hơn hai mươi năm tuổi thọ, hứa giao toàn bộ tông phái, dùng cả tình cảm sư môn lẫn lợi ích quyền lực thuyết phục. Hàn Lập kiên quyết từ chối, nói đã gia nhập Lạc Vân Tông, chỉ muốn tìm chỗ tu luyện, coi hưng diệt tông phái là chuyện bình thường, không quan tâm đồng môn cũ."},{"chuong":722,"tieuDe":"Sơ Kiến Ngọc Phù","tomTat":"Lệnh Hồ Lão Tổ bày tỏ tình cảm hơn ngàn năm với Hoàng Phong Cốc, lo truyền thừa gián đoạn sau khi tọa hóa, mời Hàn Lập làm trưởng lão. Hàn Lập suy nghĩ kỹ rồi dứt khoát từ chối vì không muốn dính vào vấn đề Lục phái, Cửu Quốc Minh và quan hệ phức tạp với Nam Cung Uyển cùng Yểm Nguyệt Tông. Lệnh Hồ Lão Tổ cải biến điều kiện, tặng ba trọng bảo đổi lấy ba lần tương trợ: Lam Quang Thuẫn là cổ bảo phòng ngự khắc hỏa, thất cấp yêu đan Thiết Sí Điêu, và ngọc phù thượng cổ do cổ tu sĩ tinh thông đạo phù luyện chế. Lệnh Hồ Lão Tổ biểu diễn thần thông quỷ thủ của ngọc phù, huyễn hóa hắc hồng đại thủ dùng âm hỏa hủy bàn gỗ không dấu vết, tiết lộ uy lực đã dùng hơn phân nửa. Hàn Lập đồng ý và trao lại ba trận bàn trắng trong suốt do mình luyện chế làm tín vật. Sau khi rời đi, Hàn Lập lấy ngọc giản của bạch bào trưởng lão Thiên Cực Môn ra xem, sắc mặt lộ vẻ do dự."},{"chuong":723,"tieuDe":"Lưỡng Nghi Hoàn","tomTat":"Hàn Lập cầm ngọc giản xuyên qua Điền Thiên Thành tới cửa hàng tạp hóa Ngọc Hòa hiên ở góc hẻo lánh, được chưởng quỹ tu vi Luyện Khí kỳ dẫn qua cơ quan thế tục xuống mật thất dưới lòng đất. Dưới mật thất, Hàn Lập tái ngộ Nam Lũng Hầu cùng lão giả áo trắng Tuyền Kì Tử thuộc Thiên Cực Môn — bạn sinh tử chi giao của Nam Lũng Hầu. Nam Lũng Hầu sắc mặt xám trắng vì tổn hao nguyên khí, kể lại bị đối phương cài bí thuật truy tung, đuổi kịp ở biên giới thảo nguyên Mộ Lan, may gặp đội pháp sĩ cao cấp nên trốn thoát. Hắn cảnh báo Quỷ Linh Môn cũng sẽ truy sát Hàn Lập vì hắn giữ vật phẩm then chốt. Tuyền Kì Tử tiết lộ chiếc nhẫn đen Hàn Lập đang giữ chính là Lưỡng Nghi Hoàn (phần âm hoàn), do Huyền Hoàng Lão Nhân dùng thiên ngoại vẫn thiết luyện chế, gặp Bắc Cực nguyên quang thì âm hoàn hộ thể còn dương hoàn thao túng nguyên quang tấn công. Đây là vật phẩm bắt buộc để vào Trụy Ma Cốc an toàn, cần phối hợp cùng lộ tuyến đồ của Nam Lũng Hầu. Hàn Lập đang cân nhắc lợi hại lời đề nghị liên thủ."},{"chuong":724,"tieuDe":"Hỏa Thiềm Cổ Thú","tomTat":"Nam Lũng Hầu đề xuất ba người (cùng Tuyền Ki Tử và Hàn Lập) liên thủ dùng Lưỡng Nghi hoàn vào Trụy Ma Cốc tầm bảo. Hàn Lập nghe xong nhận ra chiếc nhẫn lấy từ sư tỷ Nam Cung Uyển chính là Dương hoàn, tức đã có đủ cặp với Âm hoàn. Nam Lũng Hầu tiết lộ trong cốc có Hỏa Thiềm cổ thú sống vạn năm, sở hữu Thiên Lân Yêu Hỏa mạnh hơn anh hỏa tu sĩ Nguyên Anh, Thương Khôn Thượng Nhân từng giao thủ đã thua và bị hỏa độc suýt chết. Hai người cần lam sắc hàn diễm của Hàn Lập để khắc chế Hỏa Thiềm, dẫn dụ nó rời đi lấy Túi trữ vật của cổ tu sĩ gần hang ổ. Hàn Lập không đáp ứng ngay, hẹn trước thời điểm ổn định một năm sẽ trả lời, cam kết dù không đi cũng cho mượn Lưỡng Nghi hoàn. Tuyền Ki Tử giao lệnh bài Thiên Cực Môn cho Hàn Lập để liên lạc. Hàn Lập rời đi, xác định ưu tiên trước mắt là đối phó pháp sĩ Mộ Lan xâm lấn."},{"chuong":725,"tieuDe":"Chi Viện","tomTat":"Hàn Lập trở về lầu các, Mộ Phái Linh lui lên lầu nghỉ ngơi, hắn ngẫm chuyện tình Nam Cung Uyển rồi thở dài. Lữ Lạc và Hỏa Long đồng tử thông báo đã truyền tin cho đạo hữu Thiên Đạo Minh, đại bộ phận đồng ý trợ giúp Cửu Quốc Minh ngăn cản tiên phong Mộ Lan, nhưng lo ngại Cửu Quốc Minh có thể liên hợp hãm hại thế lực khác. Hàn Lập đồng ý ủng hộ liên minh. Tại nghị điện ngày thứ hai, số tu sĩ Nguyên Anh tham dự tăng vọt khiến hai chủ trì Côn Bằng và Thích phu nhân ứng phó không kịp, Cửu Quốc Minh bị buộc chấp nhận điều kiện tứ đại thế lực chia đều nhân thủ. Thiên Đạo Minh Nguyên lão hội quyết định phái thêm trưởng lão Nguyên Anh và tu sĩ Kết Đan chi viện Điền Thiên Thành. Hàn Lập được phái cùng lão giả họ Mã của Hạo Nhiên Các và Cốc Song Bồ của Ngự Linh Tông tới trấn thủ cấm chế đại trận biên giới Ngu Quốc. Ba người bay trước bằng độn quang, Hàn Lập nhận thấy Túi linh thú bên hông Cốc Song Bồ phát ra hơi thở bất thường, còn hai người đồng hành đều không coi trọng thực lực hắn vì biết hắn mới tiến cấp Nguyên Anh."},{"chuong":726,"tieuDe":"Hoàng Long Sơn","tomTat":"Hơn nửa tháng sau, tại đỉnh Hoàng Long Sơn gần Ngu Quốc, đại hán họ Lục (Nguyên Anh kỳ) nhận Truyền Âm Phù từ Bặc Đà Tử báo tin Thiên phong huyền ba trận đã bị phá, bản thân bị thương nặng, truy binh pháp sĩ Mộ Lan sắp đến. Đại hán gõ chuông xanh kích hoạt đại trận lục sắc vụ hải bao phủ hơn mười dặm phòng thủ. Bốn Kết Đan tu sĩ dưới trướng gồm Trùng Vân Tử, Mộ Dung huynh đệ và nữ tu họ Lý nghe lệnh chuẩn bị. Ba Nguyên Anh viện quân là Hàn Lập, lão giả họ Mã và Cốc Song Bồ ngày đêm kiêm trình đến nơi. Hàn Lập nhận ra Mộ Dung huynh đệ là người quen cũ, hỏi thăm Niếp sư muội. Đại hán họ Lục thoáng thất vọng khi biết Hàn Lập mới ngưng kết Nguyên Anh mấy năm gần đây nhưng vẫn cảm tạ, sau đó nghiêm sắc mặt phân tích tình thế nguy hiểm trước mắt."},{"chuong":727,"tieuDe":"Tích Nhật Anh Ninh","tomTat":"Trọc mi đại hán thông báo Thiên Thai Cốc đã bị pháp sĩ công phá, tu sĩ chiến bại đang tháo chạy về cứ điểm. Lão giả họ Mã xung phong đi tiếp ứng cùng Mộ Dung huynh đệ, nói muốn thử uy lực dị bảo mới có được. Hàn Lập được nữ tu họ Lý dẫn tới tiểu lâu nghỉ ngơi, qua đôi mắt quen thuộc và tên Anh Ninh nhận ra nàng chính là con gái Mặc Ngọc Châu. Nàng xác nhận mẫu thân là Mặc Ngọc Châu xuất thân Việt Quốc, rút Thông Linh ngọc bội đưa Hàn Lập xem. Hàn Lập cầm ngọc bội lộ thần sắc tang thương nhớ cố nhân, rồi trả lại. Anh Ninh kể ngoại tổ phụ cùng phụ thân sớm qua đời, mẫu thân mang nàng rời Việt Quốc phiêu bạt rồi định cư Cửu Quốc Minh. Hàn Lập tự nhận là một nửa sư huynh của mẫu thân nàng ở thế tục, nhận vai sư bá, tặng hai bình đan dược đột phá bình cảnh và viên cầu Phệ Kim Trùng tam sắc ngưng tụ để nàng phòng thân."},{"chuong":728,"tieuDe":"Tử La Cực Hỏa","tomTat":"Hàn Lập ngồi tĩnh thất tu luyện, dùng Kiềm Lam Băng Diễm kết hợp Lục Dực Sương Công phun hàn khí luyện hóa thành ma diễm tím, đặt tên Tử La cực hỏa — uy lực hơn Kiềm Lam Băng Diễm một bậc, là đòn sát thủ lớn nhất hiện tại nhưng số lượng còn rất ít. Ngân Nguyệt nhận xét uy lực đã mạnh gấp ba, còn nhiều tiềm lực. Hàn Lập bàn về hy vọng mở Hư Thiên Đỉnh, Ngân Nguyệt cam đoan thần thông chỉ hơn không kém. Anh Ninh truyền tin báo Mã tiền bối đã đưa viện quân về, Hàn Lập đến đại điện gặp Bặc Vân Hạc — chủ trì Thiên Thai Cốc, Nguyên Anh Kỳ tu sĩ sắc mặt tái nhợt vừa thoát nạn. Bặc Vân Hạc tường thuật Thiên Thai Cốc thất thủ: pháp sĩ Mộ Lan mang thượng cổ cự thú mặc chiến giáp được gia trì cổ quái cấm pháp phá vỡ đại trận, bản thân bị hai Đại Thượng Sư liên thủ kìm chân, cảnh báo còn pháp sĩ khí tức quỷ dị ẩn nặc. Mọi người thống nhất dựa đại trận giằng co tranh thời gian, trọc mi đại hán chỉ huy sắp xếp phòng thủ. Đại quân Mộ Lan như mây đen áp sát phía nam Hoàng Long Sơn, hơn mười cao giai pháp sĩ dẫn đầu, nổi bật ba cao thủ bao quanh một hắc bào pháp sĩ bí ẩn được kính sợ pha lẫn chán ghét."},{"chuong":729,"tieuDe":"Hỏa Linh Hóa Giao","tomTat":"Hai pháp sĩ Nguyên Anh cao giai bàn bạc phá trận, Hắc bào nhân (Thiên Khốc tiên sinh) phán đoán tu sĩ bên trong đã muốn đi ra. Đám người Hàn Lập gồm bảy đạo độn quang xuất trận qua vụ hải, Hàn Lập quan sát Hắc bào nhân liên tưởng đến Huyền Cốt Thượng Nhân, nghi là quỷ tu. Quật Diệu (Đại Thượng Sư Bái Hỏa Bộ, Mộ Lan) hóa hỏa cầu bay xuống khiêu chiến, hai bên thống nhất tỷ thí một chọi một. Lão giả họ Mã (Hạo Nhiên Các) chủ động ra trận đầu. Hàn Lập dùng Thiên Nhãn phát hiện hỏa mãng trên người Quật Diệu không phải linh thú phổ thông, bí mật truyền âm cảnh báo Mã lão giả. Quật Diệu đắc ý tiết lộ hỏa mãng là Thiên Địa Hỏa Linh ngưng hóa sinh thành, hỏa mãng biến hóa thành hỏa giao hồng lân mọc sừng mọc vuốt. Lão giả họ Mã dốc toàn lực lấy ra quyển trục bát quái đồ ngũ sắc, nhưng hỏa giao phun xích diễm cuồn cuộn bao phủ cả người và pháp bảo trong biển lửa, kết cục chưa rõ."},{"chuong":730,"tieuDe":"Thái Huyền Bát Quái Đồ","tomTat":"Tu sĩ họ Mã kích hoạt Thái Huyền Bát Quái Đồ phản công Quật Diệu, phóng bạch phong trụ đẩy lui biển lửa và bắn ngân hồng tấn công. Quật Diệu đáp trả bằng phi đao đỏ trong suốt và lưỡng diện hồng tiểu phiên, phun tinh khí tăng cường hỏa giao nuốt hỏa vân bành trướng thân hơn mười trượng. Tu sĩ họ Mã ném quyển trục lên trời triệu trận đồ ngũ sắc khổng lồ vây nhốt Quật Diệu cùng hỏa giao, mọi phản kích đều vô hiệu. Hắc bào nhân bình luận tu sĩ họ Mã chưa nắm cách dùng Cổ Bảo, chỉ dựa linh lực cường đại, khinh thường tu sĩ Thiên Nam. Hàn Lập dùng Thanh Minh linh nhãn quan sát, Ngân Nguyệt truyền âm tiết lộ đây là Cổ Bảo thượng cổ uy lực không dưới Tử Vân Đấu nhưng kiện này chỉ là thô chế hạ phẩm. Cuối cùng Quật Diệu phá nát trận đồ thoát ra mặt đỏ như máu, tu sĩ họ Mã sắc mặt xám trắng thu hồi tàn tích quyển trục."},{"chuong":731,"tieuDe":"Thiên Sát Chân Ma Công","tomTat":"Trận đấu giữa Mã lão giả và Quật Diệu kết thúc hoà khi pháp sĩ cao gầy phán quyết hai bên pháp lực tiêu hao quá nhiều, quyển trục pháp bảo của Mã lão giả bị hư hại nặng nề. Hắc bào nhân chủ động thách đấu sinh tử phe Thiên Nam, tuyên bố không chết không thôi, khiến trọc mi đại hán và Cốc Song Bồ biến sắc nhưng không dám ứng chiến. Hàn Lập đột ngột xung phong nhận trận, hoá thanh hồng bay tới đối mặt đối thủ. Hắc bào nhân ma hoá thân thể thi triển Thiên Sát Chân Ma Công, dùng quỷ trảo ẩn hình và đôi lợi trảo tấn công nhưng đều bị Hàn Lập né hoặc đỡ. Hàn Lập nhận ra bộ dáng ma hoá giống hệt huyễn ảnh Lục Cực Chân Ma Công mà Lục Đạo Truyền Nhân từng thi triển, hỏi về Lục Đạo Cực Thánh nhưng hắc bào nhân không biết danh hiệu này. Hàn Lập thi triển kim sắc điện hồ phá tan trảo ảnh và bao trùm đối thủ, hắc bào nhân mới nhớ ra đây chính là tối kiêng kị của Thiên Sát Chân Ma Công mà trưởng lão truyền công từng dặn dò, kinh hãi hoá thân thành vô số mảnh tơ đen phát sáng bắn đi bốn phương tháo chạy."},{"chuong":732,"tieuDe":"Song Vỹ Xà","tomTat":"Hàn Lập dùng Ích Tà Thần Lôi (kim sắc điện hồ) diệt sát hắc bào nhân Thiên Khốc trong chớp mắt, kể cả nguyên anh cũng không chạy thoát, thu được Túi trữ vật màu đen. Đại quân Mộ Lan rút lui theo lệnh của một thanh âm bí ẩn không rõ nam nữ, hứa sẽ giải thích cái chết của Thiên Khốc với các Thần Sư. Hai Đại Thượng Sư Mộ Lan lộ thông tin: Thiên Khốc đến từ Bàng Đại đế quốc, trước đó đã tiêu diệt hai tu sĩ Nguyên Anh Thiên Nam. Chúng tu sĩ quay về đại điện, thái độ kính sợ Hàn Lập, đại hán trọc mi khen ngợi và hứa trọng thưởng. Hàn Lập tinh mắt phát hiện một người trong nhóm lộ tia cười châm chọc đáng ngờ. Sau khi mọi người tản đi, kẻ ám sát bí ẩn quay lại đại điện, vu cáo Hàn Lập là gian tế Mộ Lan, đưa lục sắc ngọc giản biến thành Song Vĩ Phỉ Thúy Xà cắn chết đại hán trọc mi, nguyên anh không thể độn thoát, thi thể tan chảy. Kẻ ám sát lấy Túi trữ vật trên thi thể, kích động hạ thần thức tìm kiếm vật gì đó bên trong."},{"chuong":733,"tieuDe":"Bại Lộ","tomTat":"Cốc Song Bồ lục soát Túi trữ vật của đại hán trọc mi nhưng không tìm thấy lệnh bài, nhận ra mình đã trúng bẫy. Hắn định bỏ chạy nhưng bốn vách tường đại điện phát ngân quang hình thành lồng ánh sáng nhốt chặt, mọi nỗ lực dùng linh thú Xuyên Sơn Giác Bàn và pháp bảo lam sắc phi xoa tấn công đều bị bắn ngược. Đại hán họ Lục hiện thân giải thích đại điện chính là trung tâm đại trận Hoàng Long Sơn, và cái bị giết trước đó chỉ là huyết nhục khôi lỗi thế thân do tu sĩ bí ẩn ở Cửu Quốc Minh luyện chế. Hàn Lập cùng Mã phó môn chủ bước ra từ thạch bích, Cốc Song Bồ không còn chối cãi, tuyên bố bản thân vốn là người Mộ Lan chứ không phải phản đồ, rồi phân trần về tình cảnh thiếu thốn tư nguyên tu luyện khiến pháp sĩ Mộ Lan phải liều lĩnh xâm lược Thiên Nam. Hàn Lập bình thản tiết lộ đã nghe trộm truyền âm mật thuật giữa Cốc Song Bồ và Nhạc thượng sư, nói ra việc chủ lực Mộ Lan đại bại trước người Đột Ngột mất hơn nửa thảo nguyên, khiến Cốc Song Bồ kinh hãi suy đoán thần thức Hàn Lập phải ngang tu sĩ Nguyên Anh hậu kỳ. Đại hán họ Lục dùng lệnh bài kích hoạt cấm chế ngân hoa hủy diệt trong lồng để xử tử Cốc Song Bồ, tuyên bố hắn sẽ hình thần câu diệt, rồi cùng Hàn Lập và Mã phó môn chủ rời đi bàn bạc cách giải thích với liên minh về việc trưởng lão Ngự Linh Tông thực chất là gian tế."},{"chuong":734,"tieuDe":"Phụ Linh Xà Quái","tomTat":"Hàn Lập cùng đại hán trọc mi và lão giả họ Mã bàn cách xử lý vụ gián điệp Cốc Song Bồ, quyết định trình báo Ngự Linh Tông kèm chứng cớ là ngọc giản phục chế đối thoại. Bất ngờ Cốc Song Bồ trong cấm chế thi triển phụ linh thuật, hợp nhất với song vĩ phỉ thúy xà biến thành quái vật nửa người nửa rắn có chiến lực ngang Nguyên Anh trung kỳ. Quái xà phun độc dịch đen làm nhiễm quang bích rồi phá lỗ hổng thoát khỏi cấm chế, đại hán và Mã lão giả chỉ dám phòng ngự. Hàn Lập chủ động chắn lỗ hổng, dùng bàn tay phủ ma diễm xanh đóng băng toàn thân quái xà trong tích tắc, sau đó phóng kim hồ hóa kim võng phá vỡ băng điêu. Một vật thể đen cỡ nắm tay từ trong bay ra cố tẩu thoát nhưng bị kim võng bắt giữ, Hàn Lập siết kim võng bạo vỡ, kim quang bao phủ vật đen bên trong."},{"chuong":735,"tieuDe":"Tương Kế Tựu Kế","tomTat":"Ích Tà Thần Lôi diệt nguyên anh xà quái phụ linh trong kim mang, khắc chế hoàn toàn phụ linh thuật thượng cổ ma đạo. Hàn Lập nhặt túi trữ vật và pháp bảo của kẻ địch rồi giao cho đại hán trọc mi để chuyển về Ngự Linh Tông, tránh rắc rối. Đại hán trọc mi và Mã lão giả đánh giá thần thông Hàn Lập sâu không lường, tuy Nguyên Anh sơ kỳ nhưng ngang Nguyên Anh hậu kỳ. Hàn Lập suy ngẫm rằng sau khi ngưng kết nguyên anh không cần giấu toàn bộ thần thông nữa, quyết lộ bớt sức mạnh nhưng giữ chiêu sát thủ. Cảm ứng Tử La Cực Hỏa bao nguyên anh có bất ổn sau khi phóng hết Kiềm Lam Băng Diễm, nhận ra uy lực ma diễm liên quan cảnh giới. Đại hán trọc mi đề kế tương kế tựu kế lợi dụng việc phe Mộ Lan cho gian tế phá đại trận. Ngày thứ hai, đại quân pháp sĩ kéo đến, xuất hiện Nhạc thượng sư ngồi trên cự thú khổng lồ khoác chiến giáp đen, được pháp sĩ cao gầy và Quật Diệu cung kính. Phe pháp sĩ thấy Hoàng Long Sơn hoang tàn im ắng nhưng còn cấm chế thần thức, nghi là huyễn tượng hoặc gian tế thất bại."},{"chuong":736,"tieuDe":"Phá Trận Đại Chiến (1)","tomTat":"Ba Đại Thượng Sư Mộ Lan là Nhạc Thượng Sư, Quật Diệu và Ấm Thượng Sư họp bàn kế phá đại trận Hoàng Long Sơn, dưới áp lực viện quân Thiên Nam sắp tới trong hai ba tháng. Nhạc Thượng Sư quyết định phái gần trăm pháp sĩ cấp thấp tiên phong thăm dò, sau tăng thêm hai trăm người. Khi tổng cộng ba trăm pháp sĩ Mộ Lan đã vào núi, lão giả họ Mã và trọc mi đại hán bên phe Cửu Quốc Minh phát động cấm chế đại trận, lục vụ bùng phát bao phủ toàn núi nhốt toàn bộ. Quật Diệu nổi giận vì hậu nhân trực hệ bị mắc kẹt, xin đi đầu phá trận bằng hỏa linh tinh nguyên. Nhạc Thượng Sư phân công tác chiến: tự nhận đối phó Hàn Lập bằng Nhu phong quyết, dặn Ấm Thượng Sư tránh cận chiến. Trong trận, Hàn Lập bình tĩnh giết một Kết Đan pháp sĩ Mộ Lan rồi bay về trung tâm hải vụ. Phe Mộ Lan phát động tổng công kích, trống trận vang lên, linh khí bùng phát, lão giả họ Mã và trọc mi đại hán trên lầu cao nhìn đại quân địch với nét mặt ngưng trọng."},{"chuong":737,"tieuDe":"Phá Trận Đại Chiến (2)","tomTat":"Trọc mi đại hán, lão giả họ Mã và Hàn Lập họp bàn đối sách trước trận đại chiến tại Hỏa Long Sơn. Lão giả họ Mã đã dùng Nặc Thiên Kỳ che khuất nửa đỉnh núi, pháp lực còn lại chỉ đủ cầm chân một Đại Thượng Sư. Hàn Lập nhận nhiệm vụ đối đầu Nguyên Anh tu sĩ phe Mộ Lan, hai người còn lại lo diệt thấp giai pháp sĩ. Pháp sĩ Mộ Lan phát động linh thuật đại trận hỏa thuộc tính do Quật Diệu chủ trì, hơn mười hỏa cầu khổng lồ phá tan cấm chế vụ hải. Nữ tử áo xanh dùng viên quyển vàng kích hoạt cự tê thú lao vào vụ hải, rồi ra lệnh đại quân hơn ngàn pháp sĩ tổng tấn công. Hàn Lập mai phục trong vụ hải, phủ Phệ Kim Trùng lên thân, bày trận pháp tạm thời, dùng thần thức phát hiện đối phương có Nguyên Anh trung kỳ nữ pháp sĩ. Hắn gọi Ngân Nguyệt ra, giao Tử Vân Đấu và giỏ hoa Cổ Bảo, dặn chiến thuật linh hoạt, không cần liều mạng."},{"chuong":738,"tieuDe":"Phá Trận Đại Chiến (3)","tomTat":"Hàn Lập giao hai kiện bảo vật cho Ngân Nguyệt, ra lệnh nàng ẩn hình phục kích chờ thời cơ ra tay như lần đối phó Đại trưởng lão Yểm Nguyệt Tông trước đó. Đại quân pháp sĩ Mộ Lan theo cự tê thú tiến vào sương mù, cự tê dùng thân hình khổng lồ phá sạch mọi cấm chế, mở ra khu trống hơn trăm trượng. Phe tu sĩ dùng hai thanh ngân qua hỗ kích tạo lôi điện chọc giận cự tê, dụ nó đuổi theo vào sương mù tách khỏi đội hình. Hơn trăm tu sĩ phục binh từ sương mù bốn phía tấn công rồi rút, khiến đám pháp sĩ Mộ Lan phải phân nhóm truy sát, đội hình hoàn toàn tan rã. Lão giả họ Mã bình tĩnh dùng thần thức phá ẩn độn của Âm thượng sư, hai bên khai chiến. Đại hán họ Lục chặn Quật Diệu, lần đầu hiển lộ khí linh chi bảo bạch đoản côn hóa Tứ Nhĩ Kim Viên — vượn vàng bốn tai cao năm sáu trượng — khiến Quật Diệu kinh hãi. Nữ tử áo xanh Nguyên Anh Trung Kỳ hành động riêng lẻ nhắm phá trung tâm đại trận, cảm nhận thần thức Hàn Lập cường đại không dưới Nguyên Anh Hậu Kỳ, rút thanh châu chuẩn bị giao chiến."},{"chuong":739,"tieuDe":"Phá Trận Đại Chiến (4)","tomTat":"Nữ tử áo xanh (Nhạc Thượng Sư) dùng thanh sắc viên châu phá sương mù, phát hiện Hàn Lập phục kích và nhận ra đám kim vân Phệ Kim Trùng trên cao. Nàng tiết lộ Phệ Kim Trùng là thánh trùng người Đột Ngột, tử địch truyền kiếp của Mộ Lan nhân, tổ tiên Đột Ngột bồi dục hơn mười con thành thục, đồng thời lộ điểm yếu: bảo vật mộc ngọc có thể cấm chế vây khốn chúng. Nàng kích phát Hoàng Linh Đỉnh phóng hoàng hà quang tấn công đàn trùng, nhưng Hàn Lập lập tức phân tán Phệ Kim Trùng vào sương mù tứ phía tấn công các pháp sĩ Mộ Lan khác. Nữ tử tung tuyết điêu pháp bảo hóa cự điêu tấn công Hàn Lập, nhưng Hàn Lập dùng kim võng, Bạch Lân Thuẫn phòng ngự rồi dùng hắc hồng cự thủ bắt gọn tuyết điêu và phun Kiền Lam Băng Diễm đóng băng hoàn toàn. Trong lúc đó nữ tử hoàn thành Bạch Liên bí thuật, đọc thượng cổ chú ngữ kết ấn hoa sen tạo bạch sắc quang mạc phong tỏa phương viên trăm trượng, chặn đứng Thanh Trúc Phong Vân Kiếm không thể tới gần, đẩy Hàn Lập vào thế bất lợi."},{"chuong":740,"tieuDe":"Phá Trận Đại Chiến (5)","tomTat":"Hàn Lập thi triển Âm Ma Trảm phóng quang phiến hắc hồng tấn công Bạch Liên của nữ tử áo xanh nhưng bị liên ảnh chặn lại. Hắn tung Thiên Trọng Phong hóa sơn phong trăm trượng ép nữ tử phải thi triển Phong Độn Thuật thoát đi. Hàn Lập mọc Phong Lôi Sí áp sát dùng Kiềm Lam Băng Diễm phá quang tráo, nhưng nữ tử đã nhập Bạch Liên vào thiên linh cái, từ trán phóng cánh hoa sen trắng đánh trúng ngực Hàn Lập, bắn bay hai ba mươi trượng khiến hắn khạc máu. Trùng giáp tam sắc bên trong trường bào bị lõm nứt nhưng tự phục hồi nguyên trạng dưới thanh quang, cứu mạng Hàn Lập. Nữ tử kinh ngạc tăng sát ý, quyết tổn hao nguyên khí rút Thanh Đồng Đăng — Cổ Bảo hình đèn đồng xanh cổ xưa ngả đen. Hàn Lập cảm thấy nguy hiểm, không chần chừ thu toàn bộ bảo vật, ôm cự điêu hóa băng dùng Phong Lôi Sí lao vào sương mù dày đặc. Nữ tử sợ mất pháp bảo cự điêu liền cầm cổ đăng đuổi theo, bị dẫn dụ tới nơi xa lạ. Hàn Lập dừng lại ở một nơi khác, dùng kim quang phá vỡ băng điêu, phá hủy pháp bảo biến hình của nữ tử."},{"chuong":741,"tieuDe":"Phá Trận Đại Chiến (6)","tomTat":"Tuyết điêu của nữ tử áo lục bị Hàn Lập phá hủy nhưng linh quang tự hội tụ tái sinh, tuy nhiên khí sắc uể oải suy yếu rõ rệt, chứng tỏ không phải bất tử. Hàn Lập bày trận kỳ hóa vụ giao cùng trận bàn phóng quang ti xanh hồng bao vây, đồng thời triển khai Kinh Long chung phóng sóng âm bạc xuyên thấu phòng ngự Bạch Liên. Nữ tử dùng Bạch Liên co rút cánh hoa phòng thủ chặt rồi bung cánh phá tan trận pháp bên ngoài. Nữ tử tháo đăng hoa từ đồng đăng Cổ Bảo thổi nhẹ, bao bọc Kinh Long chung trong quang cầu xanh, ma diễm bốc cháy hòa tan ngân chung hoàn toàn khiến Hàn Lập mất một Cổ Bảo quan trọng. Hàn Lập kích hoạt Phong Lôi Sí rút lui, Ngân Nguyệt đã mai phục dưới đất từ trước bất ngờ xuất hiện kích hoạt Tử Vân Đấu tử võng mười trượng bao vây nữ tử kèm Ngọc Dương Chân Hỏa thanh bạch nhị sắc tấn công. Hàn Lập hợp nhất 72 thanh Thanh Trúc Phong Vân Kiếm thành cự kiếm phủ điện hình cung và Kiềm Lam Băng Diễm lao tấn công. Nữ tử tức giận cực kỳ, cầm đăng hoa đánh xuống đỉnh đầu phản kích, chương kết ở cliffhanger."},{"chuong":742,"tieuDe":"Phá Trận Đại Chiến (7)","tomTat":"Nữ tử họ Nhạc dùng đăng hoa từ đồng đăng bảo vật hấp thu toàn bộ Ngọc Dương Chân Hỏa rồi hợp nhất ba đóa đăng diễm thành đầu lâu hỏa cầu, nuốt trọn cự kiếm Thanh Trúc Phong Vân Kiếm cùng Ích Tà Thần Lôi và Kiền Lam Băng Diễm. Hàn Lập cảm ứng đau đớn qua bổn mạng pháp bảo nhưng kinh ngạc phát hiện phi kiếm mộc thuộc tính không bị đăng diễm hóa tro dù bị bao lâu. Ngân Nguyệt phun phấn hồng sắc hương vụ huyễn hóa tuấn nam mỹ nữ quấy rối nữ tử họ Nhạc, tạo cơ hội cho Hàn Lập thu hồi kiếm. Hàn Lập hợp nhất hàn quang, lam diễm và thanh khí tạo tử sắc hỏa diễm đối kháng ngang ngửa đăng diễm Cổ Bảo, khiến nữ tử trợn mắt. Chương tiết lộ đồng đăng là một trong hai đại truyền thừa chi bảo Mộ Lan tộc, nữ tử họ Nhạc là đệ nhất nữ pháp sĩ kiêm tam đại thần sư. Nữ tử quyết dùng hết số lần đồng đăng để diệt Hàn Lập, nhưng đúng lúc đó nhân ảnh bí ẩn từ hải vụ xông ra, Tử Vân Đấu hóa tử vân tách đôi và bạch quang cuốn đồng đăng bắn đi."},{"chuong":743,"tieuDe":"Phá Trận Đại Chiến (8)","tomTat":"Ngân Nguyệt vừa đoạt được Hoa Lam Cổ Bảo và nhốt Thanh Đồng cổ đăng thì Trọng Thần Sư — một trong tam đại Thần Sư Mộ Lan tộc, tu vi Nguyên Anh Hậu Kỳ — xuất hiện. Hắn phóng ngân mang áp đảo Ngân Nguyệt, cướp lại Tử Thành Đâu cùng Hoa Lam Cổ Bảo, đánh nàng thương nặng rồi đặt thiết cấm chế. Lão giả họ Mã mất một cánh tay, cảnh báo Hàn Lập rằng Lục đạo hữu đã bị giết. Đúng lúc ngân sắc cự thủ sắp đập nát Ngân Nguyệt, Hàn Lập thi triển Lôi Độn Thuật ôm nàng biến mất. Trọng Thần Sư trả lại Cổ Bảo và Thanh Đồng cổ đăng (còn gọi là Mộ Lan nguyên minh đăng, truyền thừa chi bảo) cho Nhạc thượng sư, rồi phân thân thành ba truy đuổi Hàn Lập. Sau bốn ngày bốn đêm bỏ chạy, Ích Tà Thần Lôi gần cạn kiệt, Hàn Lập nhận ra thần thức bản thân thua Nguyên Anh Hậu Kỳ vì Đại Diễn Quyết chưa học hết, quyết tâm sau trận chiến sẽ tới cực tây lấy mấy tầng khẩu quyết cuối cùng."},{"chuong":744,"tieuDe":"Thanh Danh Tiệm Khởi","tomTat":"Hàn Lập bàn kế với Ngân Nguyệt rồi liên tiếp thi triển Huyết Ảnh Độn ba lần kết hợp Lôi Độn Thuật, tổn hao tinh huyết cực lớn để vượt phạm vi thần thức hơn hai trăm dặm của Trọng thần sư. Trọng thần sư hợp nhất ba thân truy đuổi nhưng không thể khóa được Hàn Lập, đánh giá xác suất đuổi kịp rất nhỏ lại lo bị tu sĩ Nguyên Anh Hậu Kỳ Thiên Nam vây công nên từ bỏ quay đầu. Hàn Lập sắc mặt tái nhợt, nguyên khí hư tổn nặng, quyết định không quay về Điền Thiên Thành vì đã kết oán Quỷ Linh Môn, đồng thời lo ngại Thanh Trúc Phong Vân Kiếm bị dính nhiễm thanh sắc đăng diễm từ đồng đăng bảo vật truyền thừa Mộ Lan, dùng Tử La Thiên Hỏa áp chế nhưng chưa trừ hết. Ngân Nguyệt an ủi rồi dùng Thổ Độn Thuật đưa Hàn Lập vào lòng núi hoang bế quan. Nửa năm sau Hàn Lập vẫn chưa xuất quan, bên ngoài đại chiến tu sĩ và pháp sĩ sắp bùng phát, cái tên Lạc Vân Tông Hàn trưởng lão đã trở thành đại danh đỉnh đỉnh khắp Thiên Nam và đại quân pháp sĩ, ai cũng coi hắn là thực lực cấp Nguyên Anh Trung Kỳ."},{"chuong":745,"tieuDe":"Hồi Quy","tomTat":"Sau trận Hoàng Long Sơn, tam Đại Thần Sư dẫn đại quân pháp sĩ chiếm Điền Thiên Thành trong hơn nửa tháng dù Ngụy Vô Nhai (tam đại tu sĩ Thiên Nam) trợ giúp duy trì cấm chế đại trận hơn một tháng. Chủ lực Cửu Quốc Minh rút về Bắc Lương Quốc an toàn. Viện quân chính ma lưỡng đạo cùng Thiên Đạo Minh kịp tới, tứ đại thế lực liên thủ xây thạch thành Thiên Nhất tại biên giới Bắc Lương Quốc và Ngu Quốc chỉ trong một đêm làm cứ điểm đối kháng, hai bên tạm đình chiến. Danh tiếng Hàn Lập vang khắp Thiên Nam sau khi nho sinh (Thần Sư) đánh giá thần thông hắn hơn tu sĩ Nguyên Anh trung kỳ phổ thông một bậc. Hàn Lập xuất quan sau hơn nửa năm bế quan khôi phục nguyên khí, cùng Ngân Nguyệt bắt gặp đội tuần tra Mộ Lan do Phụng Thác dẫn đầu, dùng Kinh Long Chung đánh bất tỉnh cả đội rồi phối hợp Mộng Dẫn thuật và Mê hồn huyễn thuật tra hỏi tù binh, nắm tình hình biên giới. Hàn Lập thiêu hủy tù binh rồi bao Ngân Nguyệt trong hà quang vượt biên giới. Tại thạch thành Thiên Nhất, Lữ Lạc nhàn đàm với tu sĩ Thiên Đạo Minh nhưng tâm thần bất an, lo lắng cho Hàn Lập mất tích và khó tin thần thông nghịch thiên của hắn."},{"chuong":746,"tieuDe":"Nghĩa Muội","tomTat":"Lữ Lạc tiếp đãi các trưởng lão Thiên Đạo Minh tại đại sảnh, trong đó Từ Trường Cảnh (Thủy Ảnh Tông) hỏi thăm tin tức Hàn Lập và kinh ngạc khi biết hắn mới kết Nguyên Anh mà thoát khỏi tay Mộ Lan thần sư. Trưởng lão mi dài Loan Minh Môn — tông phái mạnh nhất Thiên Đạo Minh — ngầm ghen tức, dội nước lạnh bằng cách gợi ý Hàn Lập bị thương nặng. Lữ Lạc nhận truyền tin hồng quang báo Hàn Lập đã vào thành và vội vã đến cứ địa Lạc Vân Tông gặp hắn. Hàn Lập giải thích mình bị tổn thương nguyên khí nên phải tĩnh dưỡng hơn nửa năm. Lữ Lạc tiết lộ: Yểm Nguyệt Tông tuyên bố Nam Cung Uyển tẩu hỏa nhập ma vẫn lạc, hôn ước với Ngụy Ly Thần đã giải trừ, Trình sư huynh nhận nàng làm nghĩa muội và dự tính gả cho Hàn Lập sau khi đánh lùi Mộ Lan. Hàn Lập im lặng hồi lâu rồi thở dài nhận ân tình hai sư huynh, khiến Lữ Lạc mừng rỡ vì mục đích gắn kết Hàn Lập với Lạc Vân Tông, ngăn Hoàng Phong Cốc chiêu dụ, đã thành công. Đổng Huyên Nhi đã được đệ tử hộ tống rời khỏi thành vì sắp xảy ra đại chiến."},{"chuong":747,"tieuDe":"Điều Kiện","tomTat":"Lữ Lạc truyền đạt yêu cầu của cao tầng liên minh chánh ma lưỡng đạo: Hàn Lập phải tiếp tục tham chiến trong đại chiến sắp tới thay vì chỉ ra tay một lần, vì công pháp của hắn khắc chế được tu sĩ hắc bào Mộ Lan. Hàn Lập đồng ý và yêu cầu gặp trực tiếp chủ sự Thiên Đạo Minh để đàm phán. Trên đường đi, Lữ Lạc giới thiệu cơ cấu Thiên Đạo Minh — trưởng lão hội mười người, ba phái khởi xướng (Loan Minh Tông, Cổ Kiếm Môn, Nghê Hàng Trai) không thay đổi, Loan Minh Tông thực lực cao nhất. Chủ sự tại Thiên Nhất thành là Long Hàm (Nguyên Anh trung kỳ đỉnh phong) và đạo lữ Phượng Băng (đang bế quan tu luyện bí thuật), phu phụ song tu liên thủ có thể địch Nguyên Anh hậu kỳ. Tại đại điện nghị sự, Hàn Lập gặp Long Hàm, tu sĩ họ Huống (Nghê Hàng Trai, nổi danh với Kiền Thổ Công) và trưởng lão họ Điền (Cổ Kiếm Môn). Long Hàm chủ động xin lỗi và đề nghị bồi thường. Hàn Lập đưa ra điều kiện: mượn lực lượng liên minh thu gom một loại tài liệu luyện khí trọng yếu, cực kỳ khó tìm, nói rằng nếu có trước đại chiến sẽ tăng khả năng đối phó tu sĩ hắc bào."},{"chuong":748,"tieuDe":"Ý Ngoại Chi Ước","tomTat":"Hàn Lập nêu điều kiện gia nhập Thiên Đạo Minh: liên minh giúp thu thập Canh Tinh — loại Duệ kim chi bảo cực hiếm — để luyện chế Đại Canh kiếm trận. Lâm Hiên phân tích Canh Tinh rất khó kiếm số lượng lớn, Lữ Lạc khuyên đổi điều kiện nhưng Hàn Lập kiên quyết giữ. Long Hàm cuối cùng đồng ý phái đệ tử tận lực tìm kiếm, nhóm còn tặng thêm hơn trăm linh thạch bậc trung bồi thường. Hàn Lập kể sơ lược trận chiến Hoàng Long sơn và nêu nghi ngờ tu sĩ hắc bào tu luyện ma công chứ không phải di loại. Hắn bắt đầu suy tính nếu Thiên Nam không đủ Canh Tinh thì phải đi Đại Tấn quốc hoặc Thiên Sa đại lục, nhớ lại lời hứa giao hộp xương chứa phương pháp Hàng Linh phù cho Thiên Phù môn. Sau khi Lữ Lạc vội vàng đi vì nhận Truyền Âm phù, Hàn Lập gặp nữ tử họ Tống đang chờ trong ngõ nhỏ để chuyển ngọc giản thư của Mai Ngưng. Hai người bay đến sơn cốc phía Nam Thiên Nhất thành, Hàn Lập tái ngộ Mai Ngưng — nàng tu vi đạt Trúc Cơ đỉnh phong, thần sắc u oán khi gặp lại, chúc mừng hắn đạt Nguyên Anh kỳ, còn Hàn Lập lộ vẻ xấu hổ."},{"chuong":749,"tieuDe":"Linh Chúc Quả Và Tạo Hóa Đan","tomTat":"Hàn Lập đến nơi hẹn gặp Mai Ngưng và Tử Linh, được Mai Ngưng cung kính đón tiếp và cảm ơn ân tặng đan dược trước đây. Tử Linh xuất hiện sau khi thu công, xưng hô thân mật và dò hỏi thực lực Hàn Lập có thể so Nguyên Anh trung kỳ không. Hàn Lập từ chối trả lời trước khi biết mục đích, thầm so sánh nhan sắc Tử Linh với Nam Cung Uyển — nhận định Tử Linh nhỉnh hơn về tư sắc nhưng Nam Cung Uyển là người không thể thay thế. Ba nữ tu tiết lộ đã dùng huyễn thuật khai thác bí mật từ đệ tử Quỷ Linh Môn: trong Trụy Ma Cốc bị phong bế từ thời man hoang có Linh Chúc quả — chủ dược luyện Tạo Hóa đan, loại đan dược giúp tu sĩ dưới Hóa Thần kỳ đột phá bình cảnh. Mai Ngưng kích động vì có thể tăng xác suất Kết Đan. Hàn Lập sau khi cân nhắc đặt điều kiện phải giải đáp hết thắc mắc mới chịu hợp tác, tuyên bố sẽ không mạo hiểm tính mạng."},{"chuong":750,"tieuDe":"Định Nghị","tomTat":"Hàn Lập chất vấn lý do Tử Linh tìm mình hợp tác thay vì Nam Lũng Hầu, được giải thích Nam Lũng Hầu tính cách không đáng tin. Tử Linh tiết lộ Quỷ Linh Môn đang nghiên cứu phương pháp nhập Trụy Ma Cốc riêng, dự định hỗn nhập theo khi cốc ổn định. Hàn Lập sơ bộ đồng ý tham gia vì Tạo Hóa đan nhưng giấu kín việc mình cũng biết phương pháp nhập cốc qua Nam Lũng Hầu. Tử Linh tiết lộ hạn chế quan trọng: Linh Chúc quả hái xong nửa ngày phải luyện đan, Tạo Hóa đan luyện xong phải phục dụng trong thời hạn, buộc cả ba nữ tử đích thân nhập cốc. Nữ tử họ Tống lấy ra ngọc giản cổ thư bí truyền Tống gia chứa phương thuốc thượng cổ, Hàn Lập dùng bình đan dược xanh biếc đổi lấy. Hàn Lập nhận định đại chiến với Mộ Lan xác suất năm năm, lo ngại nhất là tu sĩ hắc bào có thế lực bên ngoài nhúng tay. Khi chia tay, Mai Ngưng muốn nói gì đó nhưng do dự im lặng, Hàn Lập nhìn nàng rung động rồi nhanh chóng bay về Thiên Nhất thành."},{"chuong":751,"tieuDe":"Hóa Diễm","tomTat":"Trên đường bay về Thiên Nhất Thành, Hàn Lập phân tích cho nữ tử họ Tống về sự nguy hiểm của Trụy Ma Cốc — đa phần tu sĩ chết vì lòng tham, cần phương pháp nhập cốc và lộ tuyến an toàn mới có thể sống sót. Hàn Lập nhận định phương pháp nhập cốc của Quỷ Linh Môn có thể không ổn và hé lộ quá khứ Tử Linh: từng bị tu sĩ cường đại uy hiếp, môn phái mẫu thân bị thế lực khác chiếm nên tâm chí truy cầu cường đại, sẽ bất chấp nguy hiểm vào cốc. Hàn Lập tiết lộ bản thân cũng muốn vào cốc lấy Linh Chúc quả để đột phá Nguyên Anh Sơ Kỳ, nhưng ưu tiên sống sót qua đại chiến trước. Sau khi về thành, Lữ Lạc dẫn Hàn Lập gặp hơn mười tu sĩ Nguyên Anh kỳ giao hảo với Lạc Vân Tông. Hàn Lập vào mật thất xử lý thanh sắc đăng diễm bám trên Thanh Trúc Phong Vân Kiếm từ trận Hoàng Long Sơn — dùng Tử La Cực Hỏa dồn ép thanh diễm xuống mũi kiếm nhỏ bằng hạt đậu nhưng nó bất tử bất diệt tự khôi phục, cuối cùng quyết định bọc tử diễm lên tay trần bóp chặt thanh diễm."},{"chuong":752,"tieuDe":"Lôi Châu","tomTat":"Hàn Lập thử dùng Tử La Cực Hỏa luyện hóa thanh sắc đăng diễm bám trên Thanh Trúc Phong Vân Kiếm nhưng chỉ áp chế được mà không luyện hóa nổi. Ích Tà Thần Lôi kim ti cũng bị thanh diễm hấp nạp sạch. Hắn nghĩ ra kế thu Tử La Cực Hỏa, liên tục phóng Thanh Nguyên kiếm khí cho thanh diễm hấp thu quá tải đến bão hòa, thành công giải phóng phi kiếm trở lại sạch sẽ, thanh diễm hóa thành hỏa cầu xanh chói mắt. Tuy nhiên hắn chỉ điều khiển được hỏa cầu lệch lạc hơn một trượng vì thiếu công pháp tương ứng. Hắn tra Huyền Âm Kinh tìm thấy phương pháp Âm Hỏa Lôi có uy lực trên cả Thiên Đô Thi Hỏa, quyết định cải biến phương pháp dùng thanh diễm thay âm hỏa kết hợp Ích Tà Thần Lôi bắt đầu luyện chế Lôi châu biến thể. Tại thính đường Lạc Vân Tông, Lữ Lạc cùng mấy tu sĩ Kết Đan kỳ lo lắng Hàn Lập bế quan hơn hai tháng trong khi tam đại tu sĩ đã tề tụ Thiên Nhất Thành phát thiếp mời dự hội nghị chỉ dành cho Nguyên Anh trung kỳ trở lên vào ngày mai. Đúng lúc đang bàn bạc, tiếng nói Hàn Lập từ bên ngoài vang tới, Lữ Lạc vui mừng."},{"chuong":753,"tieuDe":"Vân Lộ Lão Ma","tomTat":"Hàn Lập kết thúc hai tháng bế quan, đã khu trừ sạch thanh diễm trên Thanh Trúc Phong Vân Kiếm và dùng Ích Tà Thần Lôi luyện chế thanh diễm thành bảy tám viên lôi châu. Gặp Lữ Lạc tại đại sảnh, được thông báo tam đại tu sĩ Nguyên Anh hậu kỳ sẽ đích thân chủ trì cao tầng tụ hội ngày mai, chỉ tu sĩ Nguyên Anh trung kỳ trở lên mới được dự. Lữ Lạc cho biết Mộ Lan pháp sĩ đã bắt đầu đánh mạnh vào đại trận biên giới ba bốn ngày trước, Lạc Vân Tông đã xuất hơn phân nửa thực lực. Sáng hôm sau Hàn Lập đến thạch điện trung tâm Thiên Nhất Thành, trước cửa gặp Vân Lộ lão ma — lão quái họ Cổ của Hợp Hoan Tông, trời sinh âm dương đồng thể, ngoại hình tuấn mỹ nhưng khí tức quỷ dị — dẫn theo Đổng Huyên Nhi mặc đồ đỏ hồng, tu vi đã đạt Kết Đan trung kỳ. Vân Lộ lão ma chú ý đánh giá Hàn Lập rồi nhoẻn cười vũ mị, khiến Hàn Lập bất an vội vào điện. Sau khi Hàn Lập đi, Vân Lộ lão ma phát hiện Đổng Huyên Nhi nhịp tim bất thường và truy vấn nàng có biết người đó không."},{"chuong":754,"tieuDe":"Lão Quái Tề Tụ","tomTat":"Vân Lộ lão ma nhận ra Hàn Lập là người quen cũ mà Đổng Huyên Nhi từng nhắc, giữa chân mày hiện tia âm độc. Đổng Huyên Nhi không đủ tu vi Nguyên Anh nên không được vào đại điện tụ hội, được đưa đi nghỉ ngơi chỗ khác. Hàn Lập vào đại điện, ngồi cạnh Long Hàm — trưởng lão Loan Minh Tông kiêm chủ sự Thiên Đạo Minh. Long Hàm chỉ điểm cho Hàn Lập về Toái Hồn Chân Nhân (Cửu Hồn bí công đạt chí cao), Thiên Hận Lão Quái (tồn tại ngay sau tam đại tu sĩ, từng trọng thương Chí Dương), và Đông Môn Đồ — đại trưởng lão Ngự Linh Tông bất mãn với Hàn Lập vì vụ tiêu diệt Cốc Song Bồ. Hàn Lập nhớ mình từng đánh chết môn hạ Toái Hồn tại Việt Quốc nhưng không đề cập, suy đoán quan hệ Đổng Huyên Nhi với Vân Lộ lão ma không đơn thuần sư đồ. Cuối cùng tam đại tu sĩ Nguyên Anh Hậu Kỳ — hắc bào đại hán, lục phát lão giả, đạo sĩ giắt trường kiếm — bước ra từ cửa bên, toàn bộ lão quái trong điện chờ họ lên tiếng."},{"chuong":755,"tieuDe":"Sinh Tử Đổ Chiến","tomTat":"Ba vị Đại trưởng lão — Hợp Hoan lão ma (Hợp Hoan Tông), Chí Dương thượng nhân (Thái Chân môn, Chính Đạo minh), Ngụy Vô Nhai (Cửu Quốc Minh) — bước ra chủ trì hội nghị tại đại điện. Hợp Hoan lão ma phóng linh áp trấn áp toàn trường, Hàn Lập nhận ra ma khí âm hàn của hắn giống Quỷ Linh Môn hơn là Hợp Hoan Tông. Mộ Lan nhân đã phái sứ giả đưa Khiêu chiến thư, đòi nhường một nửa Thiên Nam, nếu không thì bảy ngày sau quyết tử chiến tại biên giới, kèm đề xuất đổ chiến sinh tử. Các tu sĩ tranh cãi chiến lược: lão giả họ Lỗ (Thiên Huyễn Tông) chủ trương cầm cự, đại hán ngăm đen phản bác, Hợp Hoan lão ma quát dẹp. Chí Dương thượng nhân phân tích khí thế pháp sĩ đại quân quá mạnh, kéo dài chiến tranh bất khả thi, buộc phải tập trung hơn nửa lực lượng Thiên Nam. Nội dung đổ chiến: mười trường chiến đấu sinh tử tiến hành đồng thời trong không gian phong bế, trừ Nguyên Anh hậu kỳ ai cũng tham gia, thua là chết tại chỗ, thắng lấy Túi Trữ Vật đối phương. Tu sĩ họ Huống (Nghê Hàng Trai) đề xuất không chấp nhận nhưng Chí Dương thượng nhân khẳng định buộc phải tham gia và phải thắng."},{"chuong":756,"tieuDe":"Lợi Dụ","tomTat":"Chí Dương thượng nhân chủ trì hội nghị, thông báo Mộ Lan bắt hơn một ngàn tù binh tu sĩ và đề xuất 10 ván đổ chiến tử chiến, mỗi ván kèm 100 tù binh — chỉ bên thắng mới được thả người. Long Hàm thở dài thừa nhận dù biết là bẫy vẫn phải nhảy vào vì sĩ khí. Tam đại tu sĩ lần lượt truyền âm dụ dỗ từng người bằng tài liệu trân quý; Toái Hồn Chân Nhân là người đầu tiên đồng ý, sau đó Vân Lộ lão ma cũng đáp ứng, tổng cộng năm người chấp thuận. Chí Dương thượng nhân riêng truyền âm cho Hàn Lập đề nghị lượng lớn Canh Tinh, Hàn Lập xác nhận đang tìm nhưng yêu cầu xem số lượng trước. Hàn Lập suy tính: uy lực Thanh Trúc Phong Vân Kiếm chưa đủ mạnh khi dùng đơn lẻ, coi Đại Canh Kiếm Trận là đại thần thông cốt lõi tương lai, hoài nghi Hư Thiên Đỉnh, tự tin có Phong Lôi Sí và Tử La Cực Hỏa đủ thoát thân. Hội nghị kết thúc, Hàn Lập, Vân Lộ lão ma và một phụ nhân xinh đẹp sắc mặt tái nhợt bị giữ lại."},{"chuong":757,"tieuDe":"Canh Tinh","tomTat":"Hắc bào đại hán gọi Vân Lộ lão ma đi riêng nói chuyện bí mật, Vân Lộ lão ma tỏ ra kính sợ. Chí Dương thượng nhân trịnh trọng chiêu mộ Bạch phu nhân và Hàn Lập tham gia đổ chiến chống pháp sĩ Mộ Lan. Bạch phu nhân tuyên bố không quan tâm đại chiến, chỉ đến vì vật phẩm, lộ mâu thuẫn cũ với Chí Dương. Chí Dương trao đôi Thanh Vương tằm cực phẩm cho Bạch phu nhân, bà kiểm tra hài lòng rồi đồng ý đổ chiến. Chí Dương đưa ba khối Canh Tinh cho Hàn Lập, Ngụy Vô Nhai bổ sung thêm một khối lớn bằng nắm tay. Hàn Lập tính toán đủ luyện 36 thanh phi kiếm phối hợp Kiếm Ảnh Phân Quang Thuật bày Đại Canh Kiếm Trận loại nhỏ, chính thức đồng ý tham gia đổ chiến. Hàn Lập đổi Canh Tinh bằng lân phiến Độc Giao cấp tám (cho Ngụy Vô Nhai) và xác quy yêu cấp tám (cho Chí Dương), khiến cả hai kinh ngạc vì tu sĩ Nguyên Anh Sơ Kỳ sở hữu tài liệu yêu thú quý hiếm."},{"chuong":758,"tieuDe":"Huyền Thiên Tiên Đằng","tomTat":"Ngụy Vô Nhai xác nhận lân phiến Độc Giao mà Hàn Lập đưa ra, vui mừng vì pháp bảo của lão có hi vọng tăng tầng, chủ động giao khối Canh Tinh cuối cùng (vốn định lưu cho hậu nhân) cho Hàn Lập, đủ nguyên liệu luyện chế 36 thanh phi kiếm. Chí Dương thượng nhân giám định xong quy xác rất vừa ý nhưng không còn Canh Tinh, nên tặng Hàn Lập một phần tư rễ cây Huyền Thiên Tiên Đằng — linh căn thượng cổ từ thời hỗn độn, khai hoa kết quả có thần thông nghịch thiên nhưng đã chết héo, chính ma lưỡng đạo đều cứu không được nên chia nhỏ. Hàn Lập nảy ý tưởng dùng lục dịch tiểu bình thần bí thử cứu sống Huyền Thiên Tiên Đằng. Hắn xác nhận tham gia đổ chiến bảy ngày sau rồi cáo từ rời nghị điện. Khi Hàn Lập bước tới cửa, Ngụy Vô Nhai truyền âm nói nể mặt vụ lân phiến mà không truy cứu việc Hàn Lập cướp Nam Cung Uyển, đồng thời xóa bỏ hôn sự giữa điệt nhi Ngụy gia và Nam Cung tiên tử. Hai lão quái sau đó bàn luận, nghi Hàn Lập đã kế thừa y bát tu sĩ thượng cổ qua cổ Truyền Tống Trận, nhưng khẳng định không có ý sát nhân đoạt bảo vì thần thông Hàn Lập mạnh, thuộc phe Thiên Đạo Minh và phu phụ Long Hàm không dễ chọc."},{"chuong":759,"tieuDe":"Linh Phù Và Giao Hồn","tomTat":"Hàn Lập rời đại điện sau thương thảo, bất ngờ gặp Đổng Huyên Nhi đứng ngoài cửa lộ vẻ cổ quái pha ganh ghét nhìn theo hắn mà không nói gì. Ngân Nguyệt từ trong đầu trêu chọc hỏi về nữ tu sĩ kia, Hàn Lập phủ nhận mọi tình cảm, quan hệ hai bên đã thân cận hơn kể từ khi Hàn Lập cứu nàng và không truy hỏi việc mất Tử Vân Đấu, Hoa Lam Cổ Bảo. Về căn cứ Lạc Vân Tông, Hàn Lập báo cáo Lữ Lạc nội dung thương thảo, trấn an sư huynh rằng mình nắm tám chín phần thắng trong đổ chiến, giao ngọc giản nhờ đệ tử thu thập tài liệu phụ trợ luyện chế Hàng Linh Phù. Hàn Lập quyết định Hàng Linh Phù là sát chiêu duy nhất khả thi trong mấy ngày ngắn ngủi, dù lo xác suất thành công thấp vì thiếu bút chế linh phù vừa ý. Hai ngày sau nhận đủ tài liệu, hắn vào mật thất lấy giao hồn Độc Giao ra, dùng Minh Thanh Linh Nhãn quan sát thấy hồn lực vẫn cường đại nhưng linh thức ba phần si ngốc, thần trí thoái hóa, cảm khái về sự hung hiểm của tu tiên. Hắn tiến hành luyện chế tấm da linh thú qua nhiều giai đoạn anh hỏa phức tạp, cuối cùng tấm da thu nhỏ bằng lòng bàn tay màu đỏ máu, giao hồn bị hấp dẫn nhập vào tấm da thú, hoàn thành bước đầu chế tạo Hàng Linh Phù."},{"chuong":760,"tieuDe":"Đại Chiến Tướng Chí","tomTat":"Hàn Lập luyện chế Hàng Linh Phù lần đầu bằng cách cho giao hồn nhập da linh thú rồi dùng linh phù bút cùng nhiều loại linh dịch vẽ phù văn, sử dụng Minh Thanh Linh Nhãn mức cao nhất. Luyện chế thất bại, da linh thú phát nổ nhưng Bạch lân thuẫn chặn dễ dàng. Giao hồn thoát ra định trốn bị bắt lại, Hàn Lập phát hiện hồn lực chỉ suy yếu chứ không biến mất, có thể thử luyện lại nhiều lần. Trong khi đó, toàn bộ Thiên Nhất Thành được tổng động viên, tu sĩ các tông phái rời thành tiến về biên giới chuẩn bị quyết chiến với đại quân pháp sĩ Mộ Lan, danh tính mười vị Nguyên Anh kỳ tham chiến được giữ bí mật. Lữ Lạc theo Lạc Vân Tông rời thành, phân phó nữ tử họ Tống ở lại chờ Hàn Lập xuất quan. Đến ngày thứ năm Hàn Lập ra khỏi mật thất, triệu Ngự Phong Xa cùng nữ tử họ Tống bay về phía biên giới. Hắn được biết Tử Linh và Mai Ngưng đã tạm rời Thiên Nhất Thành chờ đại chiến kết thúc, khen Tử Linh cơ trí."},{"chuong":761,"tieuDe":"Tiêu Sư Diệt Khải","tomTat":"Tại biên giới Ngu Quốc – Bắc Lương Quốc, tu sĩ Thiên Nam và pháp sĩ Mộ Lan liên tục tập kết trong sáu ngày, thiết lập cấm chế phòng thủ gần hoàn chỉnh, bầu không khí sát phạt ngưng trọng chờ đại chiến. Hàn Lập cùng nữ tử họ Tống ngồi Ngự Phong Xa bay tới đại doanh, gặp lại Tiêu Thúy Nhi (nay Kết Đan sơ kỳ) đang dẫn đội tuần tra. Hai người ôn chuyện cũ, Tiêu Thúy Nhi kể Mã sư huynh đã tọa hóa, nàng cơ duyên kết Kim Đan, Hoàng Phong Cốc tình cảnh khó khăn vì không có tu sĩ Nguyên Anh kế thừa. Hàn Lập dứt khoát từ chối trở về Hoàng Phong Cốc, tiết lộ đã có giao dịch với Lệnh Hồ lão tổ và hứa tương trợ khi cần. Vì tình nghĩa với Mã sư huynh, Hàn Lập tặng Tiêu Thúy Nhi nhẫn xanh (pháp bảo) và lọ đan dược tinh tiến tu vi. Sau đó Hàn Lập thu hồi Ngự Phong Xa, cùng nữ tử họ Tống vào đại doanh qua nghiệm chứng thân phận, chia tay nàng rồi đến gặp chủ sự Chí Dương Thượng Nhân nghe an bài đại chiến, cuối cùng nghỉ ngơi dưỡng sức trong phòng đá."},{"chuong":762,"tieuDe":"Địch Mưu Khải","tomTat":"Hàn Lập tĩnh tọa hồi phục linh lực, nhận ra Thanh Nguyên Kiếm Quyết tầng mười trở lên giúp hồi phục nhanh hơn đáng kể. Hắn kiểm tra tấm Hàng Linh Phù vừa luyện thành sau ba lần thất bại, uy lực thấp hơn dự kiến do giao hồn cấp tám mất nửa hồn lực. Tại thạch thất ngầm cách đại doanh Thiên Nam hơn mười dặm, bảy nhân vật cốt cán phe Mộ Lan – Âm La Tông họp bàn kế hoạch đại chiến: Nhạc thượng sư xác nhận đủ dầu thánh cho thánh cầm, Trọng thần sư trình bày đại trận linh thuật cải tiến trăm năm, Tất huynh được phân công cho pháp sĩ cao cấp triệu hồi Hư linh thú tấn công trước. Phòng tông chủ Âm La Tông tiết lộ tham chiến vì trấn tông chi bảo Quỷ La Phiên bị chính đạo phá hủy cần đại lượng sinh hồn chữa trị. Hai bên tranh chấp gay gắt về quyền thu sinh hồn, Chúc thần sư dàn xếp thỏa hiệp cho Âm La Tông lấy nhưng phải lén lút. Nữ tử Âm La Tông đề xuất xử lý tu sĩ phóng kim hồ (Hàn Lập), Chúc thần sư nhận ra Kim Lôi Trúc là tam đại thần mộc liên quan Ích Tà Thần Lôi, đặt điều kiện Âm La Tông thả thêm đồng giáp thi binh đổi lấy Mộ Lan bắt sống Hàn Lập."},{"chuong":763,"tieuDe":"Ám Thủ Khải","tomTat":"Phe hắc bào nam tử (Phòng tông chủ, khô gầy lão giả, nho sinh) quyết định chuyển mục tiêu từ bắt sống sang diệt sát Hàn Lập vì hắn tinh thông lôi độn và huyết độn thuật không thể cản, nhằm cướp Kim Lôi Trúc. Tại đại sảnh phe tu sĩ, Chí Dương thượng nhân chủ trì cuộc họp bàn kế hoạch đại chiến: dụ chủ lực pháp sĩ Mộ Lan ra biên giới, trong khi Thiên Hận Lão Quái dẫn tán tu lẻn vào Điền Thiên Thành phá kho tài nguyên linh thạch bí mật. Ngụy Vô Nhai cung cấp Truyền Tống Trận và tiết lộ nội gián là một Đại Thượng Sư trong kho sẽ giải cấm chế. Đổi lại, Thiên Hận Lão Quái được hứa Tư quốc để khai tông lập phái, tứ đại thế lực cam đoan. Hợp Hoan lão ma thuyết minh chuẩn bị của Ma Đạo Lục Tông gồm trấn tông tam thú, âm dương song ma giải cấm và vạn hồn đại trận, Chánh Đạo Minh lấy ra mười mấy thượng cổ kỳ bảo, Loan Minh Tông xuất thượng cổ Ngọc phù. Chí Dương phân tích Hắc bào nhân có thể là Đại Tấn quốc Ma Tông và đề cập Phá Cấm Châu để đối phó, Long Hàm hoài nghi ích lợi pháp khí cấp thấp này."},{"chuong":764,"tieuDe":"Cuộc Chiến Biên Giới (1)","tomTat":"Trước đại chiến biên giới, Chí Dương thượng nhân tiết lộ Phá Cấm Châu chính thức khác bản bán thành phẩm thất lạc, bổn môn đã chuẩn bị mười viên cho người tham chiến. Hợp Hoan lão ma bổ sung bí chế đan dược của Thiên Sát Tông có thể kích thích chân nguyên khôi phục pháp lực nhưng đại giá tổn thương nguyên khí. Long Hàm nêu lo ngại về đám Hắc bào nhân tu ma đạo, Chí Dương nhận để Chánh Đạo Minh đối phó. Hàn Lập quan sát hai phe: tu sĩ Cửu Quốc pháp khí cao cấp nhưng đội hình hỗn loạn, phe pháp sĩ Mộ Lan đội ngũ chỉnh tề và sở hữu mười mấy đầu cự thú khổng lồ. Hàn Lập kiểm tra Phá Cấm Châu và đan dược được phát, quan sát bảo vật bí mật các tông môn gồm hai cỗ quan tài đen trắng Hợp Hoan Tông có cấm chế thần thức không xuyên thấu, đồng la khổng lồ kim quang chói mắt và mười mấy pho tượng thượng cổ dị thú. Hai đại quân dàn trận đối diện, Mộ Lan tam đại thần sư và ba Nguyên Anh tu sĩ bay ra đối thoại. Trung niên nho sinh đề nghị chia nửa Thiên Nam để đình chiến, Ngụy Vô Nhai thản nhiên đáp rằng pháp sĩ nếu thua sẽ là diệt tộc."},{"chuong":765,"tieuDe":"Cuộc Chiến Biên Giới (2)","tomTat":"Phe Mộ Lan và Thiên Nam đàm phán về việc thả tù binh trước trận đánh cuộc. Khô gầy lão giả đề xuất nhượng bộ thả trước một nửa trong hơn ngàn tù binh, Chí Dương thượng nhân truyền âm với hai lão quái rồi quyết đoán đồng ý. Phe Thiên Nam cử trăm tu sĩ kiểm tra kỹ tù binh, xác nhận không có gian tế hay thủ đoạn. Ải Tử tiếc nuối vì không kịp dùng Thất Tâm đan cho tù binh trước đó. Tu sĩ và pháp sĩ hai phe hợp lực bố trí mười tòa tiểu hình pháp trận phiếm bạch quang, mỗi tòa 70-80 trượng, do Kết Đan Kỳ tu sĩ và pháp sĩ giám sát. Hàn Lập giấu mình tránh sự chú ý, chủ động đề xuất để Tống nữ tử giám sát pháp trận. Phe Mộ Lan phái mười hắc bào ma tu, phe Thiên Nam phái mười Nguyên Anh lão quái gồm Hàn Lập, Toái Hồn Chân Nhân, Vân Lộ lão ma, Bạch phụ nhân. Hàn Lập nhận xét ma tu đối thủ đều là Nguyên Anh Sơ Kỳ đỉnh phong, không có Trung Kỳ, cảm thấy bất thường. Hai bên trao đổi Túi Trữ Vật cá cược rồi bước vào pháp trận, Hàn Lập chuẩn bị sẵn Ích Tà Thần Lôi trong đan điền, quyết tâm diệt ma tu."},{"chuong":766,"tieuDe":"Cuộc Chiến Biên Giới (3)","tomTat":"Hắc bào nhân đối đầu Hàn Lập trong lồng hào quang đột ngột tự bạo thân thể, huyết nhục bắn lên vách quang tráo hóa huyết vụ nhuộm đỏ toàn bộ lồng thành huyết tráo. Hàn Lập dùng Cấm chế châu, mười đạo kiếm khí, kim hồ Thần Lôi đều không phá nổi, huyết vụ tán rồi lập tức khôi phục. Tình hình tương tự xảy ra ở hơn mười chỗ — toàn bộ mười Nguyên Anh tu sĩ Thiên Nam tham gia đổ chiến đều bị vây trong huyết tráo. Phòng tông chủ lộ diện tiết lộ Huyết La Quang Tráo là một trong sáu đại bí thuật tông phái, cần hy sinh mười huyết thi trăm năm cùng ma linh đan và phân thức khống chế. Tam đại tu sĩ Chí Dương thượng nhân, Ngụy Vô Nhai, Hợp Hoan lão ma bất lực trước huyết tráo, nhận ra nó chỉ vây khốn không thương tổn. Hợp Hoan lão ma lớn tiếng khiêu chiến Mộ Lan thần sư, pháp sĩ Mộ Lan đánh trống trận chuẩn bị tổng tiến công."},{"chuong":767,"tieuDe":"Cuộc Chiến Biên Giới (4)","tomTat":"Sáu đại tu sĩ cấp Nguyên Anh của hai phe bay lên cao giao chiến — phe Mộ Lan cử Phòng tông chủ (Thiên Sát Chân Ma Công đạt cảnh giới cực cao) đối đầu Hợp Hoan lão ma, cùng Nho sinh họ Trọng và gã lùn họ Tất; phe Thiên Nam cử Chí Dương thượng nhân cùng hai người khác. Bầu trời biến sắc, lôi bàn bạo liệt vang lên. Ở mặt đất, Long Hàm chỉ huy tu sĩ Thiên Nam ra lệnh công kích trước bằng dị bảo viễn trình (đồng la phát kim vụ, giao long kỳ phun hắc phong, cổ kính phun Hỏa Điểu, hồ lô tạo mưa tuyết) rồi phát động đợt hai bằng bí thuật liên thủ, áp chế pháp sĩ. Lão giả khô gầy buộc phải yêu cầu Lục phu nhân cho phép sử dụng cự thú phi giáp — mười mấy hoang dã cự thú da dày tự lành vết thương xông ra buộc tu sĩ phân tán hỏa lực. Cao giai pháp sĩ nhân cơ hội tung đạn hoàn biến hóa yêu thú tái tạo không ngừng gây thêm áp lực. Long Hàm nhận thấy không thể tái áp chế, ra lệnh rút dị bảo về và hơn ngàn tu sĩ lập ngũ sắc quang mạc phòng hộ thêm một tầng. Non nửa số pháp sĩ thi triển Linh thuật pháp trận bắn hàng trăm hỏa cầu và hơn ngàn băng thương bao trùm bầu trời phe tu sĩ, cự thú và yêu thú đã vượt quá nửa khoảng cách xông sát trận tuyến."},{"chuong":768,"tieuDe":"Cuộc Chiến Biên Giới (5)","tomTat":"Tu sĩ Cửu Quốc triển khai ngũ sắc thái mạc chuyên khắc chế linh thuật cấm chế, chặn đứng đợt công kích đầu tiên của pháp sĩ Mộ Lan, Long Hàm vui mừng xác nhận lời Ngụy Vô Nhai. Chỉ huy pháp sĩ ra lệnh đợt hai với hỏa nha và băng mãng mạnh hơn. Đội tu sĩ áo lục Ngự Linh Tông thả hơn mười linh thú tinh nhuệ nghênh chiến cự thú pháp sĩ, phe linh thú hơi chiếm thượng phong. Mấy ngàn tu sĩ chia năm đội xung phong, bảy lão giả Loan Minh Tông tế bảy đạo thượng cổ ngọc phù hóa bảy mặt trời bạch sắc bạo liệt thành bảy điện võng khổng lồ trùm xuống đại quân pháp sĩ, khiến chỉ huy hoảng sợ. Hai bên chính thức giao chiến trực tiếp. Trong khi đó Hàn Lập bị nhốt trong huyết quang tráo vẫn bình tĩnh, cố ý không ra sớm để tránh loạn chiến ban đầu. Hắn thử phá cấm chế bằng thần thức, Minh thanh linh nhãn, phi kiếm và Thiên Trọng Phong nhưng đều thất bại, phát hiện Ích Tà Thần Lôi cũng vô hiệu dù cấm chế mang tính ma đạo. Hàn Lập quyết định thử tiếp Kiền Lam Băng Diễm và Tử La Thiên Hỏa."},{"chuong":769,"tieuDe":"Cuộc Chiến Biên Giới (6)","tomTat":"Hàn Lập bị vây trong huyết quang tráo, lần lượt thử Kiền Lam Băng Diễm, kiếm khí, Tử La Thiên Hỏa phối hợp kim hồ nhưng đều không phá nổi — huyết tráo có khả năng tự chữa trị, đủ sức vây khốn nguyên anh tu sĩ bình thường. Cuối cùng Hàn Lập lấy ra viên lôi châu thanh sắc mới luyện chế, uy lực vượt dự đoán, phá thủng vách tráo tạo thông đạo, hóa thanh hồng thoát ra ngoài. Qua đó xác nhận Tử La Thiên Hỏa thuộc băng hàn không tương khắc huyết tráo, còn lôi châu luyện từ đăng diễm hỏa thuộc tính mới khắc chế. Vừa ra khỏi tráo, Hàn Lập bị hơn mười pháp sĩ Mộ Lan vây quanh, dùng Thanh Trúc Phong Vân Kiếm phân thành hơn trăm đạo kiếm quang tiêu diệt toàn bộ, gồm hai Kết Đan pháp sĩ bỏ chạy cũng bị kiếm quang liên kết tăng tốc truy sát, nguyên thần tan rã. Đại Thượng Sư Mộ Lan (người mặc hoàng sam) bay đến trong cơn cuồng nộ vì thân truyền đệ tử bị giết, nhận ra danh tiếng Hàn Lập, ném pháp bảo hình khối tứ phương hóa cự chuyên hơn mười trượng tấn công. Hàn Lập dùng Phong Lôi Sí biến mất rồi xuất hiện sau lưng đối phương. Trận chiến chưa phân thắng bại."},{"chuong":770,"tieuDe":"Cuộc Chiến Biên Giới (7)","tomTat":"Hàn Lập phối hợp cùng Ngân Nguyệt đối chiến Hoàng sam lão giả — Mộ Lan Đại Thượng Sư Nguyên Anh kỳ. Hàn Lập dùng Bạch lân thuẫn, Lôi Độn Thuật và Kiềm Lam Băng Diễm tấn công, Ngân Nguyệt nhờ thần thông ẩn nặc Tứ Đồng Linh Hồ vừa đột phá thêm một tầng mà lén tiếp cận tập kích từ sau, phá tử vân hộ thể Cổ Bảo, hủy nhục thân lão giả. Lão giả quyết đoán tự hủy nhục thân và bổn mạng pháp bảo cho Nguyên Anh thoát bằng thuấn di thuật. Hàn Lập nhận ra Mộ Lan đã nắm rõ Phong Lôi Sí và Kiềm Lam Băng Diễm, lợi thế bất ngờ không còn. Quan sát toàn cảnh chiến trường hỗn loạn với nhiều hình thái giao chiến. Hàn Lập bay tới phá huyết quang tráo bằng lôi châu, giải cứu Toái Hồn Chân Nhân, nhờ Toái Hồn chặn hai Đại Thượng Sư Mộ Lan rồi tiếp tục tới tráo kế tiếp. Tại tráo thứ ba, một cẩm bào đại hán bí ẩn xuất hiện vô thanh vô tức, Hàn Lập quét thần thức xong trợn mắt há hốc mồm — chương kết thúc bằng cliffhanger."},{"chuong":771,"tieuDe":"Cuộc Chiến Biên Giới (8)","tomTat":"Hàn Lập dùng thần thức phát hiện cẩm bào đại hán chính là Điền Chung — đệ tứ thần sư Mộ Lan, tu vi Nguyên Anh Hậu Kỳ mới đột phá, trước đó tình báo chỉ ghi nhận ba đại thần sư. Hai bên giao chiến, lôi châu bị bàn tay pháp lực xanh chế trụ, Hàn Lập dẫn bạo triệt tiêu lẫn nhau. Phượng Băng — phu nhân Long Hàm — bất ngờ xuất hiện trợ chiến, dùng Hỏa Linh Bình phun liệt hỏa hóa cự xà đỏ sậm đối đầu bản thể Điền Chung, bảo Hàn Lập đi cứu người. Điền Chung thi triển Thân Ngoại Hóa Thân tách phân thân màu xanh chặn Hàn Lập, đồng thời thả hai con Thiên Hổ Thú Kết Đan Hậu Kỳ có năng lực thuấn di kẹp hai sườn. Hàn Lập thả Phệ Kim Trùng hóa kim vụ tấn công nhưng bị phân thân phun quang cầu mộc linh khí giam lại. Hé lộ phe pháp sĩ cao tầng đã bàn bạc từ trước, giao nhiệm vụ giết Hàn Lập cho Điền Chung kèm pháp bảo và linh thú khắc chế. Cuối chương, Long Hàm lao vào giao chiến trực tiếp với pháp sĩ khô gầy, bảy vị Nguyên Anh Kỳ lão giả tóc bạc bay theo hỗ trợ, nữ tử họ Nhạc nhận lệnh lấy ra Cổ đăng bằng đồng xanh chuẩn bị tham chiến."},{"chuong":772,"tieuDe":"Thái Chân Thất Tu Sĩ Và Thánh Cầm","tomTat":"Nhạc thượng sư thi triển nghi thức triệu hồi, dùng cổ đăng cổ xưa, tiên huyết và viên châu phấn hồng triệu hồi thành công phân thân Mộ Lan Thánh cầm — con khổng tước xanh cảnh giới ngoài Hóa Thần. Thánh cầm biến thành Hỏa Điểu khổng lồ, hấp thu toàn bộ địa hỏa linh khí trong mười dặm, khiến công pháp hỏa thuộc tính giảm uy lực một nửa. Lục phu nhân phân tích Thánh cầm là phân thân, linh lực thực tế chỉ tầm Nguyên Anh Sơ Kỳ tăng tới Hậu Kỳ sau hấp thu. Bảy lão giả Thiên Nam buộc phải tế xuất bộ Thái Chân Thất Bảo, thi triển Khốn ma đại trận vây khốn Thánh cầm, nhưng vẫn ở thế hạ phong — băng võng bị thiêu, lệnh bài suýt bị đánh nát. Nhạc thượng sư ở lại bảo vệ cổ đăng, không tham chiến, vì đèn tắt thì Thánh cầm biến mất. Long Hàm ra lệnh thả hơn mười con Phê Linh Tượng Thú phản công. Chúc thần sư thúc giục Lục phu nhân thả đồng giáp thi giáng đòn trí mạng, nhưng Lục phu nhân bình tĩnh từ chối, nói đại bộ phận đồng giáp thi tu vi chỉ tương đương Trúc Cơ Kỳ, cần chờ đối phương tiêu hao thêm."},{"chuong":773,"tieuDe":"Hàng Linh Chi Uy","tomTat":"Hàn Lập bị hai con Thiên Hổ Thú và thanh ảnh thuần mộc linh khí cầm chân, mọi thủ đoạn như Thanh Trúc Phong Vân Kiếm, Kiền Lam Băng Diễm, Ngân Chung, Thiên Trọng Phong đều vô hiệu trước thanh ảnh. Nhận ra tình thế bất lợi toàn cục khi Phượng Băng hoàn toàn hạ phong trước Điền Chung và bảy tu sĩ Nguyên Anh Kỳ bị thánh cầm thần thông trấn áp, Hàn Lập quyết định sử dụng Hàng Linh Phù. Hấp thu giao hồn Độc Giao bát cấp, Hàn Lập biến thành nửa giao nửa người với sừng giao, lân phiến huyết sắc và tiêm giáp, tu vi tăng lên đỉnh Nguyên Anh Sơ Kỳ. Giao độc hộ thể khắc chế hoàn toàn linh ti của thanh ảnh, Hàn Lập nhờ đó lần lượt diệt cả hai con Thiên Hổ Thú, chộp yêu đan. Điền Chung thấy hai yêu thú bị diệt, vừa giận vừa sợ, bỏ Phượng Băng hoá kinh hồng bay thẳng về phía Hàn Lập. Đúng lúc đó một huyết tráo gần đó bạo liệt vỡ ra, một đạo ngân hồng phóng ra đứng gần Hàn Lập, danh tính chưa rõ."},{"chuong":774,"tieuDe":"Âm Dương Ma Thi","tomTat":"Bạch sam phụ nhân phá Huyết La tráo bước ra, phối hợp với Phượng Băng hợp công Điền Chung (đệ tứ thần sư Mộ Lan) bằng hàn khí và hỏa diễm, chưa phân thắng bại. Hàn Lập dùng Lôi Dực bay tới huyết tráo khác định ném lôi châu cứu người nhưng bị hoả cầu xanh từ thánh cầm Mộ Lan nuốt mất lôi châu, biến thành hoả điểu bao vây. Hắn nhận ra lôi châu luyện từ đăng diễm nên cùng nguồn gốc với hoả điểu, hoàn toàn vô hiệu. Ngân Nguyệt hiện thân nhận hai lôi châu cuối, đi tìm phá huyết tráo ở nơi không có hoả điểu. Hàn Lập dùng quang thuẫn lam và linh hồng quang trướng bảo hộ, lao vào vùng hoả điểu tấn công. Nhận thấy tình thế bất lợi, Long Hàm quyết định dùng con bài cuối cùng: ra lệnh thả Âm Dương Song Ma với ưu tiên phá cửu trản cổ đăng. 32 đệ tử Hợp Hoan Tông giải phong ấn hai quan tài đen-trắng, Song Ma phá quan tài xông ra cắn yết hầu hai đệ tử hút máu. Phi phát lão giả dùng đồng bài xanh lục kiểm soát Song Ma, ra lệnh tấn công Khổng Tước."},{"chuong":775,"tieuDe":"Cự Viên Xuất Hiện","tomTat":"Âm Dương Song Ma hóa lục phong phóng tới tấn công cự điểu xanh Hóa Thần Kỳ, dùng pháp thuật ẩn nặc tiếp cận nhưng bị phát hiện, chuyển hướng phá nát chín chim lửa của cửu trản cổ đăng rồi bị cự điểu cuốn vào biển lửa. Thái Chân Thất tu sĩ dùng bảy loại cổ bảo liên hợp nhưng vẫn bị cự điểu ép tới đường cùng. Hắc bào nữ tử phun tiểu phiên đen gọi mây đen che trời, triệu hồi hàng ngàn đồng giáp thi từ Tấn quốc Ma Tông khiến Long Hàm nhận định Thiên Nam chắc chắn bại. Một con cự viên cổ quái cao hơn hai mươi trượng bất ngờ xuất hiện, dùng mũi hít sạch thi khí rồi phun ánh sáng vàng quét sạch hàng trăm luyện thi hóa tro bụi, đảo ngược cục diện. Hắc bào nữ tử hoảng sợ lao tới tấn công cự viên bằng cự nhận tử quang nhưng bị Hàn Lập xuất hiện trên vai cự viên chặn đứng bằng lam quang thuẫn, hiện điện hồ kim sắc quanh thân chuẩn bị chiến đấu."},{"chuong":776,"tieuDe":"Lạt Thủ Vô Tình","tomTat":"Hàn Lập dùng Thanh Minh Linh Nhãn nhìn thấu phân thân ảo ảnh của hắc bào nữ tử, phun kim hồ đánh trúng vai rồi dùng Phong Lôi Sí xuất hiện sau lưng đóng băng lam diễm hủy nhục thân, kích nổ kim võng Ích Tà Thần Lôi tiêu diệt. Nguyên anh nữ tử hiện ra cầu tha mạng, xưng là bạn lữ Âm La Tông tông chủ Tấn quốc ma đạo, nhưng Hàn Lập giả vờ thả rồi bất ngờ siết kim võng diệt sát vì không thể để về báo thù. Vân Lộ lão ma dùng đám mây phấn hồng chặn Chúc thần sư không cho cứu viện, tuyên bố đã trả ơn Hàn Lập, từ nay không nợ nhau. Đề Hồn Thú được thả ra từ Linh Thú Túi, hóa thành hắc sắc cự viên thôn hấp thi khí đám đồng giáp luyện thi Âm La Tông cực nhanh, lộ năng lực mới ngoài ý liệu. Long Hàm dẫn nhóm tu sĩ tinh nhuệ đến viện binh, nhận thấy hình dáng Hàn Lập có chút yêu hóa nhưng không hỏi, phái tu sĩ thay thế để Phượng Băng cùng nữ tu họ Bạch hợp chiến đoàn vợ chồng liên thủ. Hai bên tung lực lượng dự bị cuối cùng, phía pháp sĩ có Chúc thần sư Nguyên Anh hậu kỳ, phía tu sĩ có Vân Lộ lão ma cùng Long Hàm và ba bốn Nguyên Anh trung kỳ liên thủ ứng phó. Hàn Lập định vây công lão giả khô gầy nhưng nhìn về phía thanh sắc cự cầm do Hắc bào nhân thao túng thì biến sắc nhiều lần."},{"chuong":777,"tieuDe":"Huyết Quỷ Và Thạch Nhân","tomTat":"Bảy trưởng lão Thái Chân môn liên thủ cùng Âm Dương song ma đối kháng Mộ Lan thánh cầm nhưng dần rơi vào hạ phong, linh lực tiêu hao nặng, hai vị gần kiệt sức. Nữ tử họ Nhạc canh giữ cửu trản cổ đăng, dùng cổ ngữ khẩn cầu thánh cầm hỗ trợ, cự điểu huyễn hóa mấy trăm Hỏa Điểu thanh sắc bay đi tương trợ đám lão giả phe Mộ Lan. Tại trung tâm chiến trường, Mộ Lan Đại Thượng Sư hợp lực ngưng tụ thạch nhân khổng lồ cao gần trăm trượng vây công tu sĩ Thiên Nam. Trưởng lão Quỷ Linh Môn quyết định dùng huyết tế triệu hồi Huyết Quỷ cao hơn mười trượng có năng lực tái sinh bất tử, đối kháng thạch nhân ngang ngửa. Cự điểu chia biển lửa thành hai khu vực cô lập song ma và Thái chân thất tu, tập trung hơn nửa thế công đánh bảy trưởng lão vào thế nguy. Hàn Lập giao Minh Hồn Châu cho Ngân Nguyệt canh giữ Đề Hồn Thú, sử dụng thần thông ẩn nặc tàng hình từ vô danh pháp quyết yêu tộc bí mật tiếp cận nữ tử họ Nhạc nhằm phá hủy cổ đăng. Tuy nhiên nữ tử họ Nhạc nhíu mày phát hiện, bắt đăng diễm từ cổ đăng ném ra hơn ba mươi trượng, thiêu hủy đối phương thành tro bụi trong nháy mắt."},{"chuong":778,"tieuDe":"Đoạt Đăng","tomTat":"Nữ tử họ Nhạc (đệ nhất nữ thượng sư Mộ Lan tộc) ngồi canh cửu trản cổ đăng, đã diệt nhiều tu sĩ Thiên Nam ẩn nặc bằng đăng diễm. Hàn Lập lập kế cho hơn mười Khôi Lỗi cự viên nghi binh và dùng một Khôi Lỗi giả dạng bản thân đánh lừa nữ tử thổi đăng diễm thiêu nhầm. Thừa lúc nữ tử phân tâm, Hàn Lập dùng Lôi Độn Thuật dịch chuyển tới sát cổ đăng, phóng bàn tay hắc hồng đoạt chủ đăng và dùng âm hỏa diệt đăng diễm, khiến tám trản còn lại đồng loạt tắt. Hàn Lập cất chủ đăng rồi rút lui, kích nổ lôi châu giấu trong Khôi Lỗi đánh bật nữ tử, thả tam sắc phi trùng ngăn cản truy đuổi, cuối cùng ẩn nặc thoát đi. Thanh điểu đang giao chiến bên kia mất nguồn linh lực từ cổ đăng, thu nhỏ rồi bạo liệt hóa thành linh quang biến mất. Biển lửa xanh tiêu tan, các tu sĩ Thái Chân Thất bị vây trước đó thoát nạn, nhận ra cổ bảo triệu hồi yêu cầm của Mộ Lan tộc đã bị đoạt."},{"chuong":779,"tieuDe":"Viễn Tín","tomTat":"Mộ Lan thánh cầm bất ngờ biến mất khỏi chiến trường khiến pháp sĩ thần sắc đại biến, hai thần sư không biết chi bảo đã rơi vào tay Hàn Lập. Đề Hồn Thú dạng cự viên tiêu diệt đồng giáp luyện thi cuối cùng, hấp thu thi khí tăng trưởng, được Hàn Lập thu vào túi linh thú. Âm La Tông tông chủ phát hiện phu nhân bị giết, giận dữ gầm thét truy tìm hung thủ, thề quất hồn luyện phách, dọa dùng chí bảo Quỷ La Phiên; Hợp Hoan lão ma đuổi theo ngăn cản, Hàn Lập thấp thỏm vì chính hắn là kẻ ra tay. Hoàng bào pháp sĩ tu vi Nguyên Anh Trung Kỳ dẫn hơn mười người bay đến mang tin cấp báo thảo nguyên có biến, lão giả khô gầy nhận ngọc giản xem xong mặt xanh mét, chủ động đề nghị Long Hàm ngưng chiến với lý do kẻ thứ ba quấy rối. Long Hàm thất thanh khi nghe truyền âm, phóng phù ngừng chiến, hai bên đồng loạt rút quân. Ngụy Vô Nhai, Chí Dương thượng nhân, Trọng Thần Sư và ải tử Mộ Lan đều bình an trở về từ không trung. Long Hàm triệu tập hội nghị phạm vi nhỏ gồm tu sĩ Nguyên Anh Trung Kỳ, Hàn Lập nhờ biểu hiện chiến đấu xuất sắc được tham dự."},{"chuong":780,"tieuDe":"Sau Đại Chiến","tomTat":"Long Hàm triệu tập hội nghị hậu chiến với hơn hai mươi tu sĩ đại biểu các thế lực Thiên Nam, tiết lộ Đột Ngột nhân đã liên hợp tông môn Tấn quốc tấn công hậu phương Mộ Lan, diệt sạch đệ nhất đại tộc Mộ Lan. Long Hàm ca ngợi công lao Hàn Lập phá đồng giáp luyện thi và Mộ Lan thánh cầm, đề xuất nhượng khu vực biên giới cho Mộ Lan cư trú làm tấm chắn. Ngụy Vô Nhai phản đối vì thiệt hại cho Cửu Quốc Minh nhưng cuối cùng đồng ý thương lượng. Thiên Hận lão quái trốn về Thiên Nhất Thành xác nhận tin tình báo, hai bên đạt hiệp nghị đình chiến. Sau đàm phán kịch liệt, Thiên Nam nhượng hai quốc gia biên giới cho Mộ Lan an trí, tam đại thế lực bồi thường Cửu Quốc Minh, đổi lại Mộ Lan toàn lực ngăn Đột Ngột nhân. Tông chủ Âm La Tông nhiều lần gửi khiêu chiến thư cho Hàn Lập vì bạn lữ bị giết, Hàn Lập hóa tro ngọc giản không đáp. Mộ Lan thần sư đòi lại Nguyên Minh Đăng, Hàn Lập đàm phán đổi lấy trân hi tài liệu rồi sảng khoái trả lại, nhận định giữ vật này chỉ mang họa."},{"chuong":781,"tieuDe":"Nam Cung Kinh Biến","tomTat":"Sau chiến dịch biên giới, Mộ Lan nhân chủ động hoàn trả Tử Thành Đâu và Hoa Lam Cổ Bảo cho Hàn Lập để giữ quan hệ tốt; Hàn Lập tặng Tử Thành Đâu cho Ngân Nguyệt làm thưởng công. Đột Ngột nhân phái đại lượng tu sĩ tới kề cận thảo nguyên nhưng chỉ yên lặng quan sát, Thiên Nam các tông phái thi hành phương án thay phiên đóng quân. Hàn Lập dùng Ngự Phong Xa trở về Lạc Vân Tông trước Lữ Lạc, bị Trình sư huynh chặn đưa vào mật thất. Tại đây hắn kinh hoàng phát hiện Nam Cung Uyển đã hóa thành nữ đồng khoảng tám tuổi bị phong ấn trong tường băng. Nửa tháng trước, Nam Cung Uyển đi lấy Thiên Âm Lộ tu luyện Luân Hồi Quyết thì bị hắc bào nam tử tập kích, phá tan hộ thân chi bảo rồi điểm Phong Hồn Chú lên trán — ma đạo cấm chế khiến ba hồn bảy phách dần tiêu tán. Nàng tỉnh lại rồi tự dùng Luân Hồi Quyết phong ấn bản thân bằng hàn khí trì hoãn phát tác. Hắc bào nam tử ném lại ngọc giản đỏ yêu cầu Hàn Lập mang Kim Lôi Trúc tới Huyền Thiên phong. Hàn Lập xem xong tức giận đốt tan, suy đoán hung thủ là Tấn quốc Âm La Tông ma tu nhắm đoạt Kim Lôi Trúc chuyên khắc chế ma công, tự trách đã liên lụy Uyển Nhi."},{"chuong":782,"tieuDe":"Mật Thất Luyện Kiếm","tomTat":"Hàn Lập nhận định kẻ hạ Phong Hồn Chú tám chín phần mười là tông chủ Âm La Tông, quyết tâm tự mình đối phó trong thời hạn hai tháng do ngọc giản để lại, từ chối để Lữ Lạc mời vợ chồng Long Hàm vì mất ba bốn tháng không kịp. Lữ Lạc đi tàng thư các tìm thượng cổ điển tịch về giải chú, đồng thời xác nhận Đại trưởng lão đã liệt mật thất chứa tường băng Nam Cung Uyển vào cấm địa. Mộ Phái Linh đến hỏi thăm, cho biết được Nam Cung Uyển chỉ điểm tu luyện; Liễu Ngọc cũng đến vấn an rồi sau đó châm chọc Mộ Phái Linh chuyện vẫn còn xử nữ dù mang danh thị thiếp. Hàn Lập ngồi suốt một ngày đêm bên tường băng suy nghĩ đối sách, sau đó bế quan luyện hóa Canh Tinh vào ba mươi sáu khẩu phi kiếm để hoàn thành Tiểu Canh Kiếm Trận — đòn sát thủ tối hậu có thể đấu ngang Nguyên Anh Hậu Kỳ tu sĩ. Canh Tinh đủ dùng nhờ ba nguồn: từ Chí Dương thượng nhân, từ Mộ Lan nhân, và Long Hàm nhờ thế lực Thiên Đạo Minh tìm tại Thiên Nhất Thành."},{"chuong":783,"tieuDe":"Kiếm Trận Sơ Thành","tomTat":"Hàn Lập hoàn thành luyện chế 36 thanh Thanh Trúc Phong Vân Kiếm trộn Canh Tinh, dùng tinh huyết kích hoạt Canh Tinh rồi luyện anh hỏa liên tục nhiều ngày nhờ vạn năm linh dịch hồi phục pháp lực. Phi kiếm biến thành xích kim sắc vĩnh viễn do tương tác Kim Lôi Trúc, Luyện tinh và Canh Tinh, uy lực tăng gần ba thành. Hàn Lập thử nghiệm Đại Canh Kiếm Trận trong mật thất, uy lực cực lớn khiến hắn tự tin tám chín thành vây khốn diệt sát Nguyên Anh Trung Kỳ, đủ tự bảo trước Nguyên Anh Hậu Kỳ. Xuất quan gặp lão giả tóc bạc, nhận ngọc giản Hắc bào nhân hẹn tại đỉnh Thiên Trụ Sơn, yêu cầu đến một mình mang theo Kim Lôi Trúc pháp bảo. Lão giả tóc bạc đã ước hẹn Hỏa Long Đồng Tử cùng năm sáu Nguyên Anh đồng đạo bí mật theo sau, đồng thời ngầm tính khi mình đại hạn tọa hóa thì Hàn Lập sẽ toàn lực duy trì Lạc Vân Tông. Hàn Lập bay đến Thiên Trụ Sơn, cách trăm dặm đã bị thần thức Hắc bào nhân dò xét, cảm giác ngang Nguyên Anh Trung Kỳ nhưng nghi giấu thực lực. Hắc bào nhân chờ sẵn trên đỉnh núi, xác nhận tình báo về quan hệ Hàn Lập và Nam Cung Uyển chính xác."},{"chuong":784,"tieuDe":"Hắc Bào Thanh Niên","tomTat":"Hắc bào thanh niên bí ẩn rời khỏi đỉnh Thiên Trụ Sơn qua Truyền Tống Trận sau khi để lại tin nhắn khắc đá dẫn dụ. Hàn Lập bay tới nơi, phát hiện trận và tin nhắn, cân nhắc giữa nguy hiểm và cơ hội tìm cách giải Phong hồn chú cho bạn lữ. Hắn gửi Truyền Âm Phù cho đồng bọn rồi trang bị phòng thủ tối đa — triệu Phệ Kim Trùng hóa chiến giáp, dùng Bạch lân thuẫn, lấy tấm lụa hộ thân Nam Cung Uyển tặng — mạo hiểm bước vào trận. Bị truyền tống đến vô danh tiểu đảo cách ngàn dặm, Hàn Lập đối mặt hắc bào thanh niên có tu vi cao tới mức không nhìn ra, xác nhận người này không phải Âm La Tông tông chủ mà tự xưng bất đồng với tông chủ, chỉ muốn đoạt Kim Lôi Trúc. Hai bên trao đổi đồ giả lừa nhau rồi phát hiện, dẫn đến đàm phán đổ vỡ. Hàn Lập tuyên bố sẽ sưu hồn đối phương, khiến thanh niên giận dữ kích hoạt cấm chế Thất long thung — bảy quang trụ hiện bảy giao long bạc. Ngân Nguyệt hoảng sợ cảnh báo chủ nhân mau tránh."},{"chuong":785,"tieuDe":"Kiếm Trận Sơ Triển","tomTat":"Hàn Lập triển khai ba tầng phòng ngự: Bạch Lân Thuẫn hóa thủy mạc, cẩm mạt Cổ Bảo hóa sương mù, cùng Tử Vân Đâu hỏa võng do Ngân Nguyệt tự ý tung ra. Hắc bào thanh niên phát động Thất long thung, bảy đạo ngân quang đánh thủng hỏa võng và sương mù, nhưng Ngân Nguyệt nhận ra đó chỉ là phỏng chế phẩm, phun Yêu Đan cho bạo liệt thấm vào thủy mạc Bạch Lân Thuẫn, phản xạ ngân quang hủy diệt toàn bộ Thất long thung. Hắc bào thanh niên nhận ra Ngân Nguyệt là hồ yêu cấp bảy hóa hình, nổi lòng tham muốn bắt làm thị thiếp. Trong lúc đối thoại, Hàn Lập âm thầm bố trí hoàn tất Đại Canh Kiếm Trận bằng 36 thanh Thanh Trúc Phong Vân Kiếm. Kiếm trận phát động, kiếm quang ẩn hình hóa kim ti vô hình chém đôi hắc phủ và cắt nát phi đao của đối phương. Hắc bào thanh niên sắc mặt xanh mét, lấy hơn mười viên huyết ti bạch sắc viên châu bắn ra bốn phương phản kích tuyệt vọng."},{"chuong":786,"tieuDe":"Quỷ La Phiên","tomTat":"Hắc bào thanh niên ném hơn mười viên Huyết Lôi Tử nhằm ô nhiễm phi kiếm Hàn Lập, nhưng Ích Tà Thần Lôi ẩn trong phi kiếm lần đầu tự động kích phát, triệt tiêu toàn bộ huyết vụ. Hắc bào thanh niên kinh hãi nhận ra phi kiếm là Kim Lôi Trúc, còn Hàn Lập tự đánh giá tu vi Nguyên Anh Sơ Kỳ chỉ thúc dục được một nửa kiếm trận, cần Nguyên Anh Trung Kỳ mới tối ưu. Hắc bào thanh niên phun huyết xuất ra Quỷ La Phiên — một trong các chủ phiên của mười hai lá cờ, trấn tông chi bảo Âm La Tông, lá cờ thiếu một góc. Phất phiên khiến trời đất tối sầm, phóng âm hồn ti tấn công nhưng bị kim ti kiếm trận cắt nát. Phát động uy lực tối đại, lá cờ cuồng trướng cao hai trượng, bề mặt hiện sinh hồn hàng vạn người cùng tinh hồn hàng trăm tu sĩ, triệu ra hàng trăm đầu lâu quỷ hỏa bốc lửa. Hàn Lập phẫn nộ trước cảnh tượng, lạnh lùng tuyên bố đối phương đáng chết. Trận chiến chưa ngã ngũ khi Hắc bào thanh niên bắt quyết phát động đầu lâu quỷ hỏa tấn công."},{"chuong":787,"tieuDe":"Thôn Ma Đạm Quỷ","tomTat":"Hàn Lập đối đầu hắc bào thanh niên Âm La Tông. Kim ti kiếm trận không hiệu quả với quỷ đầu từ Quỷ La phiên vì chúng là âm quỷ chi thân vô hình, nhưng Ích Tà Thần Lôi khắc chế được phần lớn, riêng chủ ma đầu ngưu giác miễn cưỡng chống lại. Hàn Lập thả Đề Hồn Thú, con thú biến lớn phun hoàng hà nuốt sạch toàn bộ ma đầu kể cả chủ ma đầu hóa ác quỷ hai trượng, lộ thần thông thôn phệ ma đạm quỷ khiến hắc bào thanh niên kinh hãi. Thanh niên tự chặt năm ngón tay hiến huyết tăng lực cho ma đầu nhưng vẫn bị nuốt hết, hắn hợp nhất với Quỷ La phiên hóa âm vụ thoát thân nhưng bị kim ti đánh tan, thân xác băm vạn đoạn. Nguyên anh thoát ra bị kim võng Ích Tà Thần Lôi bắt gọn. Thanh niên dọa tự bạo nguyên anh nếu Hàn Lập dùng sưu hồn thuật, đề nghị đổi phương pháp giải phong hồn chú để được tha. Hàn Lập tỏ vẻ cân nhắc nhưng tử võng bất ngờ co rút nguyên anh, đồng thời Ngân Nguyệt xuất hiện phía sau phun hồng sắc hương vụ và bắn ngân quang tấn công, phối hợp khống chế hoàn toàn đối phương."},{"chuong":788,"tieuDe":"Trên Đường Gặp Mặt","tomTat":"Nguyên anh hắc bào thanh niên bị Ngân Nguyệt dùng hương vụ phấn hồng làm mê thần thức rồi bắt sống, mất hoàn toàn thần thông không thể tự bạo. Hàn Lập thu hồi kim võng và Đại Canh Kiếm Trận, ra lệnh Ngân Nguyệt mang Nguyên anh vào rừng thi triển sưu hồn thuật tìm phương pháp giải phong hồn chú. Sáu tu sĩ Nguyên Anh Sơ Kỳ dẫn đầu bởi Trình đạo hữu cùng Hỏa Long Đồng Tử, lão giả họ Vưu (mang chí bảo Mê Tiên Chung), đại hán họ Tá và lão giả họ Trần bay tới cứu viện. Hàn Lập gặp đoàn, thông báo đã tiêu diệt ma tu và xác nhận đó là trưởng lão Âm La Tông chứ không phải tông chủ, ném lệnh bài đen làm chứng cứ. Mọi người chấn kinh trước việc Hàn Lập một mình diệt Nguyên Anh Trung Kỳ, đều muốn kết giao. Hàn Lập cùng Trình đạo hữu chia tay nhóm, trở về nghị sự đại điện Lạc Vân Tông tại Vân Mông Sơn. Trình đạo hữu nhận ra Hàn Lập trên đường có vẻ tâm sự miễn cưỡng, hỏi thẳng có tìm được cách giải phong hồn chú không — chương kết ở câu hỏi ngỏ này."},{"chuong":789,"tieuDe":"Chỗ Cực Tây","tomTat":"Hàn Lập báo cáo cho sư huynh Trác Như Đình rằng ma tu Âm La Tông trưởng lão chỉ biết hạ Phong Hồn Chú chứ không biết giải, pháp quyết giải trừ là bí thuật cấp tông chủ và đại trưởng lão Âm La Tông. Hàn Lập đã dùng sưu hồn thuật trích xuất được vài phương pháp mượn ngoại vật phá ấn nhưng đều cực hiếm, từ chối sự hỗ trợ của tông môn. Hắn đến mật thất thăm Nam Cung Uyển đông cứng trong băng bích, phát hiện nàng đã liều tu luyện Xá Nữ Thiên Nguyệt Quyết — công pháp tử rồi mới sinh trong Luân Hồi Công. Hàn Lập quyết định vào Trụy Ma Cốc lấy nội đan Thượng cổ hỏa thiềm thú để giải Phong Hồn Ấn với 50% khả năng, nếu thất bại sẽ đi Tấn quốc lấy giải chú từ Âm La Tông. Trước đó hắn sẽ đi Cực Tây đắc thủ hai tầng cuối Đại Diễn Quyết và tìm Thiên Trúc Giáo kiếm pháp luyện Khôi Lỗi cấp Kết Đan, chuyến đi ước mất cả năm do phải đi bộ qua đại sa mạc có cuồng phong quanh năm. Hàn Lập giao Huyền Thiên Tiên Đằng cho Ngân Nguyệt chăm sóc bằng lục dịch quán chú hàng ngày, đồng thời lên kế hoạch loại bỏ nguyên anh thứ hai của Mộc Linh Anh và dùng pháp quyết tế luyện ma thi xử lý Thi Tiêu ở Vân Mộng Sơn. Cuối chương Ngân Nguyệt gọi Hàn Lập lại, nói có việc canh cánh trong lòng đã lâu muốn hỏi."},{"chuong":790,"tieuDe":"Xâm Chiếm","tomTat":"Ngân Nguyệt hỏi Hàn Lập tại sao chưa bao giờ dùng nàng dưới hình thái khí linh ứng địch, Hàn Lập giải thích việc hóa khí linh tiêu hao tinh nguyên có thể khiến khí linh tiêu tán, trừ vạn bất đắc dĩ sẽ không làm vậy. Trong mật thất, Hàn Lập cho nguyên anh xuất khiếu kiểm tra, xác nhận nguyên anh đã chính thức ngưng cố sau mấy năm bồi luyện, đủ điều kiện tu luyện đệ nhị nguyên anh. Nguyên anh thi triển thuấn di thuật nhưng tiêu hao nguyên khí rất lớn. Hàn Lập lấy Mộc Linh Anh ra khỏi phong ấn, xác nhận cách hồn thuật từ Huyền Âm Kinh đã hoàn toàn phát huy hiệu lực suy yếu thần thức đến cùng cực. Nguyên anh cưỡng hành xâm chiếm xóa sạch linh thức cuối cùng của Mộc Linh Anh sau một ngày đêm đau đớn, rót thần thức vào rồi thu linh anh vào cơ thể bắt đầu đồng hóa tạo đệ nhị nguyên anh. Sau đó Hàn Lập luyện mười mấy cự đinh pháp khí biến ảo, mang đến thạch thất nơi Thi Tiêu nằm cùng kim phù ngọc hạp chuẩn bị thao tác tiếp theo."},{"chuong":791,"tieuDe":"Thiên Tuyệt Ma Thi","tomTat":"Hàn Lập đến thạch thất kiểm tra Thi Tiêu đang bị Ngân Liên quấn kín, triệu Đề Hồn Thú ra và phát hiện đồ án huyết sắc trên lưng nó rõ ràng hơn trước, có vẻ như đang sống lại sau hai lần thôn phệ. Hắn nghiên cứu ngọc giản luyện thi thuật thu từ thần thức hắc bào thanh niên Âm La Tông, phát hiện phương pháp đỉnh cao Thiên Tuyệt Ma Thi có thể giữ nguyên thần thông và tu vi nguyên bản, quyết định luyện Thi Tiêu làm nguyên liệu. Hàn Lập dùng đinh bạc và kim hồ ghim chặt thân xác Thi Tiêu, mở hộp ngọc ép nguyên thần thoát ra. Nguyên thần Thi Tiêu hiện hình nữ tử giống Ngân Nguyệt nhưng hung ác, phóng âm phong tấn công nhưng bất lực. Bất ngờ trong thân Thi Tiêu còn ẩn giấu phân thân nguyên thần, cả hai mặt quỷ đều bị Đề Hồn Thú nuốt sạch. Hàn Lập dùng Thanh Trúc Phong Vân Kiếm đã trộn Canh Tinh chặt Ngân Liên, cực kỳ khó cắt, chém lâu mới đứt. Thu Ngân Liên về tay, phát hiện bề mặt trơn bóng nhưng khắc vô số phù văn nhỏ bé khó nhìn, khiến hắn khiếp sợ."},{"chuong":792,"tieuDe":"Trước Lúc Đi Xa","tomTat":"Hàn Lập kiểm tra hai chiếc ngân liên, nhận định là cổ bảo hiếm không phải sản phẩm Thiên Nam, cất đi chờ nối lại thử uy lực. Hắn kiểm tra thân thể Thi Tiêu, phát hiện cực kỳ cường hãn nhưng thiếu một cánh tay, bèn dùng Phệ Kim Trùng tam sắc ngưng tụ thành cánh tay thay thế, rồi bố trí trận pháp luyện chế hơn hai tháng khiến nguyên khí hao tổn. Sau khi bế quan phục hồi một tháng, Hàn Lập xem Lục Dực Sương Công đã tiến hóa thêm bậc và đẻ 24 quả trứng, kiểm tra Phệ Kim Trùng vẫn tiến hóa chậm, nghe Ngân Nguyệt báo cáo Huyền Thiên Tiên Đằng chưa rõ sống chết dù đã dùng vạn năm linh dịch cứu chữa. Hàn Lập quyết định lên đường đi cực tây, dự tính ba năm đi về để kịp vào Trụy Ma Cốc. Mộ Phái Linh tu vi đã tới bình cảnh, xin đi theo và được chấp thuận. Ba người lên Ngự Phong Xa bay đi. Lạc Vân Tông loan tin Hàn Lập bế quan vì bị thương, ngân phát lão giả ứng đối các tông phái. Nhờ danh tiếng giết trưởng lão Nguyên Anh Trung Kỳ đỉnh cấp Âm La Tông, Hàn Lập được sánh vai Thiên Hận Lão Quái và Lạc Vân Tông trở thành đệ nhất môn phái Khê Quốc."}];
